payload.text:
こちらのアプリをパワーアップさせてください。

<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Computational Collation System for Multilingual Manuscript Analysis</title>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/d3/7.8.5/d3.min.js"></script>
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Noto+Sans+Coptic&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=EB+Garamond:wght@400;500;600&family=IBM+Plex+Mono:wght@400;500&display=swap');

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'EB Garamond', 'Times New Roman', serif;
            background: #fdfcfa;
            color: #2c3e50;
            min-height: 100vh;
            padding: 0;
            line-height: 1.8;
            font-size: 11pt;
        }


        .header-institutional {
            background: linear-gradient(135deg, #34495e 0%, #2c3e50 100%);
            border-bottom: 3px solid #c9302c;
            padding: 20px 40px;
            margin-bottom: 30px;
        }

        .institution {
            font-size: 10pt;
            color: #ecf0f1;
            text-transform: uppercase;
            letter-spacing: 1px;
            margin-bottom: 5px;
        }

        .department {
            font-size: 9pt;
            color: #bdc3c7;
            font-style: italic;
        }

        .container {
            max-width: 900px;
            margin: 0 auto;
            background: #ffffff;
            padding: 0 40px 40px 40px;
            box-shadow: 0 2px 10px rgba(52, 73, 94, 0.1);
        }
        a {
            color: yellowgreen;
        }

        h1 {
            color: #2c3e50;
            margin-bottom: 10px;
            font-size: 18pt;
            font-weight: 600;
            text-align: center;
            text-transform: uppercase;
            letter-spacing: 1px;
            line-height: 1.3;
        }

        .authors {
            text-align: center;
            font-size: 10pt;
            margin-bottom: 20px;
            font-style: italic;
            color: #7f8c8d;
        }

        .abstract {
            background: #f8f9fa;
            border: 1px solid #d6c5a0;
            border-left: 4px solid #8b7355;
            padding: 15px 20px;
            margin-bottom: 30px;
            font-size: 10pt;
            text-align: justify;
        }

        .abstract-label {
            font-weight: 600;
            margin-bottom: 5px;
            color: #8b7355;
        }

        .section-number {
            font-weight: 600;
            margin-right: 8px;
            color: #8b7355;
        }

        h2 {
            font-size: 12pt;
            font-weight: 600;
            margin-top: 30px;
            margin-bottom: 15px;
            text-transform: uppercase;
            border-bottom: 2px solid #8b7355;
            padding-bottom: 5px;
            color: #2c3e50;
        }

        h3 {
            font-size: 11pt;
            font-weight: 600;
            margin-top: 20px;
            margin-bottom: 10px;
            color: #34495e;
        }

        .methodology-note {
            font-size: 10pt;
            text-align: justify;
            margin-bottom: 20px;
            line-height: 1.6;
            color: #2c3e50;
        }

        .input-section {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 20px;
            margin-bottom: 25px;
        }

        .text-input-group {
            display: flex;
            flex-direction: column;
        }

        label {
            font-weight: 600;
            font-size: 10pt;
            margin-bottom: 5px;
            text-transform: uppercase;
            letter-spacing: 0.5px;
            color: #34495e;
        }

        textarea {
            width: 100%;
            height: 120px;
            padding: 8px;
            border: 1px solid #95a5a6;
            background: #fcfcfc;
            font-size: 10pt;
            font-family: 'IBM Plex Mono', 'Noto Sans Coptic', monospace;
            resize: vertical;
            line-height: 1.4;
            color: #2c3e50;
        }

        textarea:focus {
            outline: 2px solid #7f8c8d;
            outline-offset: 1px;
            background: #ffffff;
        }

        .parameter-table {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 20px;
            font-size: 10pt;
        }

        .parameter-table th {
            background: #ecf0f1;
            border: 1px solid #95a5a6;
            padding: 8px;
            text-align: left;
            font-weight: 600;
            text-transform: uppercase;
            font-size: 9pt;
            color: #34495e;
        }

        .parameter-table td {
            border: 1px solid #95a5a6;
            padding: 8px;
            background: #fafafa;
        }

        input[type="number"], select {
            width: 100%;
            padding: 4px 6px;
            border: 1px solid #95a5a6;
            background: #fcfcfc;
            font-size: 10pt;
            font-family: 'IBM Plex Mono', monospace;
            color: #2c3e50;
        }

        input[type="number"]:focus, select:focus {
            outline: 2px solid #7f8c8d;
            outline-offset: 1px;
            background: #ffffff;
        }

        .corpus-selection {
            margin-bottom: 20px;
        }

        .corpus-grid {
            display: grid;
            grid-template-columns: repeat(5, 1fr);
            gap: 8px;
        }

        .corpus-btn {
            background: #ffffff;
            color: #34495e;
            border: 1px solid #95a5a6;
            padding: 6px 8px;
            font-size: 9pt;
            cursor: pointer;
            transition: all 0.2s;
            font-family: 'EB Garamond', serif;
            text-align: center;
        }

        .corpus-btn:hover {
            background: #34495e;
            color: #ecf0f1;
            border-color: #34495e;
        }

        .execute-btn {
            background: #8b7355;
            color: #ffffff;
            border: 2px solid #8b7355;
            padding: 10px 30px;
            font-size: 11pt;
            font-weight: 600;
            cursor: pointer;
            text-transform: uppercase;
            letter-spacing: 1px;
            display: block;
            margin: 20px auto;
            font-family: 'EB Garamond', serif;
            transition: all 0.3s;
        }

        .execute-btn:hover {
            background: #6d5a45;
            border-color: #6d5a45;
            transform: translateY(-1px);
            box-shadow: 0 2px 8px rgba(139, 115, 85, 0.3);
        }

        .results-section {
            display: none;
            margin-top: 40px;
        }

        .results-section.active {
            display: block;
        }

        .stats-table {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 30px;
            font-size: 10pt;
        }

        .stats-table caption {
            font-weight: 600;
            text-align: left;
            margin-bottom: 10px;
            font-size: 11pt;
            color: #34495e;
        }

        .stats-table th, .stats-table td {
            border: 1px solid #95a5a6;
            padding: 10px;
            text-align: center;
        }

        .stats-table th {
            background: #34495e;
            font-weight: 600;
            text-transform: uppercase;
            font-size: 9pt;
            color: #ecf0f1;
        }

        .stats-table td {
            font-family: 'IBM Plex Mono', monospace;
            font-size: 11pt;
            background: #fafafa;
            color: #2c3e50;
        }

        .figure-container {
            margin: 30px 0;
            page-break-inside: avoid;
        }

        .figure-caption {
            font-size: 10pt;
            margin-bottom: 10px;
            font-weight: 600;
            color: #34495e;
        }

        .figure-content {
            border: 1px solid #95a5a6;
            padding: 15px;
            background: #f8f9fa;
        }

        #heatmap, #similarity-graph {
            width: 100%;
            height: 350px;
            background: #ffffff;
        }

        #parallel-viewer {
            background: #ffffff;
            padding: 15px;
        }

        .parallel-container {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 20px;
            margin-bottom: 20px;
        }

        .parallel-column h4 {
            font-size: 10pt;
            font-weight: 600;
            margin-bottom: 10px;
            text-transform: uppercase;
            border-bottom: 1px solid #8b7355;
            padding-bottom: 5px;
            color: #34495e;
        }

        .parallel-text {
            font-family: 'Noto Sans Coptic', 'EB Garamond', serif;
            font-size: 11pt;
            line-height: 1.8;
            color: #2c3e50;
            padding: 10px;
            background: #ffffff;
            border: 1px solid #bdc3c7;
            min-height: 150px;
            white-space: pre-wrap;
            word-wrap: break-word;
        }

        .morpheme {
            display: inline-block;
            padding: 0 2px;
            margin: 0 1px;
            transition: all 0.2s;
            cursor: pointer;
            position: relative;
            border-bottom: 1px solid transparent;
        }

        .morpheme:hover {
            background: #e8dcc0;
        }

        .morpheme.exact-match {
            background-color: #d4e6d4;
            border-bottom: 2px solid #27ae60;
        }

        .morpheme.high-sim {
            background-color: #dce7f1;
            border-bottom: 1px solid #3498db;
        }

        .morpheme.medium-sim {
            border-bottom: 1px dashed #7f8c8d;
        }

        .morpheme.low-sim {
            border-bottom: 1px dotted #95a5a6;
        }

        .morpheme.greek-text {
            font-style: italic;
            color: #8e44ad;
        }

        .morpheme-tooltip {
            position: absolute;
            bottom: 100%;
            left: 50%;
            transform: translateX(-50%);
            background: #34495e;
            color: #ecf0f1;
            padding: 3px 6px;
            font-size: 8pt;
            white-space: nowrap;
            display: none;
            z-index: 1000;
            margin-bottom: 2px;
            font-family: 'IBM Plex Mono', monospace;
            border-radius: 2px;
        }

        .morpheme:hover .morpheme-tooltip {
            display: block;
        }

        .legend-table {
            width: 100%;
            border-collapse: collapse;
            margin-top: 15px;
            font-size: 9pt;
        }

        .legend-table th {
            background: #34495e;
            border: 1px solid #95a5a6;
            padding: 5px;
            text-align: left;
            font-weight: 600;
            text-transform: uppercase;
            color: #ecf0f1;
        }

        .legend-table td {
            border: 1px solid #95a5a6;
            padding: 5px;
            background: #fafafa;
            color: #2c3e50;
        }

        .color-sample {
            display: inline-block;
            width: 30px;
            height: 12px;
            border: 1px solid #95a5a6;
            margin-right: 5px;
            vertical-align: middle;
        }

        .morpheme-stats-table {
            width: 100%;
            border-collapse: collapse;
            margin-top: 15px;
            font-size: 10pt;
        }

        .morpheme-stats-table th, .morpheme-stats-table td {
            border: 1px solid #95a5a6;
            padding: 8px;
            text-align: center;
        }

        .morpheme-stats-table th {
            background: #34495e;
            font-weight: 600;
            text-transform: uppercase;
            font-size: 9pt;
            color: #ecf0f1;
        }

        .morpheme-stats-table td {
            background: #fafafa;
            color: #2c3e50;
        }

        .matches-table {
            width: 100%;
            border-collapse: collapse;
            margin-top: 20px;
            font-size: 10pt;
        }

        .matches-table caption {
            font-weight: 600;
            text-align: left;
            margin-bottom: 10px;
            font-size: 11pt;
            color: #34495e;
        }

        .matches-table th {
            background: #34495e;
            border: 1px solid #95a5a6;
            padding: 8px;
            text-align: left;
            font-weight: 600;
            text-transform: uppercase;
            font-size: 9pt;
            color: #ecf0f1;
        }

        .matches-table td {
            border: 1px solid #95a5a6;
            padding: 8px;
            vertical-align: top;
            background: #fafafa;
            color: #2c3e50;
        }

        .match-text-cell {
            font-family: 'Noto Sans Coptic', 'IBM Plex Mono', monospace;
            font-size: 10pt;
            line-height: 1.4;
        }

        .footnotes {
            margin-top: 40px;
            padding-top: 20px;
            border-top: 1px solid #8b7355;
            font-size: 9pt;
            line-height: 1.4;
            color: #7f8c8d;
        }

        .footnote {
            margin-bottom: 8px;
            text-indent: -15px;
            padding-left: 15px;
        }

        .footnote-number {
            font-weight: 600;
            vertical-align: super;
            font-size: 8pt;
            color: #c9302c;
        }

        .references {
            margin-top: 30px;
            padding-top: 20px;
            border-top: 2px solid #8b7355;
        }

        .references h2 {
            font-size: 11pt;
            margin-bottom: 15px;
            color: #34495e;
        }

        .reference-entry {
            margin-bottom: 10px;
            text-indent: -20px;
            padding-left: 20px;
            font-size: 10pt;
            line-height: 1.4;
            color: #2c3e50;
        }

        @media print {
            body {
                font-size: 10pt;
            }

            .header-institutional {
                display: none;
            }

            .corpus-selection, .execute-btn {
                display: none;
            }

            .figure-container {
                page-break-inside: avoid;
            }
        }
    </style>
</head>
<body>
    <div class="header-institutional">
        <div class="institution">So Miyagawa Computational Linguistics, Digital Humanities, &amp; Egyptology Computing Laboratory at University of Tsukuba</div>
        <div class="department">Main homepage: <a href="https://somiyagawa.com/" target="_blank">https://somiyagawa.com/</a> / Contact: miyagawa.so.kb at u.tsukuba.ac.jp</div>
    </div>

    <div class="container">
        <h1>Intertextuality Collation Machine (ICoMa) </h1>
                <h3><center>Computational Methods for Detecting Text Reuse in Multilingual Manuscript Traditions</center></h3> 

        <div class="authors">Experimental Version | ISO/IEC 10646:2017 Compliant | Based on Smith-Waterman Algorithm Variants</div>

        <div class="abstract">
            <div class="abstract-label">ABSTRACT</div>
            This digital instrument implements computational algorithms for the detection and analysis of textual parallels across manuscript witnesses. The system supports Unicode blocks for Coptic (U+2C80–U+2CFF), Greek (U+0370–U+03FF, U+1F00–U+1FFF), and Latin scripts, employing n-gram analysis, Jaccard coefficients, and normalized edit distance metrics. Applications include stemmatic analysis, intertextuality studies, and dialectal variation mapping in ancient and medieval texts.
        </div>

        <h2><span class="section-number">1.</span>METHODOLOGY</h2>
        <div class="methodology-note">
            The collation algorithm employs sliding window techniques with configurable n-gram sizes (2 ≤ n ≤ 20) to identify textual correspondences. Similarity metrics are calculated using: (i) token-based overlap coefficients, (ii) character-level edit distances normalized by maximum string length, and (iii) hybrid approaches accounting for orthographic variation. The tokenization module implements language-specific morphological segmentation rules, preserving diacritical marks while normalizing for comparison purposes.<sup class="footnote-number">1</sup>
        </div>

        <h2><span class="section-number">2.</span>CORPUS SELECTION</h2>
        <div class="corpus-selection">
            <div class="corpus-grid">
                <button class="corpus-btn" onclick="loadCopticExample()">MS.Copt.27</button>
                <button class="corpus-btn" onclick="loadSahidicExample()">P.Sah.Gen.1</button>
                <button class="corpus-btn" onclick="loadBohairicExample()">Lit.Boh.3</button>
                <button class="corpus-btn" onclick="loadMixedExample()">Cod.Gr-Co.4</button>
                <button class="corpus-btn" onclick="loadEnglishExample()">Control.Lat</button>
            </div>
        </div>

        <h2><span class="section-number">3.</span>DATA INPUT</h2>
        <div class="input-section">
            <div class="text-input-group">
                <label>Witness α (Primary)</label>
                <textarea id="source-text" placeholder="Insert primary text witness...">ⲡϫⲟⲉⲓⲥ ⲡⲉ ⲡⲁⲟⲩⲟⲉⲓⲛ ⲁⲩⲱ ⲡⲁⲟⲩϫⲁⲓ ⲛϯⲛⲁⲣϩⲟⲧⲉ ⲁⲛ ⲛⲗⲁⲁⲩ. ⲡⲉⲧⲣⲟⲉⲓⲥ ⲉⲣⲟⲓ ⲛϥⲛⲁϯ ⲁⲛ ⲛⲗⲁⲁⲩ ⲛϩⲱⲃ ⲉⲧⲁϣⲉ ⲉⲣⲟⲓ.</textarea>
            </div>
            <div class="text-input-group">
                <label>Witness β (Comparandum)</label>
                <textarea id="target-text" placeholder="Insert comparandum text witness...">ⲡϫⲟⲉⲓⲥ ⲡⲉ ⲡⲁⲟⲩⲟⲉⲓⲛ ⲁⲩⲱ ⲡⲁⲛⲟⲩϩⲙ ⲛϯⲛⲁⲣϩⲟⲧⲉ ⲁⲛ ⲛⲛⲓⲙ. ⲡⲉⲧⲣⲟⲉⲓⲥ ⲉⲣⲟⲓ ⲛϥⲛⲁϯ ⲛⲗⲁⲁⲩ ⲛϩⲱⲃ.</textarea>
            </div>
        </div>

        <h2><span class="section-number">4.</span>ANALYSIS PARAMETERS</h2>
        <table class="parameter-table">
            <thead>
                <tr>
                    <th>Parameter</th>
                    <th>Value</th>
                    <th>Description</th>
                </tr>
            </thead>
            <tbody>
                <tr>
                    <td>N-gram Size (n)</td>
                    <td><input type="number" id="window-size" value="5" min="2" max="20"></td>
                    <td>Token window for sequence matching</td>
                </tr>
                <tr>
                    <td>Threshold (τ)</td>
                    <td><input type="number" id="threshold" value="60" min="0" max="100"></td>
                    <td>Minimum similarity coefficient (%)</td>
                </tr>
                <tr>
                    <td>Algorithm</td>
                    <td>
                        <select id="algorithm">
                            <option value="ngram">N-gram Overlap</option>
                            <option value="jaccard">Jaccard Coefficient</option>
                            <option value="levenshtein">Levenshtein Distance</option>
                            <option value="coptic-aware">Normalized Edit Distance</option>
                        </select>
                    </td>
                    <td>Similarity metric calculation</td>
                </tr>
                <tr>
                    <td>Script Mode</td>
                    <td>
                        <select id="script-mode">
                            <option value="auto">Automatic Detection</option>
                            <option value="coptic">Coptic Only</option>
                            <option value="mixed">Mixed Scripts</option>
                            <option value="latin">Latin Only</option>
                        </select>
                    </td>
                    <td>Character set processing mode</td>
                </tr>
            </tbody>
        </table>

        <button class="execute-btn" onclick="analyzeTexts()">Execute Collation</button>

        <div id="results" class="results-section">
            <h2><span class="section-number">5.</span>RESULTS</h2>

            <h3>5.1 Statistical Summary</h3>
            <table class="stats-table">
                <caption>Table 1. Quantitative Analysis of Textual Correspondence</caption>
                <thead>
                    <tr>
                        <th>Metric</th>
                        <th>Value</th>
                        <th>Unit</th>
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        <td>Total Alignments</td>
                        <td id="total-matches">0</td>
                        <td>count</td>
                    </tr>
                    <tr>
                        <td>Mean Similarity</td>
                        <td id="avg-similarity">0.00</td>
                        <td>%</td>
                    </tr>
                    <tr>
                        <td>Coverage Ratio</td>
                        <td id="coverage">0.00</td>
                        <td>%</td>
                    </tr>
                    <tr>
                        <td>Unique N-grams</td>
                        <td id="unique-phrases">0</td>
                        <td>count</td>
                    </tr>
                </tbody>
            </table>

            <div class="figure-container">
                <div class="figure-caption">Figure 1. Morphological Alignment Matrix</div>
                <div class="figure-content">
                    <div id="parallel-viewer">
                        <div class="parallel-container">
                            <div class="parallel-column">
                                <h4>Witness α</h4>
                                <div id="source-parallel" class="parallel-text"></div>
                            </div>
                            <div class="parallel-column">
                                <h4>Witness β</h4>
                                <div id="target-parallel" class="parallel-text"></div>
                            </div>
                        </div>
                        <table class="legend-table">
                            <thead>
                                <tr>
                                    <th colspan="2">Similarity Index</th>
                                    <th colspan="2">Script Classification</th>
                                </tr>
                            </thead>
                            <tbody>
                                <tr>
                                    <td><span class="color-sample" style="background: #d4e6d4; border-color: #27ae60;"></span></td>
                                    <td>Exact (σ = 1.0)</td>
                                    <td>Regular</td>
                                    <td>Coptic</td>
                                </tr>
                                <tr>
                                    <td><span class="color-sample" style="background: #dce7f1; border-color: #3498db;"></span></td>
                                    <td>High (σ > 0.8)</td>
                                    <td>Italic</td>
                                    <td>Greek</td>
                                </tr>
                                <tr>
                                    <td><span class="color-sample" style="border-bottom: 2px dashed #7f8c8d; background: white;"></span></td>
                                    <td>Medium (0.6 ≤ σ ≤ 0.8)</td>
                                    <td>Roman</td>
                                    <td>Latin</td>
                                </tr>
                                <tr>
                                    <td><span class="color-sample" style="border-bottom: 2px dotted #95a5a6; background: white;"></span></td>
                                    <td>Low (0.4 ≤ σ < 0.6)</td>
                                    <td>—</td>
                                    <td>—</td>
                                </tr>
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>

            <div class="figure-container">
                <div class="figure-caption">Figure 2. Similarity Matrix Visualization</div>
                <div class="figure-content">
                    <div id="heatmap"></div>
                </div>
            </div>

            <div class="figure-container">
                <div class="figure-caption">Figure 3. Text Reuse Network Graph</div>
                <div class="figure-content">
                    <div id="similarity-graph"></div>
                </div>
            </div>

            <h3>5.2 Detected Parallel Passages</h3>
            <table class="matches-table">
                <caption>Table 2. Aligned Text Segments (Threshold τ ≥ 60%)</caption>
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Witness α</th>
                        <th>Witness β</th>
                        <th>σ</th>
                    </tr>
                </thead>
                <tbody id="matches-container">
                    <tr>
                        <td colspan="4" style="text-align: center; font-style: italic;">No alignments detected</td>
                    </tr>
                </tbody>
            </table>
        </div>

        <div class="footnotes">
            <div class="footnote">
                <sup class="footnote-number">1</sup> For theoretical foundations, see Jockers, M. L. (2013) <i>Macroanalysis: Digital Methods and Literary History</i>. University of Illinois Press; Smith, D. A., et al. (2014) "Computational Methods for Uncovering Reprinted Texts in Antebellum Newspapers." <i>American Literary History</i> 27.3: E1-E15.
            </div>
        </div>

        <div class="references">
            <h2>REFERENCES</h2>
            <div class="reference-entry">
                Bostock, M. (2011). D3: Data-Driven Documents. <i>IEEE Transactions on Visualization and Computer Graphics</i>, 17(12), 2301-2309.
            </div>
            <div class="reference-entry">
                ISO/IEC 10646:2017. <i>Information technology — Universal Coded Character Set (UCS)</i>. International Organization for Standardization.
            </div>
            <div class="reference-entry">
                Smith, T. F., & Waterman, M. S. (1981). Identification of common molecular subsequences. <i>Journal of Molecular Biology</i>, 147(1), 195-197.
            </div>
            <div class="reference-entry">
                Zanetti, F. (2022). Digital Codicology and Medieval Manuscripts. In <i>Handbook of Stemmatology</i> (pp. 456-489). De Gruyter.
            </div>
        </div>
    </div>

    <script>
        // Unicode range definitions for Coptic and Greek
        const UNICODE_RANGES = {
            coptic: {
                start: 0x2C80,
                end: 0x2CFF
            },
            greek: {
                start: 0x0370,
                end: 0x03FF,
                extended_start: 0x1F00,
                extended_end: 0x1FFF
            },
            combining: {
                start: 0x0300,
                end: 0x036F
            },
            coptic_epact: {
                start: 0x102E0,
                end: 0x102FF
            }
        };

        // Check if character is Coptic
        function isCoptic(char) {
            const code = char.charCodeAt(0);
            return (code >= UNICODE_RANGES.coptic.start && code <= UNICODE_RANGES.coptic.end) ||
                   (code >= UNICODE_RANGES.coptic_epact.start && code <= UNICODE_RANGES.coptic_epact.end);
        }

        // Check if character is Greek
        function isGreek(char) {
            const code = char.charCodeAt(0);
            return (code >= UNICODE_RANGES.greek.start && code <= UNICODE_RANGES.greek.end) ||
                   (code >= UNICODE_RANGES.greek.extended_start && code <= UNICODE_RANGES.greek.extended_end);
        }

        // Check if character is a combining mark
        function isCombining(char) {
            const code = char.charCodeAt(0);
            return code >= UNICODE_RANGES.combining.start && code <= UNICODE_RANGES.combining.end;
        }

        // Detect script type
        function detectScript(text) {
            let copticCount = 0;
            let greekCount = 0;
            let latinCount = 0;

            for (let char of text) {
                if (isCoptic(char)) copticCount++;
                else if (isGreek(char)) greekCount++;
                else if (/[a-zA-Z]/.test(char)) latinCount++;
            }

            const total = copticCount + greekCount + latinCount;
            if (total === 0) return 'unknown';

            const copticGreekRatio = (copticCount + greekCount) / total;
            if (copticGreekRatio > 0.8) return 'coptic';
            if (copticGreekRatio < 0.2) return 'latin';
            return 'mixed';
        }

        // Enhanced tokenization for Coptic, Greek and mixed scripts
        function tokenize(text, mode = 'auto') {
            text = text.normalize('NFC');

            if (mode === 'auto') {
                mode = detectScript(text);
            }

            let tokens = [];

            if (mode === 'coptic' || mode === 'mixed') {
                const copticGreekPattern = /([\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF][\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF\u0300-\u036F]*)/g;
                const latinPattern = /\b[a-zA-Z]+\b/g;
                const numberPattern = /\b\d+\b/g;

                const copticGreekMatches = text.match(copticGreekPattern) || [];
                const latinMatches = text.match(latinPattern) || [];
                const numberMatches = text.match(numberPattern) || [];

                const allMatches = [];

                copticGreekMatches.forEach(match => {
                    let index = text.indexOf(match);
                    let searchFrom = 0;
                    while (index !== -1 && !allMatches.some(m => m.index === index)) {
                        allMatches.push({token: match.toLowerCase(), index: index});
                        searchFrom = index + 1;
                        index = text.indexOf(match, searchFrom);
                    }
                });

                latinMatches.forEach(match => {
                    let index = text.indexOf(match);
                    let searchFrom = 0;
                    while (index !== -1 && !allMatches.some(m => m.index === index)) {
                        allMatches.push({token: match.toLowerCase(), index: index});
                        searchFrom = index + 1;
                        index = text.indexOf(match, searchFrom);
                    }
                });

                numberMatches.forEach(match => {
                    let index = text.indexOf(match);
                    let searchFrom = 0;
                    while (index !== -1 && !allMatches.some(m => m.index === index)) {
                        allMatches.push({token: match, index: index});
                        searchFrom = index + 1;
                        index = text.indexOf(match, searchFrom);
                    }
                });

                allMatches.sort((a, b) => a.index - b.index);
                tokens = allMatches.map(m => m.token);
            } else {
                tokens = text.toLowerCase().match(/\b\w+\b/g) || [];
            }

            return tokens;
        }

        // Get tokens with positions for parallel view
        function tokenizeWithPositions(text, mode = 'auto') {
            text = text.normalize('NFC');

            if (mode === 'auto') {
                mode = detectScript(text);
            }

            let tokens = [];

            if (mode === 'coptic' || mode === 'mixed') {
                const copticGreekPattern = /([\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF][\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF\u0300-\u036F]*)/g;
                const latinPattern = /\b[a-zA-Z]+\b/g;
                const numberPattern = /\b\d+\b/g;

                let match;
                while ((match = copticGreekPattern.exec(text)) !== null) {
                    const firstChar = match[0][0];
                    const type = isCoptic(firstChar) ? 'coptic' : isGreek(firstChar) ? 'greek' : 'mixed';
                    tokens.push({
                        text: match[0],
                        normalized: match[0].toLowerCase(),
                        start: match.index,
                        end: match.index + match[0].length,
                        type: type
                    });
                }

                while ((match = latinPattern.exec(text)) !== null) {
                    tokens.push({
                        text: match[0],
                        normalized: match[0].toLowerCase(),
                        start: match.index,
                        end: match.index + match[0].length,
                        type: 'latin'
                    });
                }

                while ((match = numberPattern.exec(text)) !== null) {
                    tokens.push({
                        text: match[0],
                        normalized: match[0],
                        start: match.index,
                        end: match.index + match[0].length,
                        type: 'number'
                    });
                }
            } else {
                const pattern = /\b\w+\b/g;
                let match;
                while ((match = pattern.exec(text)) !== null) {
                    tokens.push({
                        text: match[0],
                        normalized: match[0].toLowerCase(),
                        start: match.index,
                        end: match.index + match[0].length,
                        type: 'latin'
                    });
                }
            }

            tokens.sort((a, b) => a.start - b.start);
            return tokens;
        }

        // Calculate morpheme similarity with Greek support
        function calculateMorphemeSimilarity(morpheme1, morpheme2) {
            const normalizeText = (s) => {
                return s.toLowerCase()
                    .replace(/ⲛ̄/g, 'ⲛ')
                    .replace(/ⲙ̄/g, 'ⲙ')
                    .replace(/[\u0300-\u036F]/g, '')
                    .replace(/ά/g, 'α').replace(/έ/g, 'ε').replace(/ή/g, 'η')
                    .replace(/ί/g, 'ι').replace(/ό/g, 'ο').replace(/ύ/g, 'υ')
                    .replace(/ώ/g, 'ω').replace(/Ά/g, 'Α').replace(/Έ/g, 'Ε')
                    .replace(/Ή/g, 'Η').replace(/Ί/g, 'Ι').replace(/Ό/g, 'Ο')
                    .replace(/Ύ/g, 'Υ').replace(/Ώ/g, 'Ω')
                    .normalize('NFC');
            };

            const norm1 = normalizeText(morpheme1);
            const norm2 = normalizeText(morpheme2);

            if (norm1 === norm2) return 100;

            const distance = levenshteinDistance(norm1, norm2);
            const maxLen = Math.max(norm1.length, norm2.length);
            return maxLen === 0 ? 0 : (1 - distance / maxLen) * 100;
        }

        function createNGrams(tokens, n) {
            const ngrams = [];
            for (let i = 0; i <= tokens.length - n; i++) {
                ngrams.push(tokens.slice(i, i + n));
            }
            return ngrams;
        }

        function jaccardSimilarity(arr1, arr2) {
            const set1 = new Set(arr1);
            const set2 = new Set(arr2);
            const intersection = new Set([...set1].filter(x => set2.has(x)));
            const union = new Set([...set1, ...set2]);
            return union.size === 0 ? 0 : intersection.size / union.size;
        }

        function levenshteinDistance(str1, str2) {
            const matrix = [];
            for (let i = 0; i <= str2.length; i++) {
                matrix[i] = [i];
            }
            for (let j = 0; j <= str1.length; j++) {
                matrix[0][j] = j;
            }
            for (let i = 1; i <= str2.length; i++) {
                for (let j = 1; j <= str1.length; j++) {
                    if (str2.charAt(i - 1) === str1.charAt(j - 1)) {
                        matrix[i][j] = matrix[i - 1][j - 1];
                    } else {
                        matrix[i][j] = Math.min(
                            matrix[i - 1][j - 1] + 1,
                            matrix[i][j - 1] + 1,
                            matrix[i - 1][j] + 1
                        );
                    }
                }
            }
            return matrix[str2.length][str1.length];
        }

        // Coptic and Greek aware similarity calculation
        function copticGreekAwareSimilarity(str1, str2) {
            const normalizeText = (s) => {
                return s.toLowerCase()
                    .replace(/ⲛ̄/g, 'ⲛ')
                    .replace(/ⲙ̄/g, 'ⲙ')
                    .replace(/[\u0300-\u036F]/g, '')
                    .replace(/ά/g, 'α').replace(/έ/g, 'ε').replace(/ή/g, 'η')
                    .replace(/ί/g, 'ι').replace(/ό/g, 'ο').replace(/ύ/g, 'υ')
                    .replace(/ώ/g, 'ω')
                    .normalize('NFC');
            };

            const norm1 = normalizeText(str1);
            const norm2 = normalizeText(str2);

            const distance = levenshteinDistance(norm1, norm2);
            const maxLen = Math.max(norm1.length, norm2.length);
            return maxLen === 0 ? 100 : (1 - distance / maxLen) * 100;
        }

        function findMatches(sourceText, targetText, windowSize, threshold, algorithm, scriptMode) {
            const sourceTokens = tokenize(sourceText, scriptMode);
            const targetTokens = tokenize(targetText, scriptMode);
            const sourceNGrams = createNGrams(sourceTokens, windowSize);
            const targetNGrams = createNGrams(targetTokens, windowSize);
            const matches = [];

            for (let i = 0; i < sourceNGrams.length; i++) {
                for (let j = 0; j < targetNGrams.length; j++) {
                    let similarity = 0;
                    const sourcePhrase = sourceNGrams[i].join(' ');
                    const targetPhrase = targetNGrams[j].join(' ');

                    if (algorithm === 'ngram') {
                        similarity = jaccardSimilarity(sourceNGrams[i], targetNGrams[j]) * 100;
                    } else if (algorithm === 'jaccard') {
                        similarity = jaccardSimilarity(sourcePhrase.split(''), targetPhrase.split('')) * 100;
                    } else if (algorithm === 'levenshtein') {
                        const distance = levenshteinDistance(sourcePhrase, targetPhrase);
                        const maxLen = Math.max(sourcePhrase.length, targetPhrase.length);
                        similarity = (1 - distance / maxLen) * 100;
                    } else if (algorithm === 'coptic-aware') {
                        similarity = copticGreekAwareSimilarity(sourcePhrase, targetPhrase);
                    }

                    if (similarity >= threshold) {
                        matches.push({
                            sourceIndex: i,
                            targetIndex: j,
                            sourcePhrase: sourcePhrase,
                            targetPhrase: targetPhrase,
                            similarity: similarity,
                            sourcePosition: i,
                            targetPosition: j
                        });
                    }
                }
            }

            return matches;
        }

        // Create parallel text view with highlighting
        function createParallelView(sourceText, targetText, scriptMode) {
            const sourceTokens = tokenizeWithPositions(sourceText, scriptMode);
            const targetTokens = tokenizeWithPositions(targetText, scriptMode);

            const sourceContainer = document.getElementById('source-parallel');
            const targetContainer = document.getElementById('target-parallel');

            sourceContainer.innerHTML = '';
            targetContainer.innerHTML = '';

            const similarityMatrix = [];
            const alignments = [];

            sourceTokens.forEach((sourceToken, i) => {
                similarityMatrix[i] = [];
                targetTokens.forEach((targetToken, j) => {
                    const similarity = calculateMorphemeSimilarity(sourceToken.normalized, targetToken.normalized);
                    similarityMatrix[i][j] = similarity;

                    if (similarity >= 40) {
                        alignments.push({
                            sourceIndex: i,
                            targetIndex: j,
                            similarity: similarity,
                            sourceText: sourceToken.text,
                            targetText: targetToken.text
                        });
                    }
                });
            });

            alignments.sort((a, b) => b.similarity - a.similarity);

            const sourceAligned = new Set();
            const targetAligned = new Set();
            const finalAlignments = [];

            alignments.forEach(alignment => {
                if (!sourceAligned.has(alignment.sourceIndex) && !targetAligned.has(alignment.targetIndex)) {
                    sourceAligned.add(alignment.sourceIndex);
                    targetAligned.add(alignment.targetIndex);
                    finalAlignments.push(alignment);
                }
            });

            const sourceToTarget = new Map();
            const targetToSource = new Map();

            finalAlignments.forEach(alignment => {
                sourceToTarget.set(alignment.sourceIndex, {
                    index: alignment.targetIndex,
                    similarity: alignment.similarity
                });
                targetToSource.set(alignment.targetIndex, {
                    index: alignment.sourceIndex,
                    similarity: alignment.similarity
                });
            });

            // Build source parallel text
            let lastPos = 0;
            sourceTokens.forEach((token, i) => {
                if (token.start > lastPos) {
                    const spacer = document.createElement('span');
                    spacer.textContent = sourceText.substring(lastPos, token.start);
                    sourceContainer.appendChild(spacer);
                }

                const morphemeSpan = document.createElement('span');
                morphemeSpan.className = 'morpheme';
                morphemeSpan.textContent = token.text;
                morphemeSpan.dataset.index = i;
                morphemeSpan.dataset.type = token.type;

                if (token.type === 'greek') {
                    morphemeSpan.classList.add('greek-text');
                } else if (token.type === 'coptic') {
                    morphemeSpan.classList.add('coptic-text');
                }

                if (sourceToTarget.has(i)) {
                    const alignment = sourceToTarget.get(i);
                    if (alignment.similarity === 100) {
                        morphemeSpan.classList.add('exact-match');
                    } else if (alignment.similarity >= 80) {
                        morphemeSpan.classList.add('high-sim');
                    } else if (alignment.similarity >= 60) {
                        morphemeSpan.classList.add('medium-sim');
                    } else {
                        morphemeSpan.classList.add('low-sim');
                    }
                    morphemeSpan.classList.add('connected');

                    const tooltip = document.createElement('div');
                    tooltip.className = 'morpheme-tooltip';
                    tooltip.textContent = `σ=${(alignment.similarity/100).toFixed(2)}`;
                    morphemeSpan.appendChild(tooltip);

                    morphemeSpan.addEventListener('mouseenter', () => {
                        const targetIndex = alignment.index;
                        const targetMorpheme = targetContainer.querySelector(`[data-index="${targetIndex}"]`);
                        if (targetMorpheme) {
                            targetMorpheme.style.background = '#e8dcc0';
                        }
                    });

                    morphemeSpan.addEventListener('mouseleave', () => {
                        const targetIndex = alignment.index;
                        const targetMorpheme = targetContainer.querySelector(`[data-index="${targetIndex}"]`);
                        if (targetMorpheme) {
                            targetMorpheme.style.background = '';
                        }
                    });
                }

                sourceContainer.appendChild(morphemeSpan);
                lastPos = token.end;
            });

            if (lastPos < sourceText.length) {
                const spacer = document.createElement('span');
                spacer.textContent = sourceText.substring(lastPos);
                sourceContainer.appendChild(spacer);
            }

            // Build target parallel text
            lastPos = 0;
            targetTokens.forEach((token, i) => {
                if (token.start > lastPos) {
                    const spacer = document.createElement('span');
                    spacer.textContent = targetText.substring(lastPos, token.start);
                    targetContainer.appendChild(spacer);
                }

                const morphemeSpan = document.createElement('span');
                morphemeSpan.className = 'morpheme';
                morphemeSpan.textContent = token.text;
                morphemeSpan.dataset.index = i;
                morphemeSpan.dataset.type = token.type;

                if (token.type === 'greek') {
                    morphemeSpan.classList.add('greek-text');
                } else if (token.type === 'coptic') {
                    morphemeSpan.classList.add('coptic-text');
                }

                if (targetToSource.has(i)) {
                    const alignment = targetToSource.get(i);
                    if (alignment.similarity === 100) {
                        morphemeSpan.classList.add('exact-match');
                    } else if (alignment.similarity >= 80) {
                        morphemeSpan.classList.add('high-sim');
                    } else if (alignment.similarity >= 60) {
                        morphemeSpan.classList.add('medium-sim');
                    } else {
                        morphemeSpan.classList.add('low-sim');
                    }
                    morphemeSpan.classList.add('connected');

                    const tooltip = document.createElement('div');
                    tooltip.className = 'morpheme-tooltip';
                    tooltip.textContent = `σ=${(alignment.similarity/100).toFixed(2)}`;
                    morphemeSpan.appendChild(tooltip);

                    morphemeSpan.addEventListener('mouseenter', () => {
                        const sourceIndex = alignment.index;
                        const sourceMorpheme = sourceContainer.querySelector(`[data-index="${sourceIndex}"]`);
                        if (sourceMorpheme) {
                            sourceMorpheme.style.background = '#e8dcc0';
                        }
                    });

                    morphemeSpan.addEventListener('mouseleave', () => {
                        const sourceIndex = alignment.index;
                        const sourceMorpheme = sourceContainer.querySelector(`[data-index="${sourceIndex}"]`);
                        if (sourceMorpheme) {
                            sourceMorpheme.style.background = '';
                        }
                    });
                }

                targetContainer.appendChild(morphemeSpan);
                lastPos = token.end;
            });

            if (lastPos < targetText.length) {
                const spacer = document.createElement('span');
                spacer.textContent = targetText.substring(lastPos);
                targetContainer.appendChild(spacer);
            }

            // Add morpheme statistics table
            const existingStats = document.querySelector('.morpheme-stats-table');
            if (existingStats) {
                existingStats.remove();
            }

            const exactMatches = finalAlignments.filter(a => a.similarity === 100).length;
            const highMatches = finalAlignments.filter(a => a.similarity >= 80 && a.similarity < 100).length;
            const mediumMatches = finalAlignments.filter(a => a.similarity >= 60 && a.similarity < 80).length;
            const lowMatches = finalAlignments.filter(a => a.similarity >= 40 && a.similarity < 60).length;

            const statsTable = document.createElement('table');
            statsTable.className = 'morpheme-stats-table';
            statsTable.innerHTML = `
                <thead>
                    <tr>
                        <th>Category</th>
                        <th>Count</th>
                        <th>Percentage</th>
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        <td>Exact (σ = 1.0)</td>
                        <td>${exactMatches}</td>
                        <td>${(exactMatches / sourceTokens.length * 100).toFixed(1)}%</td>
                    </tr>
                    <tr>
                        <td>High (σ > 0.8)</td>
                        <td>${highMatches}</td>
                        <td>${(highMatches / sourceTokens.length * 100).toFixed(1)}%</td>
                    </tr>
                    <tr>
                        <td>Medium (0.6 ≤ σ ≤ 0.8)</td>
                        <td>${mediumMatches}</td>
                        <td>${(mediumMatches / sourceTokens.length * 100).toFixed(1)}%</td>
                    </tr>
                    <tr>
                        <td>Low (0.4 ≤ σ < 0.6)</td>
                        <td>${lowMatches}</td>
                        <td>${(lowMatches / sourceTokens.length * 100).toFixed(1)}%</td>
                    </tr>
                </tbody>
            `;

            document.getElementById('parallel-viewer').appendChild(statsTable);
        }

        function createHeatmap(matches, sourceLength, targetLength) {
            const svg = d3.select("#heatmap").html("");
            const width = document.getElementById("heatmap").clientWidth;
            const height = 350;
            const margin = {top: 40, right: 40, bottom: 40, left: 40};

            const svgElement = svg.append("svg")
                .attr("width", width)
                .attr("height", height);

            const xScale = d3.scaleLinear()
                .domain([0, sourceLength])
                .range([margin.left, width - margin.right]);

            const yScale = d3.scaleLinear()
                .domain([0, targetLength])
                .range([margin.top, height - margin.bottom]);

            const colorScale = d3.scaleSequential()
                .domain([0, 100])
                .interpolator(t => d3.interpolateRgb("#ecf0f1", "#34495e")(t));

            // Add axes
            svgElement.append("g")
                .attr("transform", `translate(0,${height - margin.bottom})`)
                .call(d3.axisBottom(xScale).ticks(10))
                .append("text")
                .attr("x", width / 2)
                .attr("y", 35)
                .attr("fill", "#2c3e50")
                .style("text-anchor", "middle")
                .style("font-size", "10pt")
                .text("Witness α Position");

            svgElement.append("g")
                .attr("transform", `translate(${margin.left},0)`)
                .call(d3.axisLeft(yScale).ticks(10))
                .append("text")
                .attr("transform", "rotate(-90)")
                .attr("y", -25)
                .attr("x", -height / 2)
                .attr("fill", "#2c3e50")
                .style("text-anchor", "middle")
                .style("font-size", "10pt")
                .text("Witness β Position");

            const cellSize = Math.min((width - margin.left - margin.right) / sourceLength, 
                                     (height - margin.top - margin.bottom) / targetLength, 
                                     15);

            svgElement.selectAll("rect")
                .data(matches)
                .enter()
                .append("rect")
                .attr("x", d => xScale(d.sourcePosition))
                .attr("y", d => yScale(d.targetPosition))
                .attr("width", cellSize)
                .attr("height", cellSize)
                .attr("fill", d => colorScale(100 - d.similarity))
                .attr("stroke", "#95a5a6")
                .attr("stroke-width", 0.5)
                .append("title")
                .text(d => `σ = ${(d.similarity/100).toFixed(2)}\nα: "${d.sourcePhrase}"\nβ: "${d.targetPhrase}"`);
        }

        function createNetworkGraph(matches) {
            const svg = d3.select("#similarity-graph").html("");
            const width = document.getElementById("similarity-graph").clientWidth;
            const height = 350;

            const svgElement = svg.append("svg")
                .attr("width", width)
                .attr("height", height);

            const nodeMap = new Map();
            matches.forEach(match => {
                if (!nodeMap.has(match.sourcePhrase)) {
                    nodeMap.set(match.sourcePhrase, {id: match.sourcePhrase, group: 'source'});
                }
                if (!nodeMap.has(match.targetPhrase)) {
                    nodeMap.set(match.targetPhrase, {id: match.targetPhrase, group: 'target'});
                }
            });

            const nodes = Array.from(nodeMap.values());
            const links = matches.map(match => ({
                source: match.sourcePhrase,
                target: match.targetPhrase,
                value: match.similarity
            }));

            const simulation = d3.forceSimulation(nodes)
                .force("link", d3.forceLink(links).id(d => d.id).distance(d => 150 - d.value))
                .force("charge", d3.forceManyBody().strength(-200))
                .force("center", d3.forceCenter(width / 2, height / 2));

            const link = svgElement.append("g")
                .selectAll("line")
                .data(links)
                .enter().append("line")
                .attr("stroke", "#95a5a6")
                .attr("stroke-opacity", d => d.value / 100)
                .attr("stroke-width", d => Math.sqrt(d.value / 20));

            const node = svgElement.append("g")
                .selectAll("circle")
                .data(nodes)
                .enter().append("circle")
                .attr("r", 5)
                .attr("fill", d => d.group === 'source' ? "#34495e" : "#8b7355")
                .attr("stroke", "#2c3e50")
                .attr("stroke-width", 1)
                .call(d3.drag()
                    .on("start", dragstarted)
                    .on("drag", dragged)
                    .on("end", dragended));

            node.append("title")
                .text(d => d.id);

            const label = svgElement.append("g")
                .selectAll("text")
                .data(nodes)
                .enter().append("text")
                .text(d => d.id.length > 15 ? d.id.substring(0, 15) + "..." : d.id)
                .style("font-size", "8pt")
                .style("fill", "#2c3e50");

            simulation.on("tick", () => {
                link
