                : "0.00";
            document.getElementById("coverage").textContent = coverage;

            const uniquePhrases = new Set([...matches.map(m => m.sourcePhrase), ...matches.map(m => m.targetPhrase)]);
            document.getElementById("unique-phrases").textContent = uniquePhrases.size;

            // Create visualizations
