{
  "name": "ICoMa - Intertextuality Collation Machine",
  "description": "A high-performance computational collation system for multilingual manuscript analysis, specializing in Coptic, Greek, and Latin scripts with advanced visualization capabilities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Token {
  text: string;
  normalized: string;
  start: number;
  end: number;
  type: 'coptic' | 'greek' | 'latin' | 'number' | 'mixed';
  index: number;
}

export interface Alignment {
  sourceIndex: number;
  targetIndex: number;
  similarity: number;
  sourceText: string;
  targetText: string;
}

export interface Match {
  sourceIndex: number;
  targetIndex: number;
  sourcePhrase: string;
  targetPhrase: string;
  similarity: number;
  sourcePosition: number; // Token index start
  targetPosition: number; // Token index start
}

export type AlgorithmType = 'ngram' | 'jaccard' | 'levenshtein' | 'coptic-aware';
export type ScriptMode = 'auto' | 'coptic' | 'mixed' | 'latin';

export interface AnalysisConfig {
  windowSize: number;
  threshold: number;
  algorithm: AlgorithmType;
  scriptMode: ScriptMode;
}

export interface AnalysisStats {
  totalAlignments: number;
  meanSimilarity: number;
  coverage: number;
  uniqueNgrams: number;
}

export interface AnalysisResult {
  tokensA: Token[];
  tokensB: Token[];
  matches: Match[];
  alignments: Alignment[];
  stats: AnalysisStats;
}

import { Token, Match, Alignment, AlgorithmType, ScriptMode } from '../types';

// Unicode Ranges
const RANGES = {
  coptic: { start: 0x2C80, end: 0x2CFF },
  greek: { start: 0x0370, end: 0x03FF, extStart: 0x1F00, extEnd: 0x1FFF },
  copticEpact: { start: 0x102E0, end: 0x102FF }
};

const isCoptic = (char: string): boolean => {
  const code = char.charCodeAt(0);
  return (code >= RANGES.coptic.start && code <= RANGES.coptic.end) ||
         (code >= RANGES.copticEpact.start && code <= RANGES.copticEpact.end);
};

const isGreek = (char: string): boolean => {
  const code = char.charCodeAt(0);
  return (code >= RANGES.greek.start && code <= RANGES.greek.end) ||
         (code >= RANGES.greek.extStart && code <= RANGES.greek.extEnd);
};

export const detectScript = (text: string): ScriptMode => {
  let copticCount = 0;
  let greekCount = 0;
  let latinCount = 0;

  for (const char of text) {
    if (isCoptic(char)) copticCount++;
    else if (isGreek(char)) greekCount++;
    else if (/[a-zA-Z]/.test(char)) latinCount++;
  }

  const total = copticCount + greekCount + latinCount;
  if (total === 0) return 'latin'; // Default fallback

  const copticGreekRatio = (copticCount + greekCount) / total;
  if (copticGreekRatio > 0.8) return 'coptic';
  if (copticGreekRatio < 0.2) return 'latin';
  return 'mixed';
};

export const tokenize = (text: string, mode: ScriptMode = 'auto'): Token[] => {
  const normalizedText = text.normalize('NFC');
  const detectedMode = mode === 'auto' ? detectScript(normalizedText) : mode;

  const tokens: Token[] = [];

  if (detectedMode === 'coptic' || detectedMode === 'mixed') {
    // Complex tokenization for Coptic/Greek/Mixed
    const copticGreekPattern = /([\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF][\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF\u0300-\u036F]*)/g;
    const latinPattern = /\b[a-zA-Z]+\b/g;
    const numberPattern = /\b\d+\b/g;

    const patterns = [
      { regex: copticGreekPattern },
      { regex: latinPattern, type: 'latin' },
      { regex: numberPattern, type: 'number' }
    ];

    patterns.forEach(({ regex, type }) => {
      let match;
      while ((match = regex.exec(normalizedText)) !== null) {
        const firstChar = match[0][0];
        let tokenType = type;
        if (!tokenType) {
           tokenType = isCoptic(firstChar) ? 'coptic' : isGreek(firstChar) ? 'greek' : 'mixed';
        }

        tokens.push({
          text: match[0],
          normalized: match[0].toLowerCase(), // Basic normalization, refined later
          start: match.index,
          end: match.index + match[0].length,
          type: tokenType as any,
          index: 0 // Will set later
        });
      }
    });
  } else {
    // Simple Latin tokenization
    const pattern = /\b\w+\b/g;
    let match;
    while ((match = pattern.exec(normalizedText)) !== null) {
      tokens.push({
        text: match[0],
        normalized: match[0].toLowerCase(),
        start: match.index,
        end: match.index + match[0].length,
        type: 'latin',
        index: 0
      });
    }
  }

  // Sort by position and assign indices
  return tokens
    .sort((a, b) => a.start - b.start)
    .map((t, i) => ({ ...t, index: i }));
};

// Levenshtein Implementation
const levenshteinDistance = (str1: string, str2: string): number => {
  const track = Array(str2.length + 1).fill(null).map(() =>
    Array(str1.length + 1).fill(null));

  for (let i = 0; i <= str1.length; i += 1) track[0][i] = i;
  for (let j = 0; j <= str2.length; j += 1) track[j][0] = j;

  for (let j = 1; j <= str2.length; j += 1) {
    for (let i = 1; i <= str1.length; i += 1) {
      const indicator = str1[i - 1] === str2[j - 1] ? 0 : 1;
      track[j][i] = Math.min(
        track[j][i - 1] + 1,
        track[j - 1][i] + 1,
        track[j - 1][i - 1] + indicator,
      );
    }
  }
  return track[str2.length][str1.length];
};

// Advanced Coptic Normalization & Similarity
const calculateCopticSimilarity = (s1: string, s2: string): number => {
  const normalize = (s: string) => s.toLowerCase()
    .replace(/ⲛ̄/g, 'ⲛ')
    .replace(/ⲙ̄/g, 'ⲙ')
    .replace(/[\u0300-\u036F]/g, '') // strip diacritics
    // Greek standardizations often found in Coptic texts
    .replace(/[άἀἁἂἃἄἅἆἇὰάᾀᾁᾂᾃᾄᾅᾆᾇᾰᾱᾲᾳᾴᾶᾷΆἈἉἊἋἌἍἎἏᾈᾉᾊᾋᾌᾍᾎᾏᾸᾹᾺΆᾼ]/g, 'α')
    .replace(/[έἐἑἒἓἔἕὲέῈΈΈἘἙἚἛἜἝ]/g, 'ε')
    .replace(/[ήἠἡἢἣἤἥἦἧὴήᾐᾑᾒᾓᾔᾕᾖᾗῂῃῄῆῇΉἨἩἪἫἬἭἮἯᾘᾙᾚᾛᾜᾝᾞᾟῊΉῌ]/g, 'η')
    .replace(/[ίἰἱἲἳἴἵἶἷὶίῐῑῒΐῖῗΊἸἹἺἻἼἽἾἿῘῙῚΊ]/g, 'ι')
    .replace(/[όὀὁὂὃὄὅὸόΌὈὉὊὋὌὍῸΌ]/g, 'ο')
    .replace(/[ύὐὑὒὓὔὕὖὗὺύῠῡῢΰῦῧΎὙὛὝὟῨῩῪΎ]/g, 'υ')
    .replace(/[ώὠὡὢὣὤὥὦὧὼώᾠᾡᾢᾣᾤᾥᾦᾧῲῳῴῶῷΏὨὩὪὫὬὭὮὯᾨᾩᾪᾫᾬᾭᾮᾯῺΏῼ]/g, 'ω')
    .normalize('NFC');

  const n1 = normalize(s1);
  const n2 = normalize(s2);

  if (n1 === n2) return 100;

  const dist = levenshteinDistance(n1, n2);
  const maxLen = Math.max(n1.length, n2.length);
  return maxLen === 0 ? 100 : (1 - dist / maxLen) * 100;
};

// Jaccard for arrays
const jaccard = (a: any[], b: any[]): number => {
  const setA = new Set(a);
  const setB = new Set(b);
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  const union = new Set([...setA, ...setB]);
  return union.size === 0 ? 0 : intersection.size / union.size;
};

// Main Analysis Function
export const runAnalysis = (
  textA: string, 
  textB: string, 
  config: { windowSize: number; threshold: number; algorithm: AlgorithmType; scriptMode: ScriptMode }
) => {
  const tokensA = tokenize(textA, config.scriptMode);
  const tokensB = tokenize(textB, config.scriptMode);

  const matches: Match[] = [];
  const alignments: Alignment[] = []; // For detailed word-by-word

  // 1. Sliding Window Analysis (N-Grams)
  const n = config.windowSize;

  for (let i = 0; i <= tokensA.length - n; i++) {
    const sliceA = tokensA.slice(i, i + n);
    const phraseA = sliceA.map(t => t.text).join(' ');
    const normPhraseA = sliceA.map(t => t.normalized).join('');

    for (let j = 0; j <= tokensB.length - n; j++) {
      const sliceB = tokensB.slice(j, j + n);
      const phraseB = sliceB.map(t => t.text).join(' ');
      const normPhraseB = sliceB.map(t => t.normalized).join('');

      let sim = 0;

      if (config.algorithm === 'ngram') {
        sim = jaccard(sliceA.map(t => t.normalized), sliceB.map(t => t.normalized)) * 100;
      } else if (config.algorithm === 'jaccard') {
        sim = jaccard(phraseA.split(''), phraseB.split('')) * 100;
      } else if (config.algorithm === 'levenshtein') {
        const dist = levenshteinDistance(normPhraseA, normPhraseB);
        const max = Math.max(normPhraseA.length, normPhraseB.length);
        sim = max === 0 ? 0 : (1 - dist / max) * 100;
      } else if (config.algorithm === 'coptic-aware') {
        sim = calculateCopticSimilarity(phraseA, phraseB);
      }

      if (sim >= config.threshold) {
        matches.push({
          sourceIndex: i, // Index in the N-gram list, roughly correlates to token index
          targetIndex: j,
          sourcePhrase: phraseA,
          targetPhrase: phraseB,
          similarity: sim,
          sourcePosition: i, // Token index
          targetPosition: j  // Token index
        });
      }
    }
  }

  // 2. Pairwise Token Alignment (for the Parallel Viewer)
  // This is computationally expensive O(N*M), so we optimize by only checking tokens that share some resemblance
  tokensA.forEach((tA, i) => {
    tokensB.forEach((tB, j) => {
       const sim = calculateCopticSimilarity(tA.normalized, tB.normalized);
       if (sim >= 40) { // Hard lower bound for visual noise reduction
         alignments.push({
           sourceIndex: i,
           targetIndex: j,
           similarity: sim,
           sourceText: tA.text,
           targetText: tB.text
         });
       }
    });
  });

  // Calculate Stats
  const avgSim = matches.length > 0 
    ? matches.reduce((acc, m) => acc + m.similarity, 0) / matches.length 
    : 0;

  const coverage = matches.length > 0
    ? ((matches.length * config.windowSize) / Math.min(tokensA.length, tokensB.length)) * 100
    : 0;

  const uniquePhrases = new Set([
    ...matches.map(m => m.sourcePhrase),
    ...matches.map(m => m.targetPhrase)
  ]);

  return {
    tokensA,
    tokensB,
    matches,
    alignments,
    stats: {
      totalAlignments: matches.length,
      meanSimilarity: avgSim,
      coverage: Math.min(coverage, 100), // Cap at 100%
      uniqueNgrams: uniquePhrases.size
    }
  };
};

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface HeatmapProps {
  matches: Match[];
  sourceLength: number;
  targetLength: number;
}

const Heatmap: React.FC<HeatmapProps> = ({ matches, sourceLength, targetLength }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || sourceLength === 0 || targetLength === 0) return;

    // Clear previous
    d3.select(containerRef.current).selectAll("*").remove();

    const margin = { top: 40, right: 20, bottom: 40, left: 50 };
    const width = containerRef.current.clientWidth - margin.left - margin.right;
    const height = 400 - margin.top - margin.bottom;

    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", width + margin.left + margin.right)
      .attr("height", height + margin.top + margin.bottom)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    // Scales
    const x = d3.scaleLinear()
      .domain([0, sourceLength])
      .range([0, width]);

    const y = d3.scaleLinear()
      .domain([0, targetLength])
      .range([0, height]);

    // Color Scale
    const color = d3.scaleSequential()
      .domain([0, 100])
      .interpolator(d3.interpolateRdBu); // Red-Blue divergence for academic feel

    // Axes
    svg.append("g")
      .attr("transform", `translate(0,${height})`)
      .call(d3.axisBottom(x).ticks(10))
      .append("text")
      .attr("x", width / 2)
      .attr("y", 35)
      .attr("fill", "#2c3e50")
      .attr("font-weight", "bold")
      .text("Witness α Position");

    svg.append("g")
      .call(d3.axisLeft(y).ticks(10))
      .append("text")
      .attr("transform", "rotate(-90)")
      .attr("y", -35)
      .attr("x", -height / 2)
      .attr("fill", "#2c3e50")
      .attr("font-weight", "bold")
      .text("Witness β Position");

    // Dynamic cell size
    const cellWidth = Math.max(2, width / sourceLength);
    const cellHeight = Math.max(2, height / targetLength);

    // Plot points
    svg.selectAll("rect")
      .data(matches)
      .enter()
      .append("rect")
      .attr("x", d => x(d.sourcePosition))
      .attr("y", d => y(d.targetPosition))
      .attr("width", cellWidth)
      .attr("height", cellHeight)
      .attr("fill", d => color(d.similarity)) // Invert similarity for visual logic if needed
      .attr("opacity", 0.8)
      .append("title")
      .text(d => `Similarity: ${d.similarity.toFixed(1)}%\nα: "${d.sourcePhrase}"\nβ: "${d.targetPhrase}"`);

  }, [matches, sourceLength, targetLength]);

  return <div ref={containerRef} className="w-full h-[400px] bg-white border border-gray-200 rounded-sm shadow-sm" />;
};

export default Heatmap;

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface NetworkGraphProps {
  matches: Match[];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ matches }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current) return;
    d3.select(containerRef.current).selectAll("*").remove();

    const width = containerRef.current.clientWidth;
    const height = 400;

    // Data prep
    const nodeMap = new Map();
    matches.forEach(m => {
      // Limit number of nodes for performance in browser
      if (matches.length > 500 && m.similarity < 80) return;

      if (!nodeMap.has(m.sourcePhrase)) nodeMap.set(m.sourcePhrase, { id: m.sourcePhrase, group: 'alpha' });
      if (!nodeMap.has(m.targetPhrase)) nodeMap.set(m.targetPhrase, { id: m.targetPhrase, group: 'beta' });
    });

    const nodes = Array.from(nodeMap.values());
    const links = matches
      .filter(m => nodeMap.has(m.sourcePhrase) && nodeMap.has(m.targetPhrase))
      .map(m => ({
        source: m.sourcePhrase,
        target: m.targetPhrase,
        value: m.similarity
      }));

    if (nodes.length === 0) return;

    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", width)
      .attr("height", height);

    const simulation = d3.forceSimulation(nodes as any)
      .force("link", d3.forceLink(links).id((d: any) => d.id).distance(100))
      .force("charge", d3.forceManyBody().strength(-200))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collide", d3.forceCollide(20));

    const link = svg.append("g")
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke", "#95a5a6")
      .attr("stroke-opacity", 0.6)
      .attr("stroke-width", d => Math.max(1, (d.value - 50) / 10));

    const node = svg.append("g")
      .selectAll("circle")
      .data(nodes)
      .join("circle")
      .attr("r", 6)
      .attr("fill", (d: any) => d.group === 'alpha' ? "#34495e" : "#8b7355")
      .attr("stroke", "#fff")
      .attr("stroke-width", 1.5)
      .call(d3.drag<any, any>()
        .on("start", (event, d) => {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          d.fx = d.x;
          d.fy = d.y;
        })
        .on("drag", (event, d) => {
          d.fx = event.x;
          d.fy = event.y;
        })
        .on("end", (event, d) => {
          if (!event.active) simulation.alphaTarget(0);
          d.fx = null;
          d.fy = null;
        }));

    node.append("title").text((d: any) => d.id);

    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      node
        .attr("cx", (d: any) => d.x)
        .attr("cy", (d: any) => d.y);
    });

  }, [matches]);

  return <div ref={containerRef} className="w-full h-[400px] bg-white border border-gray-200 rounded-sm shadow-sm" />;
};

export default NetworkGraph;

import React, { useState } from 'react';
import { Token, Alignment } from '../types';

interface ParallelViewerProps {
  tokensA: Token[];
  tokensB: Token[];
  alignments: Alignment[];
}

const ParallelViewer: React.FC<ParallelViewerProps> = ({ tokensA, tokensB, alignments }) => {
  const [hoveredIdx, setHoveredIdx] = useState<{ side: 'A' | 'B', index: number } | null>(null);

  // Map for quick lookup
  const alignmentMapA = new Map<number, Alignment[]>();
  const alignmentMapB = new Map<number, Alignment[]>();

  alignments.forEach(a => {
    if (!alignmentMapA.has(a.sourceIndex)) alignmentMapA.set(a.sourceIndex, []);
    alignmentMapA.get(a.sourceIndex)?.push(a);

    if (!alignmentMapB.has(a.targetIndex)) alignmentMapB.set(a.targetIndex, []);
    alignmentMapB.get(a.targetIndex)?.push(a);
  });

  // Get similarity class based on best match
  const getStyle = (tokenIdx: number, side: 'A' | 'B') => {
    const map = side === 'A' ? alignmentMapA : alignmentMapB;
    const matches = map.get(tokenIdx);

    if (!matches || matches.length === 0) return 'border-transparent text-gray-800';

    // Find best match
    const bestMatch = matches.reduce((prev, current) => (prev.similarity > current.similarity) ? prev : current);

    // Check if this token is currently relevant to the hovered token
    let isConnected = false;
    if (hoveredIdx) {
      if (hoveredIdx.side === side && hoveredIdx.index === tokenIdx) {
        isConnected = true; // Self
      } else if (hoveredIdx.side !== side) {
        // Check if the other side points to this one
        const hoverMatches = (hoveredIdx.side === 'A' ? alignmentMapA : alignmentMapB).get(hoveredIdx.index);
        if (hoverMatches?.some(m => (side === 'A' ? m.sourceIndex : m.targetIndex) === tokenIdx)) {
          isConnected = true;
        }
      }
    }

    const baseClass = "cursor-pointer transition-colors duration-200 border-b-2 ";
    const connectionClass = isConnected ? "bg-academic-gold/30 " : "";

    if (bestMatch.similarity === 100) return baseClass + connectionClass + "border-green-600 bg-green-50";
    if (bestMatch.similarity >= 80) return baseClass + connectionClass + "border-blue-500 bg-blue-50";
    if (bestMatch.similarity >= 60) return baseClass + connectionClass + "border-gray-400 border-dashed";
    return baseClass + connectionClass + "border-gray-300 border-dotted";
  };

  const renderTokens = (tokens: Token[], side: 'A' | 'B') => {
    let lastPos = 0;
    return (
      <div className="font-coptic text-lg leading-relaxed whitespace-pre-wrap">
        {tokens.map((token, i) => {
          const spacing = token.start > lastPos ? " " : ""; // Simple spacing approximation
          lastPos = token.end;

          return (
            <React.Fragment key={i}>
              {spacing}
              <span
                className={`inline-block mx-[1px] px-[1px] relative group ${getStyle(i, side)}`}
                onMouseEnter={() => setHoveredIdx({ side, index: i })}
                onMouseLeave={() => setHoveredIdx(null)}
              >
                {token.text}
                {/* Tooltip */}
                <span className="hidden group-hover:block absolute bottom-full left-1/2 -translate-x-1/2 mb-1 px-2 py-1 bg-academic-blue text-white text-xs rounded z-50 font-mono">
                  Idx: {i}
                  {side === 'A' ? 
                    alignmentMapA.get(i)?.map(m => ` → β[${m.targetIndex}]: ${m.similarity.toFixed(0)}%`) :
                    alignmentMapB.get(i)?.map(m => ` → α[${m.sourceIndex}]: ${m.similarity.toFixed(0)}%`)
                  }
                </span>
              </span>
            </React.Fragment>
          );
        })}
      </div>
    );
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 p-4 bg-white border border-gray-200 shadow-sm rounded-sm h-[500px] overflow-y-auto">
      <div>
        <h4 className="font-bold text-academic-blue uppercase border-b-2 border-academic-gold mb-4 pb-2 text-sm tracking-wider">Witness α (Primary)</h4>
        {renderTokens(tokensA, 'A')}
      </div>
      <div>
        <h4 className="font-bold text-academic-blue uppercase border-b-2 border-academic-gold mb-4 pb-2 text-sm tracking-wider">Witness β (Comparandum)</h4>
        {renderTokens(tokensB, 'B')}
      </div>
    </div>
  );
};

