import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface NetworkGraphProps {
  matches: Match[];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ matches }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isEmpty, setIsEmpty] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;

    // Clear previous graph
    d3.select(containerRef.current).selectAll("*").remove();

    // 1. Filter and Prepare Data
    // We only take the top 100 strongest matches to prevent browser lag if text is huge
    const relevantMatches = matches
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 100);

    if (relevantMatches.length === 0) {
      setIsEmpty(true);
      return;
    }
    setIsEmpty(false);

    const width = containerRef.current.clientWidth || 800;
    const height = 400;

    const nodeMap = new Map();
    relevantMatches.forEach(m => {
      if (!nodeMap.has(m.sourcePhrase)) nodeMap.set(m.sourcePhrase, { id: m.sourcePhrase, group: 'alpha', r: 5 });
      if (!nodeMap.has(m.targetPhrase)) nodeMap.set(m.targetPhrase, { id: m.targetPhrase, group: 'beta', r: 5 });
    });

    const nodes = Array.from(nodeMap.values());
    const links = relevantMatches.map(m => ({
      source: m.sourcePhrase,
      target: m.targetPhrase,
      value: m.similarity
    }));

    // 2. Setup SVG with Zoom
    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", "100%")
      .attr("height", height)
      .attr("viewBox", [0, 0, width, height])
      .attr("style", "max-width: 100%; height: auto; font: 10px sans-serif;");

    // Group for zooming
    const g = svg.append("g");

    const zoom = d3.zoom()
      .scaleExtent([0.1, 4])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    svg.call(zoom as any);

    // 3. Force Simulation
    const simulation = d3.forceSimulation(nodes as any)
      .force("link", d3.forceLink(links).id((d: any) => d.id).distance(150))
      .force("charge", d3.forceManyBody().strength(-300))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collide", d3.forceCollide(20));

    // 4. Draw Elements
    const link = g.append("g")
      .attr("stroke", "#95a5a6")
      .attr("stroke-opacity", 0.6)
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke-width", d => Math.max(1, (d.value - 40) / 10));

    const node = g.append("g")
      .attr("stroke", "#fff")
      .attr("stroke-width", 1.5)
      .selectAll("circle")
      .data(nodes)
      .join("circle")
      .attr("r", (d: any) => d.r + 3)
      .attr("fill", (d: any) => d.group === 'alpha' ? "#34495e" : "#8b7355")
      .attr("cursor", "grab")
      .call(d3.drag<any, any>()
        .on("start", (event, d) => {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          d.fx = d.x;
          d.fy = d.y;
          d3.select(event.sourceEvent.target).attr("cursor", "grabbing");
        })
        .on("drag", (event, d) => {
          d.fx = event.x;
          d.fy = event.y;
        })
        .on("end", (event, d) => {
          if (!event.active) simulation.alphaTarget(0);
          d.fx = null;
          d.fy = null;
          d3.select(event.sourceEvent.target).attr("cursor", "grab");
        }));

    node.append("title")
      .text((d: any) => d.id);

    // Labels (only for nodes with few connections or high importance to avoid clutter)
    const label = g.append("g")
      .attr("class", "labels")
      .selectAll("text")
      .data(nodes)
      .enter()
      .append("text")
      .text((d: any) => d.id.length > 20 ? d.id.substring(0, 20) + '...' : d.id)
      .attr("font-size", 10)
      .attr("dx", 12)
      .attr("dy", 4)
      .attr("fill", "#2c3e50")
      .style("pointer-events", "none")
      .style("text-shadow", "1px 1px 0px white, -1px -1px 0px white, 1px -1px 0px white, -1px 1px 0px white");

    // 5. Tick Function
    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      node
        .attr("cx", (d: any) => d.x)
        .attr("cy", (d: any) => d.y);

      label
        .attr("x", (d: any) => d.x)
        .attr("y", (d: any) => d.y);
    });

    // Cleanup
    return () => {
      simulation.stop();
    };
  }, [matches]);

  return (
    <div className="relative w-full bg-white border border-gray-200 rounded-sm shadow-sm overflow-hidden h-[400px]">
      <div ref={containerRef} className="w-full h-full" />

      {isEmpty && (
        <div className="absolute inset-0 flex items-center justify-center text-gray-400 bg-gray-50/80 font-mono text-sm">
          No network data available for current threshold.
        </div>
      )}

      <div className="absolute bottom-2 right-2 bg-white/90 px-2 py-1 text-[10px] border border-gray-200 text-gray-500 rounded pointer-events-none">
        Scroll to Zoom • Drag to Pan
      </div>
    </div>
  );
};

