import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface AlignmentFlowProps {
  matches: Match[];
  sourceLength: number;
  targetLength: number;
}

const AlignmentFlow: React.FC<AlignmentFlowProps> = ({ matches, sourceLength, targetLength }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || sourceLength === 0 || targetLength === 0) return;

    d3.select(containerRef.current).selectAll("*").remove();

    const margin = { top: 30, right: 20, bottom: 30, left: 20 };
    const width = containerRef.current.clientWidth - margin.left - margin.right;
    const height = 250 - margin.top - margin.bottom;

    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", width + margin.left + margin.right)
      .attr("height", height + margin.top + margin.bottom)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    // Scales
    const xScaleA = d3.scaleLinear().domain([0, sourceLength]).range([0, width]);
    const xScaleB = d3.scaleLinear().domain([0, targetLength]).range([0, width]);

    // Draw Axes (Bars representing the full text)
    // Top Bar (Source)
    svg.append("rect")
      .attr("x", 0)
      .attr("y", 0)
      .attr("width", width)
      .attr("height", 10)
      .attr("fill", "#34495e")
      .attr("rx", 2);

    svg.append("text")
      .attr("x", -5)
      .attr("y", 9)
      .attr("text-anchor", "end")
      .attr("font-size", "10px")
      .attr("fill", "#34495e")
      .attr("font-weight", "bold")
      .text("α");

    // Bottom Bar (Target)
    svg.append("rect")
      .attr("x", 0)
      .attr("y", height - 10)
      .attr("width", width)
      .attr("height", 10)
      .attr("fill", "#8b7355")
      .attr("rx", 2);

    svg.append("text")
      .attr("x", -5)
      .attr("y", height - 1)
      .attr("text-anchor", "end")
      .attr("font-size", "10px")
      .attr("fill", "#8b7355")
      .attr("font-weight", "bold")
      .text("β");

    // Draw Ribbons (Connectors)
    // We filter slightly to avoid visual chaos if too many matches
    const displayMatches = matches.length > 300 
      ? matches.filter(m => m.similarity > 70) 
      : matches;

    svg.selectAll("path")
      .data(displayMatches)
      .enter()
      .append("path")
      .attr("d", d => {
        const x1 = xScaleA(d.sourcePosition);
        const x2 = xScaleB(d.targetPosition);
        // Ribbon width approximation based on match length relative to total
        // We use a fixed small width for visibility, or scaled
        const w1 = Math.max(2, (d.sourcePhrase.length / 5) * (width / sourceLength)); 
        const w2 = Math.max(2, (d.targetPhrase.length / 5) * (width / targetLength));

        // Drawing a ribbon or a simple curve? A curve is cleaner for flow.
        // Let's draw a cubic bezier curve
        const path = d3.path();
        path.moveTo(x1, 10); // Start at bottom of top bar
        path.bezierCurveTo(x1, height / 2, x2, height / 2, x2, height - 10); // Curve to top of bottom bar
        return path.toString();
      })
      .attr("fill", "none")
      .attr("stroke", d => d3.interpolateRdBu(1 - (d.similarity / 100))) // Red for high diff, Blue for match? Or Gold?
      // Let's use Gold/Blue theme. 
      .attr("stroke", d => d.similarity > 90 ? "rgba(39, 174, 96, 0.4)" : (d.similarity > 70 ? "rgba(52, 152, 219, 0.3)" : "rgba(149, 165, 166, 0.2)"))
      .attr("stroke-width", d => Math.max(1, (d.similarity - 40) / 15))
      .style("mix-blend-mode", "multiply")
      .append("title")
      .text(d => `Transposition Check:\nα: ${d.sourcePosition}\nβ: ${d.targetPosition}\nSim: ${d.similarity.toFixed(1)}%`);

  }, [matches, sourceLength, targetLength]);

  return (
    <div className="w-full bg-white border border-gray-200 rounded-sm shadow-sm p-2">
      <div ref={containerRef} className="w-full h-[250px]" />
      <div className="text-[10px] text-gray-500 text-center mt-1">
        Crossing lines indicate textual transposition (change in word order).
      </div>
    </div>
  );
};

export default AlignmentFlow;

import React, { useEffect, useRef } from 'react';
import { Match } from '../types';

interface DispersionPlotProps {
  matches: Match[];
  sourceLength: number;
  targetLength: number;
}

const DispersionPlot: React.FC<DispersionPlotProps> = ({ matches, sourceLength, targetLength }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Handle high DPI
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const width = rect.width;
    const height = rect.height;

    // Clear
    ctx.clearRect(0, 0, width, height);

    // Config
    const barHeight = 25;
    const gap = 15;
    const row1Y = 20;
    const row2Y = row1Y + barHeight + gap;

    // Draw Background Tracks
    ctx.fillStyle = '#f8f9fa';
    ctx.fillRect(0, row1Y, width, barHeight);
    ctx.fillRect(0, row2Y, width, barHeight);

    // Labels
    ctx.fillStyle = '#2c3e50';
    ctx.font = '10px "IBM Plex Mono"';
    ctx.fillText("Witness α Dispersion", 0, row1Y - 5);
    ctx.fillText("Witness β Dispersion", 0, row2Y - 5);

    // Draw Matches
    matches.forEach(match => {
      // Opacity based on similarity
      const alpha = (match.similarity - 20) / 100; // Normalize somewhat

      // Color based on threshold
      let color = `rgba(149, 165, 166, ${alpha})`; // Grey default
      if (match.similarity >= 80) color = `rgba(41, 128, 185, ${alpha})`; // Blue
      if (match.similarity >= 95) color = `rgba(39, 174, 96, ${alpha})`; // Green

      ctx.fillStyle = color;

      // Plot on Alpha track
      const x1 = (match.sourcePosition / sourceLength) * width;
      // Width of mark based on length of phrase relative to doc
      const w1 = Math.max(1, (match.sourcePhrase.length / sourceLength) * width);
      ctx.fillRect(x1, row1Y, w1, barHeight);

      // Plot on Beta track
      const x2 = (match.targetPosition / targetLength) * width;
      const w2 = Math.max(1, (match.targetPhrase.length / targetLength) * width);
      ctx.fillRect(x2, row2Y, w2, barHeight);
    });

    // Draw borders
    ctx.strokeStyle = '#bdc3c7';
    ctx.lineWidth = 1;
    ctx.strokeRect(0, row1Y, width, barHeight);
    ctx.strokeRect(0, row2Y, width, barHeight);

  }, [matches, sourceLength, targetLength]);

  return (
    <div className="w-full bg-white border border-gray-200 rounded-sm shadow-sm p-4">
      <canvas ref={canvasRef} className="w-full h-[100px]" />
    </div>
  );
};

