// Added 'passim' (Character N-Grams) and 'tracer' (Word N-Grams)
export type AlgorithmType = 'passim' | 'tracer' | 'jaccard' | 'levenshtein' | 'coptic-aware';
export type ScriptMode = 'auto' | 'coptic' | 'mixed' | 'latin';

export interface AnalysisConfig {
  windowSize: number;
  threshold: number;
  algorithm: AlgorithmType;
  scriptMode: ScriptMode;
}

export interface AnalysisStats {
