import { Token, Match, Alignment, AlgorithmType, ScriptMode } from '../types';

// Unicode Ranges
const RANGES = {
  coptic: { start: 0x2C80, end: 0x2CFF },
  greek: { start: 0x0370, end: 0x03FF, extStart: 0x1F00, extEnd: 0x1FFF },
  copticEpact: { start: 0x102E0, end: 0x102FF }
};

const isCoptic = (char: string): boolean => {
  const code = char.charCodeAt(0);
  return (code >= RANGES.coptic.start && code <= RANGES.coptic.end) ||
         (code >= RANGES.copticEpact.start && code <= RANGES.copticEpact.end);
};

const isGreek = (char: string): boolean => {
  const code = char.charCodeAt(0);
  return (code >= RANGES.greek.start && code <= RANGES.greek.end) ||
         (code >= RANGES.greek.extStart && code <= RANGES.greek.extEnd);
};

export const detectScript = (text: string): ScriptMode => {
  let copticCount = 0;
  let greekCount = 0;
  let latinCount = 0;

  for (const char of text) {
    if (isCoptic(char)) copticCount++;
    else if (isGreek(char)) greekCount++;
    else if (/[a-zA-Z]/.test(char)) latinCount++;
  }

  const total = copticCount + greekCount + latinCount;
  if (total === 0) return 'latin'; // Default fallback

  const copticGreekRatio = (copticCount + greekCount) / total;
  if (copticGreekRatio > 0.8) return 'coptic';
  if (copticGreekRatio < 0.2) return 'latin';
  return 'mixed';
};

export const tokenize = (text: string, mode: ScriptMode = 'auto'): Token[] => {
  const normalizedText = text.normalize('NFC');
  const detectedMode = mode === 'auto' ? detectScript(normalizedText) : mode;

  const tokens: Token[] = [];

  if (detectedMode === 'coptic' || detectedMode === 'mixed') {
    // Complex tokenization for Coptic/Greek/Mixed
    const copticGreekPattern = /([\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF][\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF\u0300-\u036F]*)/g;
    const latinPattern = /\b[a-zA-Z]+\b/g;
    const numberPattern = /\b\d+\b/g;

    const patterns = [
      { regex: copticGreekPattern },
      { regex: latinPattern, type: 'latin' },
      { regex: numberPattern, type: 'number' }
    ];

    patterns.forEach(({ regex, type }) => {
      let match;
      while ((match = regex.exec(normalizedText)) !== null) {
        const firstChar = match[0][0];
        let tokenType = type;
        if (!tokenType) {
           tokenType = isCoptic(firstChar) ? 'coptic' : isGreek(firstChar) ? 'greek' : 'mixed';
        }

        tokens.push({
          text: match[0],
          normalized: match[0].toLowerCase(), // Basic normalization, refined later
          start: match.index,
          end: match.index + match[0].length,
          type: tokenType as any,
          index: 0 // Will set later
        });
      }
    });
  } else {
    // Simple Latin tokenization
    const pattern = /\b\w+\b/g;
    let match;
    while ((match = pattern.exec(normalizedText)) !== null) {
      tokens.push({
        text: match[0],
        normalized: match[0].toLowerCase(),
        start: match.index,
        end: match.index + match[0].length,
        type: 'latin',
        index: 0
      });
    }
  }

  // Sort by position and assign indices
  return tokens
    .sort((a, b) => a.start - b.start)
    .map((t, i) => ({ ...t, index: i }));
};

// Levenshtein Implementation
const levenshteinDistance = (str1: string, str2: string): number => {
  const track = Array(str2.length + 1).fill(null).map(() =>
    Array(str1.length + 1).fill(null));

  for (let i = 0; i <= str1.length; i += 1) track[0][i] = i;
  for (let j = 0; j <= str2.length; j += 1) track[j][0] = j;

  for (let j = 1; j <= str2.length; j += 1) {
    for (let i = 1; i <= str1.length; i += 1) {
      const indicator = str1[i - 1] === str2[j - 1] ? 0 : 1;
      track[j][i] = Math.min(
        track[j][i - 1] + 1,
        track[j - 1][i] + 1,
        track[j - 1][i - 1] + indicator,
      );
    }
  }
  return track[str2.length][str1.length];
};

// Advanced Coptic Normalization & Similarity
const calculateCopticSimilarity = (s1: string, s2: string): number => {
  const normalize = (s: string) => s.toLowerCase()
    .replace(/ⲛ̄/g, 'ⲛ')
    .replace(/ⲙ̄/g, 'ⲙ')
    .replace(/[\u0300-\u036F]/g, '') // strip diacritics
    .replace(/[άἀἁἂἃἄἅἆἇὰάᾀᾁᾂᾃᾄᾅᾆᾇᾰᾱᾲᾳᾴᾶᾷΆἈἉἊἋἌἍἎἏᾈᾉᾊᾋᾌᾍᾎᾏᾸᾹᾺΆᾼ]/g, 'α')
    .replace(/[έἐἑἒἓἔἕὲέῈΈΈἘἙἚἛἜἝ]/g, 'ε')
    .replace(/[ήἠἡἢἣἤἥἦἧὴήᾐᾑᾒᾓᾔᾕᾖᾗῂῃῄῆῇΉἨἩἪἫἬἭἮἯᾘᾙᾚᾛᾜᾝᾞᾟῊΉῌ]/g, 'η')
    .replace(/[ίἰἱἲἳἴἵἶἷὶίῐῑῒΐῖῗΊἸἹἺἻἼἽἾἿῘῙῚΊ]/g, 'ι')
    .replace(/[όὀὁὂὃὄὅὸόΌὈὉὊὋὌὍῸΌ]/g, 'ο')
    .replace(/[ύὐὑὒὓὔὕὖὗὺύῠῡῢΰῦῧΎὙὛὝὟῨῩῪΎ]/g, 'υ')
    .replace(/[ώὠὡὢὣὤὥὦὧὼώᾠᾡᾢᾣᾤᾥᾦᾧῲῳῴῶῷΏὨὩὪὫὬὭὮὯᾨᾩᾪᾫᾬᾭᾮᾯῺΏῼ]/g, 'ω')
    .normalize('NFC');

  const n1 = normalize(s1);
  const n2 = normalize(s2);

  if (n1 === n2) return 100;

  const dist = levenshteinDistance(n1, n2);
  const maxLen = Math.max(n1.length, n2.length);
  return maxLen === 0 ? 100 : (1 - dist / maxLen) * 100;
};

// Jaccard for arrays
const jaccard = (a: any[], b: any[]): number => {
  const setA = new Set(a);
  const setB = new Set(b);
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  const union = new Set([...setA, ...setB]);
  return union.size === 0 ? 0 : intersection.size / union.size;
};

// Character N-Grams helper (Passim style)
const getCharNGrams = (text: string, n: number) => {
  const grams = [];
  const normalized = text.replace(/\s+/g, '').toLowerCase(); // Minimal normalization for passim
  for (let i = 0; i <= normalized.length - n; i++) {
    grams.push({
      text: normalized.substring(i, i + n),
      index: i
    });
  }
  return grams;
};

// Main Analysis Function
export const runAnalysis = (
  textA: string, 
  textB: string, 
  config: { windowSize: number; threshold: number; algorithm: AlgorithmType; scriptMode: ScriptMode }
) => {
  const tokensA = tokenize(textA, config.scriptMode);
  const tokensB = tokenize(textB, config.scriptMode);

  const matches: Match[] = [];
  const alignments: Alignment[] = [];

  // --- PASSIM-STYLE (Character N-Grams) ---
  if (config.algorithm === 'passim') {
    // Heuristic: map windowSize tokens to approx characters (1 token ~ 5 chars)
    // Range 2-10 tokens -> 10-50 chars
    const charWindow = config.windowSize * 4;

    // We need raw text mapping back to tokens for visualization, which is complex.
    // For this simulation, we will run the sliding window on TOKENS but use Character logic inside.
    // Actually, true Passim ignores word boundaries. 
    // To fit our Token-based Visualization, we will check character overlaps of the *phrases* formed by tokens.

    const n = config.windowSize;
    for (let i = 0; i <= tokensA.length - n; i++) {
      const sliceA = tokensA.slice(i, i + n);
      const phraseA = sliceA.map(t => t.text).join('');

      for (let j = 0; j <= tokensB.length - n; j++) {
        const sliceB = tokensB.slice(j, j + n);
        const phraseB = sliceB.map(t => t.text).join('');

        // Character overlap coefficient
        const sim = calculateCopticSimilarity(phraseA, phraseB); // Reuse edit distance as it's robust like Passim's fuzzy match

        if (sim >= config.threshold) {
          matches.push({
            sourceIndex: i,
            targetIndex: j,
            sourcePhrase: phraseA, // raw concat
            targetPhrase: phraseB,
            similarity: sim,
            sourcePosition: i,
            targetPosition: j
          });
        }
      }
    }
  }
  // --- TRACER-STYLE (Word N-Grams / Feature-Based) ---
  else {
    // This covers 'tracer' (word n-gram), 'jaccard', 'levenshtein', 'coptic-aware'
    const n = config.windowSize;

    for (let i = 0; i <= tokensA.length - n; i++) {
      const sliceA = tokensA.slice(i, i + n);
      const phraseA = sliceA.map(t => t.text).join(' ');
      const normPhraseA = sliceA.map(t => t.normalized).join('');

      for (let j = 0; j <= tokensB.length - n; j++) {
        const sliceB = tokensB.slice(j, j + n);
        const phraseB = sliceB.map(t => t.text).join(' ');
        const normPhraseB = sliceB.map(t => t.normalized).join('');

        let sim = 0;

        if (config.algorithm === 'tracer') {
           // TRACER style usually implies exact or fuzzy word n-gram matching
           // We'll use a strict Word Jaccard here to simulate feature overlap
           sim = jaccard(sliceA.map(t => t.normalized), sliceB.map(t => t.normalized)) * 100;
        } else if (config.algorithm === 'jaccard') {
          sim = jaccard(phraseA.split(''), phraseB.split('')) * 100;
        } else if (config.algorithm === 'levenshtein') {
          const dist = levenshteinDistance(normPhraseA, normPhraseB);
          const max = Math.max(normPhraseA.length, normPhraseB.length);
          sim = max === 0 ? 0 : (1 - dist / max) * 100;
        } else if (config.algorithm === 'coptic-aware') {
          sim = calculateCopticSimilarity(phraseA, phraseB);
        }

        if (sim >= config.threshold) {
          matches.push({
            sourceIndex: i,
            targetIndex: j,
            sourcePhrase: phraseA,
            targetPhrase: phraseB,
            similarity: sim,
            sourcePosition: i,
            targetPosition: j
          });
        }
      }
    }
  }

  // 2. Pairwise Token Alignment (for the Parallel Viewer)
  // Computationally expensive O(N*M), optimized with pre-check
  tokensA.forEach((tA, i) => {
    tokensB.forEach((tB, j) => {
       const sim = calculateCopticSimilarity(tA.normalized, tB.normalized);
       if (sim >= 40) {
         alignments.push({
           sourceIndex: i,
           targetIndex: j,
           similarity: sim,
           sourceText: tA.text,
           targetText: tB.text
         });
       }
    });
  });

  // Calculate Stats
  const avgSim = matches.length > 0 
    ? matches.reduce((acc, m) => acc + m.similarity, 0) / matches.length 
    : 0;

  const coverage = matches.length > 0
    ? ((matches.length * config.windowSize) / Math.min(tokensA.length, tokensB.length)) * 100
    : 0;

  const uniquePhrases = new Set([
    ...matches.map(m => m.sourcePhrase),
    ...matches.map(m => m.targetPhrase)
  ]);

  return {
    tokensA,
    tokensB,
    matches,
    alignments,
    stats: {
      totalAlignments: matches.length,
      meanSimilarity: avgSim,
      coverage: Math.min(coverage, 100), // Cap at 100%
      uniqueNgrams: uniquePhrases.size
    }
  };
};

import React, { useState } from 'react';
import { Token, Alignment } from '../types';

interface ParallelViewerProps {
  tokensA: Token[];
  tokensB: Token[];
  alignments: Alignment[];
}

const ParallelViewer: React.FC<ParallelViewerProps> = ({ tokensA, tokensB, alignments }) => {
  const [hoveredIdx, setHoveredIdx] = useState<{ side: 'A' | 'B', index: number } | null>(null);

  // Map for quick lookup
  const alignmentMapA = new Map<number, Alignment[]>();
  const alignmentMapB = new Map<number, Alignment[]>();

  alignments.forEach(a => {
    if (!alignmentMapA.has(a.sourceIndex)) alignmentMapA.set(a.sourceIndex, []);
    alignmentMapA.get(a.sourceIndex)?.push(a);

    if (!alignmentMapB.has(a.targetIndex)) alignmentMapB.set(a.targetIndex, []);
    alignmentMapB.get(a.targetIndex)?.push(a);
  });

  // Get similarity class based on best match
  const getStyle = (tokenIdx: number, side: 'A' | 'B') => {
    const map = side === 'A' ? alignmentMapA : alignmentMapB;
    const matches = map.get(tokenIdx);

    if (!matches || matches.length === 0) return 'border-transparent text-gray-700/80';

    const bestMatch = matches.reduce((prev, current) => (prev.similarity > current.similarity) ? prev : current);

    let isConnected = false;
    if (hoveredIdx) {
      if (hoveredIdx.side === side && hoveredIdx.index === tokenIdx) {
        isConnected = true; 
      } else if (hoveredIdx.side !== side) {
        const hoverMatches = (hoveredIdx.side === 'A' ? alignmentMapA : alignmentMapB).get(hoveredIdx.index);
        if (hoverMatches?.some(m => (side === 'A' ? m.sourceIndex : m.targetIndex) === tokenIdx)) {
          isConnected = true;
        }
      }
    }

    const baseClass = "cursor-pointer transition-all duration-200 border-b-[3px] rounded-t-sm px-0.5 ";
    const connectionClass = isConnected ? "bg-academic-gold/20 scale-105 " : "";

    if (bestMatch.similarity === 100) return baseClass + connectionClass + "border-green-600/60 bg-green-50/50 hover:bg-green-100";
    if (bestMatch.similarity >= 80) return baseClass + connectionClass + "border-blue-500/60 bg-blue-50/50 hover:bg-blue-100";
    if (bestMatch.similarity >= 60) return baseClass + connectionClass + "border-gray-400/60 border-dashed bg-gray-50 hover:bg-gray-100";
    return baseClass + connectionClass + "border-gray-300/60 border-dotted";
  };

  const renderTokens = (tokens: Token[], side: 'A' | 'B') => {
    let lastPos = 0;
    return (
      <div className="font-coptic text-lg leading-loose text-justify p-1">
        {tokens.map((token, i) => {
          const spacing = token.start > lastPos ? " " : "";
          lastPos = token.end;

          return (
            <React.Fragment key={i}>
              {spacing}
              <span
                className={`inline-block relative group ${getStyle(i, side)}`}
                onMouseEnter={() => setHoveredIdx({ side, index: i })}
                onMouseLeave={() => setHoveredIdx(null)}
              >
                {token.text}
              </span>
            </React.Fragment>
          );
        })}
      </div>
    );
  };

  // Generate details for the sticky panel
  let activeDetails = null;
  if (hoveredIdx) {
    const { side, index } = hoveredIdx;
    const token = side === 'A' ? tokensA[index] : tokensB[index];
    const matches = side === 'A' ? alignmentMapA.get(index) : alignmentMapB.get(index);

    if (matches && matches.length > 0) {
      activeDetails = (
         <div className="flex gap-4 items-center">
            <div className="font-bold text-academic-blue">
               {side === 'A' ? 'Witness α' : 'Witness β'} Token {index}:
               <span className="ml-2 font-coptic text-lg bg-white px-2 py-1 rounded border border-gray-200">{token.text}</span>
            </div>
            <div className="text-gray-400">→</div>
            <div className="flex-1 flex flex-wrap gap-2">
               {matches.sort((a,b) => b.similarity - a.similarity).slice(0, 3).map((m, idx) => (
                  <div key={idx} className="bg-white border border-gray-200 px-2 py-1 rounded text-xs flex items-center shadow-sm">
                     <span className="font-bold text-academic-gold mr-1">{m.similarity.toFixed(0)}%</span>
                     match with 
                     <span className="font-mono ml-1 font-bold">{side === 'A' ? `β[${m.targetIndex}]` : `α[${m.sourceIndex}]`}</span>
                     <span className="font-coptic ml-2 text-gray-600">
                        {side === 'A' ? m.targetText : m.sourceText}
                     </span>
                  </div>
               ))}
               {matches.length > 3 && <span className="text-xs text-gray-500 self-center">+{matches.length - 3} more</span>}
            </div>
         </div>
      );
    } else {
      activeDetails = (
        <div className="text-gray-500 italic">No strong alignments detected for this token.</div>
      );
    }
  } else {
    activeDetails = (
       <div className="text-gray-400 italic text-center text-sm">Hover over highlighted text to inspect alignment details</div>
    );
  }

  return (
    <div className="flex flex-col border border-gray-200 shadow-sm rounded-sm h-[600px] bg-white">
      {/* Scrollable Content */}
      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-0 overflow-hidden">
        <div className="flex flex-col border-r border-gray-200 h-full overflow-hidden">
          <div className="bg-academic-paper p-3 border-b border-gray-200 sticky top-0 z-10">
            <h4 className="font-bold text-academic-blue uppercase text-xs tracking-wider flex items-center justify-between">
              <span>Witness α (Primary)</span>
              <span className="text-gray-400 font-mono text-[10px]">{tokensA.length} tokens</span>
            </h4>
          </div>
          <div className="overflow-y-auto flex-1 p-4 bg-white custom-scrollbar">
            {renderTokens(tokensA, 'A')}
          </div>
        </div>

        <div className="flex flex-col h-full overflow-hidden">
          <div className="bg-academic-paper p-3 border-b border-gray-200 sticky top-0 z-10">
            <h4 className="font-bold text-academic-blue uppercase text-xs tracking-wider flex items-center justify-between">
              <span>Witness β (Comparandum)</span>
              <span className="text-gray-400 font-mono text-[10px]">{tokensB.length} tokens</span>
            </h4>
          </div>
          <div className="overflow-y-auto flex-1 p-4 bg-white custom-scrollbar">
            {renderTokens(tokensB, 'B')}
          </div>
        </div>
      </div>

      {/* Detail Inspector Panel (Sticky Bottom) */}
      <div className="h-20 bg-gray-50 border-t border-gray-200 p-3 flex items-center">
         {activeDetails}
      </div>
    </div>
  );
};

