export default App;

export interface Token {
  text: string;
  normalized: string;
  start: number;
  end: number;
  type: 'coptic' | 'greek' | 'latin' | 'number' | 'mixed';
  index: number;
}

export interface Alignment {
  sourceIndex: number;
  targetIndex: number;
  similarity: number;
  sourceText: string;
  targetText: string;
}

export interface Match {
  sourceIndex: number;
  targetIndex: number;
  sourcePhrase: string;
  targetPhrase: string;
  similarity: number;
  sourcePosition: number; // Token index start
  targetPosition: number; // Token index start
  length?: number; // Number of tokens in the match (crucial for SW)
}

// Added 'passim' (Character N-Grams), 'tracer' (Word N-Grams), and 'smith-waterman'
export type AlgorithmType = 'passim' | 'tracer' | 'jaccard' | 'levenshtein' | 'coptic-aware' | 'smith-waterman';
export type ScriptMode = 'auto' | 'coptic' | 'mixed' | 'latin';

export interface AnalysisConfig {
  windowSize: number;
  threshold: number;
  algorithm: AlgorithmType;
  scriptMode: ScriptMode;
}

export interface AnalysisStats {
  totalAlignments: number;
  meanSimilarity: number;
  coverage: number;
  uniqueNgrams: number;
}

export interface AnalysisResult {
  tokensA: Token[];
  tokensB: Token[];
  matches: Match[];
  alignments: Alignment[];
  stats: AnalysisStats;
}

import { Token, Match, Alignment, AlgorithmType, ScriptMode } from '../types';

// Unicode Ranges
const RANGES = {
  coptic: { start: 0x2C80, end: 0x2CFF },
  greek: { start: 0x0370, end: 0x03FF, extStart: 0x1F00, extEnd: 0x1FFF },
  copticEpact: { start: 0x102E0, end: 0x102FF }
};

const isCoptic = (char: string): boolean => {
  const code = char.charCodeAt(0);
  return (code >= RANGES.coptic.start && code <= RANGES.coptic.end) ||
         (code >= RANGES.copticEpact.start && code <= RANGES.copticEpact.end);
};

const isGreek = (char: string): boolean => {
  const code = char.charCodeAt(0);
  return (code >= RANGES.greek.start && code <= RANGES.greek.end) ||
         (code >= RANGES.greek.extStart && code <= RANGES.greek.extEnd);
};

export const detectScript = (text: string): ScriptMode => {
  let copticCount = 0;
  let greekCount = 0;
  let latinCount = 0;

  for (const char of text) {
    if (isCoptic(char)) copticCount++;
    else if (isGreek(char)) greekCount++;
    else if (/[a-zA-Z]/.test(char)) latinCount++;
  }

  const total = copticCount + greekCount + latinCount;
  if (total === 0) return 'latin'; // Default fallback

  const copticGreekRatio = (copticCount + greekCount) / total;
  if (copticGreekRatio > 0.8) return 'coptic';
  if (copticGreekRatio < 0.2) return 'latin';
  return 'mixed';
};

export const tokenize = (text: string, mode: ScriptMode = 'auto'): Token[] => {
  const normalizedText = text.normalize('NFC');
  const detectedMode = mode === 'auto' ? detectScript(normalizedText) : mode;

  const tokens: Token[] = [];

  if (detectedMode === 'coptic' || detectedMode === 'mixed') {
    // Complex tokenization for Coptic/Greek/Mixed
    const copticGreekPattern = /([\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF][\u2C80-\u2CFF\u0370-\u03FF\u1F00-\u1FFF\u0300-\u036F]*)/g;
    const latinPattern = /\b[a-zA-Z]+\b/g;
    const numberPattern = /\b\d+\b/g;

    const patterns = [
      { regex: copticGreekPattern },
      { regex: latinPattern, type: 'latin' },
      { regex: numberPattern, type: 'number' }
    ];

    patterns.forEach(({ regex, type }) => {
      let match;
      while ((match = regex.exec(normalizedText)) !== null) {
        const firstChar = match[0][0];
        let tokenType = type;
        if (!tokenType) {
           tokenType = isCoptic(firstChar) ? 'coptic' : isGreek(firstChar) ? 'greek' : 'mixed';
        }

        tokens.push({
          text: match[0],
          normalized: match[0].toLowerCase(), // Basic normalization, refined later
          start: match.index,
          end: match.index + match[0].length,
          type: tokenType as any,
          index: 0 // Will set later
        });
      }
    });
  } else {
    // Simple Latin tokenization
    const pattern = /\b\w+\b/g;
    let match;
    while ((match = pattern.exec(normalizedText)) !== null) {
      tokens.push({
        text: match[0],
        normalized: match[0].toLowerCase(),
        start: match.index,
        end: match.index + match[0].length,
        type: 'latin',
        index: 0
      });
    }
  }

  // Sort by position and assign indices
  return tokens
    .sort((a, b) => a.start - b.start)
    .map((t, i) => ({ ...t, index: i }));
};

// Levenshtein Implementation
const levenshteinDistance = (str1: string, str2: string): number => {
  const track = Array(str2.length + 1).fill(null).map(() =>
    Array(str1.length + 1).fill(null));

  for (let i = 0; i <= str1.length; i += 1) track[0][i] = i;
  for (let j = 0; j <= str2.length; j += 1) track[j][0] = j;

  for (let j = 1; j <= str2.length; j += 1) {
    for (let i = 1; i <= str1.length; i += 1) {
      const indicator = str1[i - 1] === str2[j - 1] ? 0 : 1;
      track[j][i] = Math.min(
        track[j][i - 1] + 1,
        track[j - 1][i] + 1,
        track[j - 1][i - 1] + indicator,
      );
    }
  }
  return track[str2.length][str1.length];
};

// Advanced Coptic Normalization & Similarity
const calculateCopticSimilarity = (s1: string, s2: string): number => {
  const normalize = (s: string) => s.toLowerCase()
    .replace(/ⲛ̄/g, 'ⲛ')
    .replace(/ⲙ̄/g, 'ⲙ')
    .replace(/[\u0300-\u036F]/g, '') // strip diacritics
    .replace(/[άἀἁἂἃἄἅἆἇὰάᾀᾁᾂᾃᾄᾅᾆᾇᾰᾱᾲᾳᾴᾶᾷΆἈἉἊἋἌἍἎἏᾈᾉᾊᾋᾌᾍᾎᾏᾸᾹᾺΆᾼ]/g, 'α')
    .replace(/[έἐἑἒἓἔἕὲέῈΈΈἘἙἚἛἜἝ]/g, 'ε')
    .replace(/[ήἠἡἢἣἤἥἦἧὴήᾐᾑᾒᾓᾔᾕᾖᾗῂῃῄῆῇΉἨἩἪἫἬἭἮἯᾘᾙᾚᾛᾜᾝᾞᾟῊΉῌ]/g, 'η')
    .replace(/[ίἰἱἲἳἴἵἶἷὶίῐῑῒΐῖῗΊἸἹἺἻἼἽἾἿῘῙῚΊ]/g, 'ι')
    .replace(/[όὀὁὂὃὄὅὸόΌὈὉὊὋὌὍῸΌ]/g, 'ο')
    .replace(/[ύὐὑὒὓὔὕὖὗὺύῠῡῢΰῦῧΎὙὛὝὟῨῩῪΎ]/g, 'υ')
    .replace(/[ώὠὡὢὣὤὥὦὧὼώᾠᾡᾢᾣᾤᾥᾦᾧῲῳῴῶῷΏὨὩὪὫὬὭὮὯᾨᾩᾪᾫᾬᾭᾮᾯῺΏῼ]/g, 'ω')
    .normalize('NFC');

  const n1 = normalize(s1);
  const n2 = normalize(s2);

  if (n1 === n2) return 100;

  const dist = levenshteinDistance(n1, n2);
  const maxLen = Math.max(n1.length, n2.length);
  return maxLen === 0 ? 100 : (1 - dist / maxLen) * 100;
};

// Jaccard for arrays
const jaccard = (a: any[], b: any[]): number => {
  const setA = new Set(a);
  const setB = new Set(b);
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  const union = new Set([...setA, ...setB]);
  return union.size === 0 ? 0 : intersection.size / union.size;
};

// Smith-Waterman Implementation (Token based)
const runSmithWaterman = (tokensA: Token[], tokensB: Token[], threshold: number): Match[] => {
  const m = tokensA.length;
  const n = tokensB.length;

  // Scoring scheme
  const MATCH_SCORE = 2;
  const MISMATCH_SCORE = -1;
  const GAP_SCORE = -1;

  // Initialize matrix
  const matrix: number[][] = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));
  let maxScore = 0;
  let maxI = 0;
  let maxJ = 0;

  // Fill matrix
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const tokenSim = calculateCopticSimilarity(tokensA[i-1].normalized, tokensB[j-1].normalized);
      const isMatch = tokenSim >= 80; // Fuzzy match threshold for SW steps

      const scoreDiag = matrix[i-1][j-1] + (isMatch ? MATCH_SCORE : MISMATCH_SCORE);
      const scoreUp = matrix[i-1][j] + GAP_SCORE;
      const scoreLeft = matrix[i][j-1] + GAP_SCORE;

      matrix[i][j] = Math.max(0, scoreDiag, scoreUp, scoreLeft);

      if (matrix[i][j] > maxScore) {
        maxScore = matrix[i][j];
        maxI = i;
        maxJ = j;
      }
    }
  }

  // Traceback (Finds ONE best local alignment)
  // For a real app, we might want Iterative SW to find multiple regions.
  // Here we return the single strongest continuous reused passage.
  const pathA: number[] = []; // indices
  const pathB: number[] = [];

  let i = maxI;
  let j = maxJ;

  while (matrix[i][j] > 0) {
    const currentScore = matrix[i][j];
    const tokenSim = calculateCopticSimilarity(tokensA[i-1].normalized, tokensB[j-1].normalized);
    const isMatch = tokenSim >= 80;

    // Check diagonal
    if (i > 0 && j > 0 && 
        (matrix[i-1][j-1] + (isMatch ? MATCH_SCORE : MISMATCH_SCORE) === currentScore || 
         (isMatch && matrix[i-1][j-1] >= matrix[i-1][j] && matrix[i-1][j-1] >= matrix[i][j-1]))) {
      pathA.unshift(i - 1);
      pathB.unshift(j - 1);
      i--;
      j--;
    } 
    // Check Up
    else if (i > 0 && matrix[i-1][j] + GAP_SCORE === currentScore) {
      i--; 
      // Gap in B (skip token in A)
    } 
    // Check Left
    else if (j > 0 && matrix[i][j-1] + GAP_SCORE === currentScore) {
      j--;
      // Gap in A (skip token in B)
    } else {
      break;
    }
  }

  if (pathA.length === 0) return [];

  // Convert path to a single Match object (Region)
  const startA = pathA[0];
  const endA = pathA[pathA.length - 1];
  const startB = pathB[0];
  const endB = pathB[pathB.length - 1];

  const phraseA = tokensA.slice(startA, endA + 1).map(t => t.text).join(' ');
  const phraseB = tokensB.slice(startB, endB + 1).map(t => t.text).join(' ');

  // Calculate aggregate similarity of this region
  const sim = calculateCopticSimilarity(phraseA, phraseB);

  // Return as a single "block" match.
  // Ideally SW returns a chain of small matches, but for this app's "Match" architecture,
  // we represent the whole region as one match entity.
  return [{
    sourceIndex: startA,
    targetIndex: startB,
    sourcePhrase: phraseA,
    targetPhrase: phraseB,
    similarity: Math.min(100, sim + 20), // Boost score for SW finding meaningful structure
    sourcePosition: startA,
    targetPosition: startB,
    length: Math.max(pathA.length, pathB.length)
  }];
};

// Main Analysis Function
export const runAnalysis = (
  textA: string, 
  textB: string, 
  config: { windowSize: number; threshold: number; algorithm: AlgorithmType; scriptMode: ScriptMode }
) => {
  const tokensA = tokenize(textA, config.scriptMode);
  const tokensB = tokenize(textB, config.scriptMode);

  let matches: Match[] = [];
  const alignments: Alignment[] = [];

  // --- SMITH-WATERMAN ---
  if (config.algorithm === 'smith-waterman') {
    matches = runSmithWaterman(tokensA, tokensB, config.threshold);
  }
  // --- PASSIM-STYLE (Character N-Grams) ---
  else if (config.algorithm === 'passim') {
    // Heuristic: map windowSize tokens to approx characters (1 token ~ 5 chars)
    const n = config.windowSize;
    for (let i = 0; i <= tokensA.length - n; i++) {
      const sliceA = tokensA.slice(i, i + n);
      const phraseA = sliceA.map(t => t.text).join('');

      for (let j = 0; j <= tokensB.length - n; j++) {
        const sliceB = tokensB.slice(j, j + n);
        const phraseB = sliceB.map(t => t.text).join('');

        const sim = calculateCopticSimilarity(phraseA, phraseB);

        if (sim >= config.threshold) {
          matches.push({
            sourceIndex: i,
            targetIndex: j,
            sourcePhrase: phraseA, 
            targetPhrase: phraseB,
            similarity: sim,
            sourcePosition: i,
            targetPosition: j,
            length: n
          });
        }
      }
    }
  }
  // --- TRACER-STYLE & OTHERS (Word N-Grams) ---
  else {
    const n = config.windowSize;

    for (let i = 0; i <= tokensA.length - n; i++) {
      const sliceA = tokensA.slice(i, i + n);
      const phraseA = sliceA.map(t => t.text).join(' ');
      const normPhraseA = sliceA.map(t => t.normalized).join('');

      for (let j = 0; j <= tokensB.length - n; j++) {
        const sliceB = tokensB.slice(j, j + n);
        const phraseB = sliceB.map(t => t.text).join(' ');
        const normPhraseB = sliceB.map(t => t.normalized).join('');

        let sim = 0;

        if (config.algorithm === 'tracer') {
           sim = jaccard(sliceA.map(t => t.normalized), sliceB.map(t => t.normalized)) * 100;
        } else if (config.algorithm === 'jaccard') {
          sim = jaccard(phraseA.split(''), phraseB.split('')) * 100;
        } else if (config.algorithm === 'levenshtein') {
          const dist = levenshteinDistance(normPhraseA, normPhraseB);
          const max = Math.max(normPhraseA.length, normPhraseB.length);
          sim = max === 0 ? 0 : (1 - dist / max) * 100;
        } else if (config.algorithm === 'coptic-aware') {
          sim = calculateCopticSimilarity(phraseA, phraseB);
        }

        if (sim >= config.threshold) {
          matches.push({
            sourceIndex: i,
            targetIndex: j,
            sourcePhrase: phraseA,
            targetPhrase: phraseB,
            similarity: sim,
            sourcePosition: i,
            targetPosition: j,
            length: n
          });
        }
      }
    }
  }

  // 2. Pairwise Token Alignment (for the Parallel Viewer)
  tokensA.forEach((tA, i) => {
    tokensB.forEach((tB, j) => {
       const sim = calculateCopticSimilarity(tA.normalized, tB.normalized);
       if (sim >= 40) {
         alignments.push({
           sourceIndex: i,
           targetIndex: j,
           similarity: sim,
           sourceText: tA.text,
           targetText: tB.text
         });
       }
    });
  });

  // Calculate Stats
  const avgSim = matches.length > 0 
    ? matches.reduce((acc, m) => acc + m.similarity, 0) / matches.length 
    : 0;

  const totalMatchLength = matches.reduce((acc, m) => acc + (m.length || config.windowSize), 0);
  const coverage = Math.min(100, (totalMatchLength / (tokensA.length + tokensB.length / 2)) * 100);

  const uniquePhrases = new Set([
    ...matches.map(m => m.sourcePhrase),
    ...matches.map(m => m.targetPhrase)
  ]);

  return {
    tokensA,
    tokensB,
    matches,
    alignments,
    stats: {
      totalAlignments: matches.length,
      meanSimilarity: avgSim,
      coverage: coverage,
      uniqueNgrams: uniquePhrases.size
    }
  };
};

import React, { useState, useEffect, useRef } from 'react';
import { Token, Alignment, Match } from '../types';

interface ParallelViewerProps {
  tokensA: Token[];
  tokensB: Token[];
  alignments: Alignment[];
  selectedMatch: Match | null;
}

const ParallelViewer: React.FC<ParallelViewerProps> = ({ tokensA, tokensB, alignments, selectedMatch }) => {
  const [hoveredIdx, setHoveredIdx] = useState<{ side: 'A' | 'B', index: number } | null>(null);

  const containerARef = useRef<HTMLDivElement>(null);
  const containerBRef = useRef<HTMLDivElement>(null);

  // Auto-scroll when selectedMatch changes
  useEffect(() => {
    if (selectedMatch) {
      const scrollTokenA = containerARef.current?.querySelector(`[data-token-index="${selectedMatch.sourcePosition}"]`);
      const scrollTokenB = containerBRef.current?.querySelector(`[data-token-index="${selectedMatch.targetPosition}"]`);

      if (scrollTokenA) scrollTokenA.scrollIntoView({ behavior: 'smooth', block: 'center' });
      if (scrollTokenB) scrollTokenB.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [selectedMatch]);

  // Map for quick lookup
  const alignmentMapA = new Map<number, Alignment[]>();
  const alignmentMapB = new Map<number, Alignment[]>();

  alignments.forEach(a => {
    if (!alignmentMapA.has(a.sourceIndex)) alignmentMapA.set(a.sourceIndex, []);
    alignmentMapA.get(a.sourceIndex)?.push(a);

    if (!alignmentMapB.has(a.targetIndex)) alignmentMapB.set(a.targetIndex, []);
    alignmentMapB.get(a.targetIndex)?.push(a);
  });

  const getStyle = (tokenIdx: number, side: 'A' | 'B') => {
    const map = side === 'A' ? alignmentMapA : alignmentMapB;
    const matches = map.get(tokenIdx);

    // 1. Check if part of Selected Match
    if (selectedMatch) {
       const len = selectedMatch.length || 3; // default window size assumption if length missing
       const start = side === 'A' ? selectedMatch.sourcePosition : selectedMatch.targetPosition;
       if (tokenIdx >= start && tokenIdx < start + len) {
         return "bg-academic-gold text-white px-0.5 rounded shadow-sm border-b-[3px] border-academic-red scale-105 z-10 font-bold transition-all duration-300";
       }
    }

    // 2. Default Alignment Styling
    if (!matches || matches.length === 0) return 'border-transparent text-gray-700/80';
    const bestMatch = matches.reduce((prev, current) => (prev.similarity > current.similarity) ? prev : current);

    // 3. Hover Effects
    let isConnected = false;
    if (hoveredIdx) {
      if (hoveredIdx.side === side && hoveredIdx.index === tokenIdx) {
        isConnected = true; 
      } else if (hoveredIdx.side !== side) {
        const hoverMatches = (hoveredIdx.side === 'A' ? alignmentMapA : alignmentMapB).get(hoveredIdx.index);
        if (hoverMatches?.some(m => (side === 'A' ? m.sourceIndex : m.targetIndex) === tokenIdx)) {
          isConnected = true;
        }
      }
    }

    const baseClass = "cursor-pointer transition-all duration-200 border-b-[3px] rounded-t-sm px-0.5 ";
    const connectionClass = isConnected ? "bg-academic-gold/20 scale-105 " : "";

    if (bestMatch.similarity === 100) return baseClass + connectionClass + "border-green-600/60 bg-green-50/50 hover:bg-green-100";
    if (bestMatch.similarity >= 80) return baseClass + connectionClass + "border-blue-500/60 bg-blue-50/50 hover:bg-blue-100";
    if (bestMatch.similarity >= 60) return baseClass + connectionClass + "border-gray-400/60 border-dashed bg-gray-50 hover:bg-gray-100";
    return baseClass + connectionClass + "border-gray-300/60 border-dotted";
  };

  const renderTokens = (tokens: Token[], side: 'A' | 'B', ref: React.RefObject<HTMLDivElement>) => {
    let lastPos = 0;
    return (
      <div ref={ref} className="font-coptic text-lg leading-loose text-justify p-1">
        {tokens.map((token, i) => {
          const spacing = token.start > lastPos ? " " : "";
          lastPos = token.end;

          return (
            <React.Fragment key={i}>
              {spacing}
              <span
                data-token-index={i}
                className={`inline-block relative group ${getStyle(i, side)}`}
                onMouseEnter={() => setHoveredIdx({ side, index: i })}
                onMouseLeave={() => setHoveredIdx(null)}
              >
                {token.text}
              </span>
            </React.Fragment>
          );
        })}
      </div>
    );
  };

  // Sticky footer details
  let activeDetails = null;
  if (selectedMatch) {
     activeDetails = (
       <div className="flex gap-4 items-center w-full bg-academic-gold/10 p-2 rounded border border-academic-gold">
         <div className="font-bold text-academic-blue uppercase text-xs">Selected Reuse Pair</div>
         <div className="flex-1 flex flex-col md:flex-row gap-2 md:items-center text-sm">
            <div className="flex-1 font-coptic truncate border-r border-gray-300 pr-2" title={selectedMatch.sourcePhrase}>
              <span className="font-mono text-xs text-gray-500 mr-2">α[{selectedMatch.sourcePosition}]</span>
              {selectedMatch.sourcePhrase}
            </div>
            <div className="font-bold text-academic-red">≈ {selectedMatch.similarity.toFixed(0)}%</div>
            <div className="flex-1 font-coptic truncate pl-2" title={selectedMatch.targetPhrase}>
               <span className="font-mono text-xs text-gray-500 mr-2">β[{selectedMatch.targetPosition}]</span>
               {selectedMatch.targetPhrase}
            </div>
         </div>
         <button onClick={() => {}} className="text-xs underline text-gray-500 hover:text-gray-800">Clear</button>
       </div>
     );
  } else if (hoveredIdx) {
    const { side, index } = hoveredIdx;
    const token = side === 'A' ? tokensA[index] : tokensB[index];
    const matches = side === 'A' ? alignmentMapA.get(index) : alignmentMapB.get(index);

    if (matches && matches.length > 0) {
      activeDetails = (
         <div className="flex gap-4 items-center animate-fade-in">
            <div className="font-bold text-academic-blue">
               {side === 'A' ? 'Witness α' : 'Witness β'} Token {index}:
               <span className="ml-2 font-coptic text-lg bg-white px-2 py-1 rounded border border-gray-200">{token.text}</span>
            </div>
            <div className="text-gray-400">→</div>
            <div className="flex-1 flex flex-wrap gap-2">
               {matches.sort((a,b) => b.similarity - a.similarity).slice(0, 3).map((m, idx) => (
                  <div key={idx} className="bg-white border border-gray-200 px-2 py-1 rounded text-xs flex items-center shadow-sm">
                     <span className="font-bold text-academic-gold mr-1">{m.similarity.toFixed(0)}%</span>
                     match with 
                     <span className="font-mono ml-1 font-bold">{side === 'A' ? `β[${m.targetIndex}]` : `α[${m.sourceIndex}]`}</span>
                     <span className="font-coptic ml-2 text-gray-600">
                        {side === 'A' ? m.targetText : m.sourceText}
                     </span>
                  </div>
               ))}
            </div>
         </div>
      );
    } else {
      activeDetails = <div className="text-gray-500 italic">No strong alignments detected for this token.</div>;
    }
  } else {
    activeDetails = <div className="text-gray-400 italic text-center text-sm">Select a chart element or hover text to inspect details</div>;
  }

  return (
    <div className="flex flex-col border border-gray-200 shadow-sm rounded-sm h-[600px] bg-white">
      {/* Scrollable Content */}
      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-0 overflow-hidden">
        <div className="flex flex-col border-r border-gray-200 h-full overflow-hidden">
          <div className="bg-academic-paper p-3 border-b border-gray-200 sticky top-0 z-10">
            <h4 className="font-bold text-academic-blue uppercase text-xs tracking-wider flex items-center justify-between">
              <span>Witness α (Primary)</span>
              <span className="text-gray-400 font-mono text-[10px]">{tokensA.length} tokens</span>
            </h4>
          </div>
          <div ref={containerARef} className="overflow-y-auto flex-1 p-4 bg-white custom-scrollbar">
            {renderTokens(tokensA, 'A', containerARef)}
          </div>
        </div>

        <div className="flex flex-col h-full overflow-hidden">
          <div className="bg-academic-paper p-3 border-b border-gray-200 sticky top-0 z-10">
            <h4 className="font-bold text-academic-blue uppercase text-xs tracking-wider flex items-center justify-between">
              <span>Witness β (Comparandum)</span>
              <span className="text-gray-400 font-mono text-[10px]">{tokensB.length} tokens</span>
            </h4>
          </div>
          <div ref={containerBRef} className="overflow-y-auto flex-1 p-4 bg-white custom-scrollbar">
            {renderTokens(tokensB, 'B', containerBRef)}
          </div>
        </div>
      </div>

      {/* Detail Inspector Panel */}
      <div className="h-24 bg-gray-50 border-t border-gray-200 p-3 flex items-center overflow-hidden">
         {activeDetails}
      </div>
    </div>
  );
};

export default ParallelViewer;

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface NetworkGraphProps {
  matches: Match[];
  onSelectMatch: (match: Match) => void;
  selectedMatch: Match | null;
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ matches, onSelectMatch, selectedMatch }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isEmpty, setIsEmpty] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;
    d3.select(containerRef.current).selectAll("*").remove();

    const relevantMatches = matches
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 100);

    if (relevantMatches.length === 0) {
      setIsEmpty(true);
      return;
    }
    setIsEmpty(false);

    const width = containerRef.current.clientWidth || 800;
    const height = 400;

    // Use phrase string as ID. 
    // NOTE: Multiple matches might share the same phrase. We link specific matches in the edge data.
    const nodeMap = new Map();
    relevantMatches.forEach(m => {
      if (!nodeMap.has(m.sourcePhrase)) nodeMap.set(m.sourcePhrase, { id: m.sourcePhrase, group: 'alpha', r: 5 });
      if (!nodeMap.has(m.targetPhrase)) nodeMap.set(m.targetPhrase, { id: m.targetPhrase, group: 'beta', r: 5 });
    });

    const nodes = Array.from(nodeMap.values());
    // Attach the actual match object to the link for click handling
    const links = relevantMatches.map(m => ({
      source: m.sourcePhrase,
      target: m.targetPhrase,
      value: m.similarity,
      matchData: m
    }));

    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", "100%")
      .attr("height", height)
      .attr("viewBox", [0, 0, width, height]);

    const g = svg.append("g");
    const zoom = d3.zoom().scaleExtent([0.1, 4]).on("zoom", (event) => g.attr("transform", event.transform));
    svg.call(zoom as any);

    const simulation = d3.forceSimulation(nodes as any)
      .force("link", d3.forceLink(links).id((d: any) => d.id).distance(150))
      .force("charge", d3.forceManyBody().strength(-300))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collide", d3.forceCollide(20));

    // Links (Edges)
    const link = g.append("g")
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke", (d: any) => {
         // Highlight if selected
         if (selectedMatch && d.matchData === selectedMatch) return "#c9302c"; // Red
         return "#95a5a6";
      })
      .attr("stroke-opacity", (d: any) => selectedMatch && d.matchData === selectedMatch ? 1 : 0.6)
      .attr("stroke-width", (d: any) => {
         const base = Math.max(2, (d.value - 40) / 10);
         return selectedMatch && d.matchData === selectedMatch ? base + 3 : base;
      })
      .attr("cursor", "pointer")
      .on("click", (event, d: any) => {
        event.stopPropagation();
        onSelectMatch(d.matchData);
      });

    link.append("title").text((d: any) => `Click to view match (${d.value.toFixed(1)}%)`);

    // Nodes
    const node = g.append("g")
      .attr("stroke", "#fff")
      .attr("stroke-width", 1.5)
      .selectAll("circle")
      .data(nodes)
      .join("circle")
      .attr("r", (d: any) => d.r + 3)
      .attr("fill", (d: any) => d.group === 'alpha' ? "#34495e" : "#8b7355")
      .attr("cursor", "grab")
      .call(d3.drag<any, any>()
        .on("start", (event, d) => {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          d.fx = d.x;
          d.fy = d.y;
        })
        .on("drag", (event, d) => {
          d.fx = event.x;
          d.fy = event.y;
        })
        .on("end", (event, d) => {
          if (!event.active) simulation.alphaTarget(0);
          d.fx = null;
          d.fy = null;
        }));

    node.append("title").text((d: any) => d.id);

    const label = g.append("g")
      .selectAll("text")
      .data(nodes)
      .enter()
      .append("text")
      .text((d: any) => d.id.length > 15 ? d.id.substring(0, 15) + '...' : d.id)
      .attr("font-size", 10)
      .attr("dx", 12)
      .attr("dy", 4)
      .attr("fill", "#2c3e50")
      .style("pointer-events", "none");

    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      node.attr("cx", (d: any) => d.x).attr("cy", (d: any) => d.y);
      label.attr("x", (d: any) => d.x).attr("y", (d: any) => d.y);
    });

    return () => { simulation.stop(); };
  }, [matches, selectedMatch]); // Re-render when selection changes

  return (
    <div className="relative w-full bg-white border border-gray-200 rounded-sm shadow-sm overflow-hidden h-[400px]">
      <div ref={containerRef} className="w-full h-full" />
      {isEmpty && <div className="absolute inset-0 flex items-center justify-center text-gray-400">No network data.</div>}
      <div className="absolute bottom-2 right-2 bg-white/90 px-2 py-1 text-[10px] text-gray-500 rounded">Scroll to Zoom • Click lines to view pair</div>
    </div>
  );
};

export default NetworkGraph;

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface HeatmapProps {
  matches: Match[];
  sourceLength: number;
  targetLength: number;
  onSelectMatch: (match: Match) => void;
  selectedMatch: Match | null;
}

const Heatmap: React.FC<HeatmapProps> = ({ matches, sourceLength, targetLength, onSelectMatch, selectedMatch }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || sourceLength === 0 || targetLength === 0) return;

    d3.select(containerRef.current).selectAll("*").remove();

    const margin = { top: 40, right: 20, bottom: 40, left: 50 };
    const width = containerRef.current.clientWidth - margin.left - margin.right;
    const height = 400 - margin.top - margin.bottom;

    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", width + margin.left + margin.right)
      .attr("height", height + margin.top + margin.bottom)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    const x = d3.scaleLinear().domain([0, sourceLength]).range([0, width]);
    const y = d3.scaleLinear().domain([0, targetLength]).range([0, height]);
    const color = d3.scaleSequential().domain([0, 100]).interpolator(d3.interpolateRdBu);

    svg.append("g").attr("transform", `translate(0,${height})`).call(d3.axisBottom(x).ticks(10));
    svg.append("g").call(d3.axisLeft(y).ticks(10));

    svg.append("text").attr("x", width/2).attr("y", height + 35).attr("text-anchor", "middle").attr("font-size", "10px").text("Witness α Position");
    svg.append("text").attr("transform", "rotate(-90)").attr("y", -35).attr("x", -height/2).attr("text-anchor", "middle").attr("font-size", "10px").text("Witness β Position");

    const cellWidth = Math.max(4, width / sourceLength * 3); // Make slightly clickable
    const cellHeight = Math.max(4, height / targetLength * 3);

    svg.selectAll("rect")
      .data(matches)
      .enter()
      .append("rect")
      .attr("x", d => x(d.sourcePosition))
      .attr("y", d => y(d.targetPosition))
      .attr("width", cellWidth)
      .attr("height", cellHeight)
      .attr("fill", d => {
         if (selectedMatch === d) return "#c9302c"; // Highlight selected
         return color(d.similarity);
      })
      .attr("stroke", d => selectedMatch === d ? "black" : "none")
      .attr("stroke-width", 1)
      .attr("opacity", d => selectedMatch && selectedMatch !== d ? 0.3 : 0.8) // Dim others
      .attr("cursor", "pointer")
      .on("click", (event, d) => {
        event.stopPropagation();
        onSelectMatch(d);
      })
      .append("title")
      .text(d => `Similarity: ${d.similarity.toFixed(1)}%\nClick to view pair`);

  }, [matches, sourceLength, targetLength, selectedMatch]);

  return <div ref={containerRef} className="w-full h-[400px] bg-white border border-gray-200 rounded-sm shadow-sm" />;
};

export default Heatmap;

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface AlignmentFlowProps {
  matches: Match[];
  sourceLength: number;
  targetLength: number;
  onSelectMatch: (match: Match) => void;
  selectedMatch: Match | null;
}

const AlignmentFlow: React.FC<AlignmentFlowProps> = ({ matches, sourceLength, targetLength, onSelectMatch, selectedMatch }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || sourceLength === 0 || targetLength === 0) return;

    d3.select(containerRef.current).selectAll("*").remove();

    const margin = { top: 30, right: 20, bottom: 30, left: 20 };
    const width = containerRef.current.clientWidth - margin.left - margin.right;
    const height = 250 - margin.top - margin.bottom;

    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", width + margin.left + margin.right)
      .attr("height", height + margin.top + margin.bottom)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    const xScaleA = d3.scaleLinear().domain([0, sourceLength]).range([0, width]);
    const xScaleB = d3.scaleLinear().domain([0, targetLength]).range([0, width]);

    // Bars
    svg.append("rect").attr("width", width).attr("height", 10).attr("fill", "#34495e").attr("rx", 2);
    svg.append("rect").attr("y", height - 10).attr("width", width).attr("height", 10).attr("fill", "#8b7355").attr("rx", 2);

    const displayMatches = matches.length > 300 ? matches.filter(m => m.similarity > 70) : matches;

    // Ribbons
    svg.selectAll("path")
      .data(displayMatches)
      .enter()
      .append("path")
      .attr("d", d => {
        const x1 = xScaleA(d.sourcePosition);
        const x2 = xScaleB(d.targetPosition);
        const path = d3.path();
        path.moveTo(x1, 10);
        path.bezierCurveTo(x1, height / 2, x2, height / 2, x2, height - 10);
        return path.toString();
      })
      .attr("fill", "none")
      .attr("stroke", d => {
        if (selectedMatch === d) return "#c9302c";
        return d.similarity > 90 ? "rgba(39, 174, 96, 0.4)" : (d.similarity > 70 ? "rgba(52, 152, 219, 0.3)" : "rgba(149, 165, 166, 0.2)");
      })
      .attr("stroke-width", d => selectedMatch === d ? 3 : Math.max(1, (d.similarity - 40) / 15))
      .attr("opacity", d => selectedMatch && selectedMatch !== d ? 0.2 : 1)
      .attr("cursor", "pointer")
      .on("click", (event, d) => {
        event.stopPropagation();
        onSelectMatch(d);
      })
      .append("title")
      .text(d => `Click to view transposition:\nSim: ${d.similarity.toFixed(1)}%`);

  }, [matches, sourceLength, targetLength, selectedMatch]);

  return (
    <div className="w-full bg-white border border-gray-200 rounded-sm shadow-sm p-2">
      <div ref={containerRef} className="w-full h-[250px]" />
      <div className="text-[10px] text-gray-500 text-center mt-1">Click ribbons to view specific reuse pair</div>
    </div>
  );
};

export default AlignmentFlow;

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface DispersionPlotProps {
  matches: Match[];
  sourceLength: number;
  targetLength: number;
  onSelectMatch: (match: Match) => void;
  selectedMatch: Match | null;
}

const DispersionPlot: React.FC<DispersionPlotProps> = ({ matches, sourceLength, targetLength, onSelectMatch, selectedMatch }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current) return;
    d3.select(containerRef.current).selectAll("*").remove();

    const width = containerRef.current.clientWidth;
    const height = 100;
    const margin = { left: 10, right: 10 };

    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", width)
      .attr("height", height);

    const barHeight = 25;
    const row1Y = 20;
    const row2Y = 60;

    // Backgrounds
    svg.append("rect").attr("x", 0).attr("y", row1Y).attr("width", width).attr("height", barHeight).attr("fill", "#f8f9fa").attr("stroke", "#bdc3c7");
    svg.append("rect").attr("x", 0).attr("y", row2Y).attr("width", width).attr("height", barHeight).attr("fill", "#f8f9fa").attr("stroke", "#bdc3c7");

    svg.append("text").attr("x", 0).attr("y", row1Y - 5).text("Witness α Dispersion").attr("font-size", "10px").attr("fill", "#2c3e50");
    svg.append("text").attr("x", 0).attr("y", row2Y - 5).text("Witness β Dispersion").attr("font-size", "10px").attr("fill", "#2c3e50");

    // Render matches
    // Note: Rendering two rects per match (one for A, one for B)

    const g = svg.append("g");

    matches.forEach(match => {
        const x1 = (match.sourcePosition / sourceLength) * width;
        const w1 = Math.max(2, (match.sourcePhrase.length / sourceLength) * width);

        const x2 = (match.targetPosition / targetLength) * width;
        const w2 = Math.max(2, (match.targetPhrase.length / targetLength) * width);

        const isSelected = selectedMatch === match;
        const color = isSelected ? "#c9302c" : (match.similarity >= 80 ? "#2980b9" : "#95a5a6");
        const opacity = isSelected ? 1 : (selectedMatch ? 0.3 : 0.6);

        // Bar A
        g.append("rect")
         .attr("x", x1)
         .attr("y", row1Y)
         .attr("width", w1)
         .attr("height", barHeight)
         .attr("fill", color)
         .attr("opacity", opacity)
         .attr("cursor", "pointer")
         .on("click", (e) => { e.stopPropagation(); onSelectMatch(match); })
         .append("title").text(`α pos: ${match.sourcePosition} (Click to view)`);

        // Bar B
        g.append("rect")
         .attr("x", x2)
         .attr("y", row2Y)
         .attr("width", w2)
         .attr("height", barHeight)
         .attr("fill", color)
         .attr("opacity", opacity)
         .attr("cursor", "pointer")
         .on("click", (e) => { e.stopPropagation(); onSelectMatch(match); })
         .append("title").text(`β pos: ${match.targetPosition} (Click to view)`);
    });

  }, [matches, sourceLength, targetLength, selectedMatch]);

  return <div ref={containerRef} className="w-full bg-white border border-gray-200 rounded-sm shadow-sm p-4" />;
};

