import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface NetworkGraphProps {
  matches: Match[];
  onSelectMatch: (match: Match) => void;
  selectedMatch: Match | null;
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ matches, onSelectMatch, selectedMatch }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isEmpty, setIsEmpty] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;

    // Clear previous SVG
    d3.select(containerRef.current).selectAll("*").remove();

    const relevantMatches = matches
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 100);

    if (relevantMatches.length === 0) {
      setIsEmpty(true);
      return;
    }
    setIsEmpty(false);

    const width = containerRef.current.clientWidth || 800;
    const height = 400;

    // Build Nodes and Links
    const nodeMap = new Map();
    relevantMatches.forEach(m => {
      // Create unique IDs based on phrase + roughly position to distinguish same phrase in different locations if needed
      // For network graph simplicity, we group identical phrases.
      if (!nodeMap.has(m.sourcePhrase)) nodeMap.set(m.sourcePhrase, { id: m.sourcePhrase, group: 'alpha', r: 5 });
      if (!nodeMap.has(m.targetPhrase)) nodeMap.set(m.targetPhrase, { id: m.targetPhrase, group: 'beta', r: 5 });
    });

    const nodes = Array.from(nodeMap.values()) as any[];
    const links = relevantMatches.map(m => ({
      source: m.sourcePhrase,
      target: m.targetPhrase,
      value: m.similarity,
      matchData: m
    }));

    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", "100%")
      .attr("height", height)
      .attr("viewBox", [0, 0, width, height]);

    const g = svg.append("g");

    // Zoom behavior
    const zoom = d3.zoom<SVGSVGElement, unknown>()
        .scaleExtent([0.1, 4])
        .on("zoom", (event) => g.attr("transform", event.transform));

    svg.call(zoom);

    // Simulation
    const simulation = d3.forceSimulation(nodes)
      .force("link", d3.forceLink(links).id((d: any) => d.id).distance(150))
      .force("charge", d3.forceManyBody().strength(-300))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collide", d3.forceCollide(20));

    // Draw Links
    const link = g.append("g")
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke", (d: any) => {
         if (selectedMatch && d.matchData === selectedMatch) return "#c9302c";
         return "#95a5a6";
      })
      .attr("stroke-opacity", (d: any) => selectedMatch && d.matchData === selectedMatch ? 1 : 0.3)
      .attr("stroke-width", (d: any) => {
         const base = Math.max(2, (d.value - 40) / 10);
         return selectedMatch && d.matchData === selectedMatch ? base + 3 : base;
      })
      .attr("cursor", "pointer")
      .on("click", (event, d: any) => {
        event.stopPropagation();
        onSelectMatch(d.matchData);
      });

    link.append("title").text((d: any) => `Similarity: ${d.value.toFixed(1)}%`);

    // Draw Nodes
    const node = g.append("g")
      .attr("stroke", "#fff")
      .attr("stroke-width", 1.5)
      .selectAll("circle")
      .data(nodes)
      .join("circle")
      .attr("r", (d: any) => {
          // Highlight nodes involved in selected match
          if (selectedMatch && (d.id === selectedMatch.sourcePhrase || d.id === selectedMatch.targetPhrase)) {
              return d.r + 5;
          }
          return d.r + 3;
      })
      .attr("fill", (d: any) => {
          if (selectedMatch && (d.id === selectedMatch.sourcePhrase || d.id === selectedMatch.targetPhrase)) {
              return "#c9302c";
          }
          return d.group === 'alpha' ? "#34495e" : "#8b7355";
      })
      .attr("cursor", "grab")
      .call(d3.drag<any, any>()
        .on("start", (event, d) => {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          d.fx = d.x;
          d.fy = d.y;
        })
        .on("drag", (event, d) => {
          d.fx = event.x;
          d.fy = event.y;
        })
        .on("end", (event, d) => {
          if (!event.active) simulation.alphaTarget(0);
          d.fx = null;
          d.fy = null;
        }));

    node.append("title").text((d: any) => d.id);

    // Labels
    const label = g.append("g")
      .selectAll("text")
      .data(nodes)
      .enter()
      .append("text")
      .text((d: any) => d.id.length > 15 ? d.id.substring(0, 15) + '...' : d.id)
      .attr("font-size", 10)
      .attr("dx", 12)
      .attr("dy", 4)
      .attr("fill", "#2c3e50")
      .style("pointer-events", "none")
      .style("opacity", (d: any) => {
          // Hide labels if not selected to reduce clutter, unless nothing is selected
          if (selectedMatch) {
              return (d.id === selectedMatch.sourcePhrase || d.id === selectedMatch.targetPhrase) ? 1 : 0.2;
          }
          return 1;
      });

    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      node.attr("cx", (d: any) => d.x).attr("cy", (d: any) => d.y);
      label.attr("x", (d: any) => d.x).attr("y", (d: any) => d.y);
    });

    // --- Auto-Centering Logic ---
    if (selectedMatch) {
        // Wait for simulation to settle slightly or use current positions if available
        // Since we re-render on select, nodes are re-initialized. 
        // We can manually move the view to the center of the graph or the selected nodes.

        // Find the nodes for the selected match
        const sourceNode = nodes.find(n => n.id === selectedMatch.sourcePhrase);
        const targetNode = nodes.find(n => n.id === selectedMatch.targetPhrase);

        if (sourceNode && targetNode) {
            // Need to wait for a tick so x/y are populated
            const timer = setTimeout(() => {
                const midX = (sourceNode.x + targetNode.x) / 2;
                const midY = (sourceNode.y + targetNode.y) / 2;

                // Transition zoom
                svg.transition()
                   .duration(750)
                   .call(
                       zoom.transform,
                       d3.zoomIdentity
                         .translate(width / 2, height / 2)
                         .scale(1.5)
                         .translate(-midX, -midY)
                   );
            }, 300); // Short delay to allow force simulation to arrange nodes initially
            return () => clearTimeout(timer);
        }
    }

    return () => { simulation.stop(); };
  }, [matches, selectedMatch]); 

  return (
    <div className="relative w-full bg-white border border-gray-200 rounded-sm shadow-sm overflow-hidden h-[400px] group">
      <div ref={containerRef} className="w-full h-full" />

      {/* Explanation Tooltip / Legend */}
      <div className="absolute top-2 left-2 bg-white/90 p-2 rounded border border-gray-200 text-[10px] text-gray-600 shadow-sm pointer-events-none opacity-50 group-hover:opacity-100 transition-opacity">
        <strong>Network Graph:</strong><br/>
        Nodes = Text Phrases<br/>
        Edges = Similarity<br/>
        <span className="text-academic-blue">●</span> Witness α
        <span className="text-academic-gold ml-2">●</span> Witness β
      </div>

      {isEmpty && <div className="absolute inset-0 flex items-center justify-center text-gray-400">No network data.</div>}
      <div className="absolute bottom-2 right-2 bg-white/90 px-2 py-1 text-[10px] text-gray-500 rounded">
        {selectedMatch ? "Centered on selection" : "Scroll to Zoom • Drag Nodes"}
      </div>
    </div>
  );
};

export default NetworkGraph;

