const App: React.FC = () => {
  const [sourceText, setSourceText] = useState(EXAMPLES.coptic.a);
  const [targetText, setTargetText] = useState(EXAMPLES.coptic.b);
  const [config, setConfig] = useState<AnalysisConfig>({
    windowSize: 3,
    threshold: 50,
    algorithm: 'coptic-aware',
    scriptMode: 'auto'
  });
  const [isProcessing, setIsProcessing] = useState(false);

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [selectedMatch, setSelectedMatch] = useState<Match | null>(null);

  const performAnalysis = useCallback(() => {
    if (!sourceText || !targetText) return;
    setIsProcessing(true);

    // Minimal timeout to allow UI to show processing state
    setTimeout(() => {
      const res = runAnalysis(sourceText, targetText, config);
      setResult(res);
      setSelectedMatch(null); // Reset selection on new analysis
      setIsProcessing(false);
    }, 10);
  }, [sourceText, targetText, config]);

  const handleClear = useCallback(() => {
    setSourceText('');
    setTargetText('');
    setResult(null);
    setSelectedMatch(null);
  }, []);

  const downloadJson = () => {
    if (!result) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(result, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "icoma_collation_analysis.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <div className="min-h-screen font-serif bg-academic-cream text-academic-blue pb-20">
      <MatchDetailModal 
        match={selectedMatch} 
        onClose={() => setSelectedMatch(null)} 
      />

      {/* Header */}
      <header className="bg-gradient-to-r from-academic-lightBlue to-academic-blue text-white border-b-4 border-academic-red px-6 py-6 shadow-md">
