                  value={sourceText}
                  onChange={(e) => setSourceText(e.target.value)}
                  placeholder="Insert primary text..."
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold uppercase text-gray-500 flex justify-between">
                  Witness β (Comparandum)
                  <span className="text-gray-300 text-[10px]">{targetText.length} chars</span>
                </label>
