                  className="w-full p-2 border border-gray-300 rounded-sm bg-academic-paper font-mono text-sm"
                >
                  <option value="coptic-aware">Coptic-Aware Edit Distance</option>
                  <option value="smith-waterman">Smith-Waterman (Local Alignment)</option>
                  <option value="passim">Passim-style (Char N-Grams)</option>
                  <option value="tracer">TRACER-style (Word N-Grams)</option>
                  <option value="levenshtein">Standard Levenshtein</option>
                  <option value="jaccard">Jaccard Index</option>
                </select>
