                    <NetworkGraph 
                      matches={result.matches} 
                      onSelectMatch={setSelectedMatch}
                      selectedMatch={selectedMatch}
                    />
                  </section>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
                    <section className="md:col-span-8">
                        <h3 className="font-bold text-gray-600 mb-2 text-sm uppercase flex items-center gap-2">
                          <span className="bg-gray-200 text-gray-600 text-[10px] px-1.5 py-0.5 rounded">Fig 4</span>
