const App: React.FC = () => {
  const [sourceText, setSourceText] = useState(EXAMPLES.coptic.a);
  const [targetText, setTargetText] = useState(EXAMPLES.coptic.b);
  const [config, setConfig] = useState<AnalysisConfig>({
    windowSize: 3,
    threshold: 50,
    algorithm: 'levenshtein', // Default to most general
    scriptMode: 'auto'
  });
  const [isProcessing, setIsProcessing] = useState(false);

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [selectedMatch, setSelectedMatch] = useState<Match | null>(null);

  const performAnalysis = useCallback(() => {
    if (!sourceText || !targetText) return;
    setIsProcessing(true);

    // Minimal timeout to allow UI to show processing state
    setTimeout(() => {
      const res = runAnalysis(sourceText, targetText, config);
      setResult(res);
      setSelectedMatch(null); // Reset selection on new analysis
      setIsProcessing(false);
    }, 10);
  }, [sourceText, targetText, config]);

  const handleClear = useCallback(() => {
    setSourceText('');
    setTargetText('');
    setResult(null);
    setSelectedMatch(null);
  }, []);

  const downloadJson = () => {
    if (!result) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(result, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "icoma_collation_analysis.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <div className="min-h-screen font-serif bg-academic-cream text-academic-blue pb-20 flex flex-col">
      {/* 
        Modal removed as per request. 
        Interaction now relies on the ParallelViewer's built-in footer and auto-scroll. 
      */}

      {/* Header */}
      <header className="bg-gradient-to-r from-academic-lightBlue to-academic-blue text-white border-b-4 border-academic-red px-6 py-4 shadow-md shrink-0">
        <div className="w-full">
          <div className="flex justify-between items-center">
            <div>
              <div className="text-xs uppercase tracking-widest text-gray-300 mb-1">
                So Miyagawa Computational Linguistics Lab
              </div>
              <h1 className="text-2xl font-bold font-serif">
                ICoMa <span className="text-academic-gold font-light ml-2 text-lg">Intertextuality Collation Machine</span>
              </h1>
            </div>
            <div className="text-right hidden md:block">
              <p className="text-xs text-gray-300 font-mono">Experimental Build</p>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content - Full Width Dashboard */}
      <main className="w-full px-4 py-6 flex-1 flex flex-col">

        {/* Input & Parameters Section (Collapsible-like look) */}
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-6 mb-8">

          {/* Inputs */}
          <div className="xl:col-span-9 bg-white p-4 border border-gray-200 shadow-sm rounded-sm">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 border-b border-gray-100 pb-2 gap-4">
              <h2 className="text-sm font-bold uppercase text-gray-500">
                <span className="text-academic-gold mr-2">1.</span>Corpus Input
              </h2>
              <div className="flex flex-wrap gap-2">
                {Object.entries(EXAMPLES).map(([key, val]) => (
                  <button
                    key={key}
                    onClick={() => { setSourceText(val.a); setTargetText(val.b); }}
                    className="text-[10px] px-2 py-1 bg-gray-50 border border-gray-200 hover:bg-academic-blue hover:text-white transition-colors uppercase font-mono rounded-sm whitespace-nowrap"
                  >
                    {val.label}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-bold uppercase text-gray-400 flex justify-between">
                  Witness α
                  <span>{sourceText.length} chars</span>
                </label>
                <textarea
                  className="w-full h-24 p-2 text-sm font-coptic border border-gray-300 rounded-sm focus:ring-1 focus:ring-academic-gold bg-gray-50 resize-none"
                  value={sourceText}
                  onChange={(e) => setSourceText(e.target.value)}
                  placeholder="Insert primary text..."
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold uppercase text-gray-400 flex justify-between">
                  Witness β
                  <span>{targetText.length} chars</span>
                </label>
                <textarea
                  className="w-full h-24 p-2 text-sm font-coptic border border-gray-300 rounded-sm focus:ring-1 focus:ring-academic-gold bg-gray-50 resize-none"
                  value={targetText}
                  onChange={(e) => setTargetText(e.target.value)}
                  placeholder="Insert comparison text..."
                />
              </div>
            </div>
          </div>

          {/* Parameters & Actions */}
          <div className="xl:col-span-3 bg-white p-4 border border-gray-200 shadow-sm rounded-sm flex flex-col justify-between">
            <div>
              <h2 className="text-sm font-bold uppercase text-gray-500 border-b border-gray-100 pb-2 mb-4">
                <span className="text-academic-gold mr-2">2.</span>Config
              </h2>
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-2">
                  <div>
                    <label className="block text-[10px] font-bold text-gray-400 mb-1">Algorithm</label>
                    <select
                      value={config.algorithm}
                      onChange={(e) => setConfig({ ...config, algorithm: e.target.value as any })}
                      className="w-full p-1 border border-gray-300 rounded-sm text-xs"
                    >
                      {/* Sorted from General/Common to Specific/Experimental */}
                      <option value="levenshtein">Levenshtein (Edit Dist)</option>
                      <option value="jaccard">Jaccard (Set Sim)</option>
                      <option value="smith-waterman">Smith-Waterman (Local)</option>
                      <option value="passim">Passim (N-Gram)</option>
                      <option value="tracer">TRACER (Word)</option>
                      <option value="coptic-aware">Coptic-Aware (Specific)</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-gray-400 mb-1">Threshold: {config.threshold}%</label>
                    <input
                      type="range"
                      min="20"
                      max="100"
                      value={config.threshold}
                      onChange={(e) => setConfig({ ...config, threshold: Number(e.target.value) })}
                      className="w-full accent-academic-gold h-4"
                    />
                  </div>
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-2 mt-4">
               <button
                  onClick={performAnalysis}
                  disabled={!sourceText || !targetText || isProcessing}
                  className={`w-full py-2 bg-academic-gold text-white font-bold uppercase tracking-wider text-xs rounded-sm shadow-sm transition-all
                    ${(!sourceText || !targetText || isProcessing) ? 'opacity-50 cursor-not-allowed' : 'hover:bg-academic-blue hover:shadow-md'}`}
                >
                  {isProcessing ? 'Processing...' : 'Run Collation'}
                </button>
                <button
                  onClick={handleClear}
                  className="w-full py-1 text-gray-400 text-[10px] uppercase hover:text-academic-red transition-colors"
                >
                  Reset Form
                </button>
            </div>
          </div>
        </div>

        {/* Dashboard Grid Results */}
        {result && (
          <div className="animate-fade-in flex-1 flex flex-col gap-6">

             {/* Dashboard Header */}
             <div className="flex justify-between items-center bg-gray-100 p-2 rounded-sm border border-gray-200">
                <div className="flex gap-4 text-xs font-mono text-gray-600">
                  <span>Alignments: <strong className="text-academic-blue">{result.stats.totalAlignments}</strong></span>
                  <span>Mean Sim: <strong className="text-academic-blue">{result.stats.meanSimilarity.toFixed(1)}%</strong></span>
                  <span>Coverage: <strong className="text-academic-blue">{result.stats.coverage.toFixed(1)}%</strong></span>
                </div>
                <button 
                    onClick={downloadJson}
                    className="text-[10px] uppercase font-bold text-academic-blue hover:text-academic-gold flex items-center gap-1"
                  >
                    Download JSON
                </button>
             </div>

             {/* Dashboard Columns */}
             <div className="grid grid-cols-1 xl:grid-cols-12 gap-6 h-full min-h-[600px]">

                {/* Left Panel: Text Viewer (Usually central to philology) */}
                <div className="xl:col-span-5 flex flex-col h-full min-h-[500px]">
                  <h3 className="font-bold text-gray-500 mb-2 text-xs uppercase flex items-center gap-2">
                    <span className="bg-academic-blue text-white text-[10px] px-1.5 py-0.5 rounded">Panel A</span>
                    Parallel Reader
                  </h3>
                  <div className="flex-1 h-full">
                    {/* The ParallelViewer handles scrolling to selection internally via props */}
                    <ParallelViewer 
                      tokensA={result.tokensA} 
                      tokensB={result.tokensB} 
                      alignments={result.alignments} 
                      selectedMatch={selectedMatch}
                    />
                  </div>
                </div>

                {/* Right Panel: Visualizations Grid */}
                <div className="xl:col-span-7 flex flex-col gap-6 h-full">

                   {/* Top Row: Network & Heatmap */}
                   <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-[350px]">
                      <div className="flex flex-col h-full">
                        <h3 className="font-bold text-gray-500 mb-2 text-xs uppercase flex items-center gap-2">
                          <span className="bg-academic-blue text-white text-[10px] px-1.5 py-0.5 rounded">Panel B</span>
                          Network
                        </h3>
                        <div className="flex-1 border border-gray-200 bg-white rounded-sm shadow-sm h-full">
                           <NetworkGraph 
                              matches={result.matches} 
                              onSelectMatch={setSelectedMatch}
                              selectedMatch={selectedMatch}
                            />
                        </div>
                      </div>
                      <div className="flex flex-col h-full">
                        <h3 className="font-bold text-gray-500 mb-2 text-xs uppercase flex items-center gap-2">
                          <span className="bg-academic-blue text-white text-[10px] px-1.5 py-0.5 rounded">Panel C</span>
                          Heatmap
                        </h3>
                         <div className="flex-1 border border-gray-200 bg-white rounded-sm shadow-sm h-full flex items-center justify-center">
                            <Heatmap 
                              matches={result.matches} 
                              sourceLength={result.tokensA.length} 
                              targetLength={result.tokensB.length} 
                              onSelectMatch={setSelectedMatch}
                              selectedMatch={selectedMatch}
                            />
                         </div>
                      </div>
                   </div>

                   {/* Bottom Row: Flow, Histogram, Dispersion */}
                   <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[250px]">
                      <div className="lg:col-span-2 flex flex-col">
                        <h3 className="font-bold text-gray-500 mb-2 text-xs uppercase flex items-center gap-2">
                          <span className="bg-academic-blue text-white text-[10px] px-1.5 py-0.5 rounded">Panel D</span>
                          Alignment Flow
                        </h3>
                        <div className="flex-1">
                          <AlignmentFlow 
                            matches={result.matches} 
                            sourceLength={result.tokensA.length} 
                            targetLength={result.tokensB.length} 
                            onSelectMatch={setSelectedMatch}
                            selectedMatch={selectedMatch}
                          />
                        </div>
                      </div>
                      <div className="flex flex-col">
                         <h3 className="font-bold text-gray-500 mb-2 text-xs uppercase flex items-center gap-2">
                          <span className="bg-academic-blue text-white text-[10px] px-1.5 py-0.5 rounded">Panel E</span>
                          Distribution
                        </h3>
                        <div className="flex-1">
                          <SimilarityHistogram matches={result.matches} />
                        </div>
                      </div>
                   </div>

                   {/* Full width dispersion at bottom of right col */}
                   <div className="h-[100px] flex flex-col">
                      <h3 className="font-bold text-gray-500 mb-1 text-xs uppercase">Dispersion</h3>
                      <DispersionPlot 
                        matches={result.matches} 
                        sourceLength={result.tokensA.length} 
                        targetLength={result.tokensB.length} 
                        onSelectMatch={setSelectedMatch}
                        selectedMatch={selectedMatch}
                      />
                   </div>

                </div>
             </div>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

