import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface NetworkGraphProps {
  matches: Match[];
  onSelectMatch: (match: Match) => void;
  selectedMatch: Match | null;
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ matches, onSelectMatch, selectedMatch }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement | null>(null);

  // Refs to store D3 selections and data so we don't re-simulate on selection change
  const simulationRef = useRef<d3.Simulation<any, undefined> | null>(null);
  const nodesDataRef = useRef<any[]>([]);
  const linksDataRef = useRef<any[]>([]);

  const linkSelectionRef = useRef<d3.Selection<SVGLineElement, any, SVGGElement, unknown> | null>(null);
  const nodeSelectionRef = useRef<d3.Selection<SVGCircleElement, any, SVGGElement, unknown> | null>(null);
  const labelSelectionRef = useRef<d3.Selection<SVGTextElement, any, SVGGElement, unknown> | null>(null);
  const zoomBehaviorRef = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);

  const [isEmpty, setIsEmpty] = useState(false);

  // 1. Initialization Effect: Runs ONLY when `matches` data changes (e.g. new analysis)
  useEffect(() => {
    if (!containerRef.current) return;

    // Sort and limit to avoid overcrowding
    const relevantMatches = matches
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 100);

    if (relevantMatches.length === 0) {
      setIsEmpty(true);
      return;
    }
    setIsEmpty(false);

    // Clear previous graph
    d3.select(containerRef.current).selectAll("*").remove();

    const width = containerRef.current.clientWidth || 800;
    const height = 400;

    // Setup SVG
    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", "100%")
      .attr("height", height)
      .attr("viewBox", [0, 0, width, height]);

    svgRef.current = svg.node();

    const g = svg.append("g");

    // Setup Zoom
    const zoom = d3.zoom<SVGSVGElement, unknown>()
        .scaleExtent([0.1, 4])
        .on("zoom", (event) => g.attr("transform", event.transform));

    svg.call(zoom);
    zoomBehaviorRef.current = zoom;

    // Prepare Data
    // Note: We use a map to merge identical phrases into single nodes
    const nodeMap = new Map();
    relevantMatches.forEach(m => {
      if (!nodeMap.has(m.sourcePhrase)) nodeMap.set(m.sourcePhrase, { id: m.sourcePhrase, group: 'alpha', r: 5 });
      if (!nodeMap.has(m.targetPhrase)) nodeMap.set(m.targetPhrase, { id: m.targetPhrase, group: 'beta', r: 5 });
    });

    const nodes = Array.from(nodeMap.values());
    // Links need to reference IDs if we used .id() in forceLink, or objects if mapped.
    // D3 mutates these objects.
    const links = relevantMatches.map(m => ({
      source: m.sourcePhrase,
      target: m.targetPhrase,
      value: m.similarity,
      matchData: m
    }));

    nodesDataRef.current = nodes;
    linksDataRef.current = links;

    // Force Simulation
    const simulation = d3.forceSimulation(nodes)
      .force("link", d3.forceLink(links).id((d: any) => d.id).distance(120))
      .force("charge", d3.forceManyBody().strength(-200))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collide", d3.forceCollide(20))
      .alphaDecay(0.05); // Decay faster to settle quicker

    simulationRef.current = simulation;

    // Draw Links
    const link = g.append("g")
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke", "#95a5a6")
      .attr("stroke-opacity", 0.3)
      .attr("stroke-width", (d: any) => Math.max(1, (d.value - 40) / 10))
      .attr("cursor", "pointer")
      .on("click", (event, d: any) => {
        event.stopPropagation();
        onSelectMatch(d.matchData);
      });

    link.append("title").text((d: any) => `Similarity: ${d.value.toFixed(1)}%`);
    linkSelectionRef.current = link;

    // Draw Nodes
    const node = g.append("g")
      .attr("stroke", "#fff")
      .attr("stroke-width", 1.5)
      .selectAll("circle")
      .data(nodes)
      .join("circle")
      .attr("r", (d: any) => d.r + 3)
      .attr("fill", (d: any) => d.group === 'alpha' ? "#34495e" : "#8b7355")
      .attr("cursor", "grab")
      .call(d3.drag<any, any>()
        .on("start", (event, d) => {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          d.fx = d.x;
          d.fy = d.y;
        })
        .on("drag", (event, d) => {
          d.fx = event.x;
          d.fy = event.y;
        })
        .on("end", (event, d) => {
          if (!event.active) simulation.alphaTarget(0);
          d.fx = null;
          d.fy = null;
        }));

    node.append("title").text((d: any) => d.id);
    nodeSelectionRef.current = node;

    // Draw Labels
    const label = g.append("g")
      .selectAll("text")
      .data(nodes)
      .enter()
      .append("text")
      .text((d: any) => d.id.length > 15 ? d.id.substring(0, 15) + '...' : d.id)
      .attr("font-size", 10)
      .attr("dx", 12)
      .attr("dy", 4)
      .attr("fill", "#2c3e50")
      .style("pointer-events", "none");

    labelSelectionRef.current = label;

    // Simulation Tick
    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      node.attr("cx", (d: any) => d.x).attr("cy", (d: any) => d.y);
      label.attr("x", (d: any) => d.x).attr("y", (d: any) => d.y);
    });

    return () => {
      simulation.stop();
    };
  }, [matches]); // IMPORTANT: Do NOT include selectedMatch here

  // 2. Selection Effect: Updates styles and zoom without restarting simulation
  useEffect(() => {
    if (!linkSelectionRef.current || !nodeSelectionRef.current || !labelSelectionRef.current) return;

    // --- Update Styles ---

    // Links
    linkSelectionRef.current
      .transition().duration(300)
      .attr("stroke", (d: any) => (selectedMatch && d.matchData === selectedMatch) ? "#c9302c" : "#95a5a6")
      .attr("stroke-opacity", (d: any) => {
        if (!selectedMatch) return 0.3;
        return d.matchData === selectedMatch ? 1 : 0.1;
      })
      .attr("stroke-width", (d: any) => {
        const base = Math.max(1, (d.value - 40) / 10);
        return (selectedMatch && d.matchData === selectedMatch) ? base + 2 : base;
      });

    // Nodes
    nodeSelectionRef.current
      .transition().duration(300)
      .attr("r", (d: any) => {
        const isTarget = selectedMatch && (d.id === selectedMatch.sourcePhrase || d.id === selectedMatch.targetPhrase);
        return isTarget ? 10 : 8;
      })
      .attr("fill", (d: any) => {
        const isTarget = selectedMatch && (d.id === selectedMatch.sourcePhrase || d.id === selectedMatch.targetPhrase);
        return isTarget ? "#c9302c" : (d.group === 'alpha' ? "#34495e" : "#8b7355");
      })
      .style("opacity", (d: any) => {
        if (!selectedMatch) return 1;
        const isTarget = selectedMatch && (d.id === selectedMatch.sourcePhrase || d.id === selectedMatch.targetPhrase);
        return isTarget ? 1 : 0.3;
      });

    // Labels
    labelSelectionRef.current
      .transition().duration(300)
      .style("opacity", (d: any) => {
        if (!selectedMatch) return 1;
        const isTarget = selectedMatch && (d.id === selectedMatch.sourcePhrase || d.id === selectedMatch.targetPhrase);
        return isTarget ? 1 : 0;
      });

    // --- Smart Zoom to Selection ---
    if (selectedMatch && svgRef.current && zoomBehaviorRef.current && nodesDataRef.current.length > 0) {
      // Find the nodes corresponding to the selected match
      // Note: Simulation has run, so nodes have x, y properties
      const sourceNode = nodesDataRef.current.find(n => n.id === selectedMatch.sourcePhrase);
      const targetNode = nodesDataRef.current.find(n => n.id === selectedMatch.targetPhrase);

      if (sourceNode && targetNode && typeof sourceNode.x === 'number' && typeof targetNode.x === 'number') {
        const width = containerRef.current?.clientWidth || 800;
        const height = 400;

        const midX = (sourceNode.x + targetNode.x) / 2;
        const midY = (sourceNode.y + targetNode.y) / 2;

        // Calculate distance to determine zoom level
        const dx = Math.abs(sourceNode.x - targetNode.x);
        const dy = Math.abs(sourceNode.y - targetNode.y);
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Scale logic: closer nodes = higher zoom, but capped
        // 1.5 is a comfortable base zoom
        const scale = Math.min(2.5, Math.max(0.8, (height * 0.6) / (distance + 1)));

        d3.select(svgRef.current)
          .transition()
          .duration(800)
          .ease(d3.easeCubicOut)
          .call(
            zoomBehaviorRef.current.transform,
            d3.zoomIdentity
              .translate(width / 2, height / 2)
              .scale(scale)
              .translate(-midX, -midY)
          );
      }
    }

  }, [selectedMatch]);

  return (
    <div className="relative w-full bg-white border border-gray-200 rounded-sm shadow-sm overflow-hidden h-[400px] group">
      <div ref={containerRef} className="w-full h-full" />

      {/* Legend / Help */}
      <div className="absolute top-2 left-2 bg-white/95 p-2 rounded border border-gray-200 text-[10px] text-gray-600 shadow-sm pointer-events-none opacity-50 group-hover:opacity-100 transition-opacity z-10">
        <strong>Network Graph:</strong><br/>
        <span className="text-academic-blue font-bold">●</span> Witness α (Source)<br/>
        <span className="text-academic-gold font-bold">●</span> Witness β (Target)<br/>
        Line thickness = Similarity
      </div>

      {isEmpty && (
        <div className="absolute inset-0 flex items-center justify-center text-gray-400 bg-gray-50/50">
          No matches high enough to display network.
        </div>
      )}

      <div className="absolute bottom-2 right-2 bg-white/90 px-2 py-1 text-[10px] text-gray-500 rounded border border-gray-100 shadow-sm z-10">
        {selectedMatch ? "View centered on selection" : "Scroll to Zoom • Drag Nodes"}
      </div>
    </div>
  );
};

export default NetworkGraph;

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface NetworkGraphProps {
  matches: Match[];
  onSelectMatch: (match: Match) => void;
  selectedMatch: Match | null;
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ matches, onSelectMatch, selectedMatch }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement | null>(null);

  // Refs to store D3 selections and data so we don't re-simulate on selection change
  const simulationRef = useRef<d3.Simulation<any, undefined> | null>(null);
  const nodesDataRef = useRef<any[]>([]);
  const linksDataRef = useRef<any[]>([]);

  const linkSelectionRef = useRef<d3.Selection<SVGLineElement, any, SVGGElement, unknown> | null>(null);
  const nodeSelectionRef = useRef<d3.Selection<SVGCircleElement, any, SVGGElement, unknown> | null>(null);
  const labelSelectionRef = useRef<d3.Selection<SVGTextElement, any, SVGGElement, unknown> | null>(null);
  const zoomBehaviorRef = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);

  const [isEmpty, setIsEmpty] = useState(false);

  // 1. Initialization Effect: Runs ONLY when `matches` data changes (e.g. new analysis)
  useEffect(() => {
    if (!containerRef.current) return;

    // Sort and limit to avoid overcrowding
    const relevantMatches = matches
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 100);

    if (relevantMatches.length === 0) {
      setIsEmpty(true);
      return;
    }
    setIsEmpty(false);

    // Clear previous graph
    d3.select(containerRef.current).selectAll("*").remove();

    const width = containerRef.current.clientWidth || 800;
    const height = 400;

    // Setup SVG
    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", "100%")
      .attr("height", height)
      .attr("viewBox", [0, 0, width, height]);

    svgRef.current = svg.node();

    const g = svg.append("g");

    // Setup Zoom
    const zoom = d3.zoom<SVGSVGElement, unknown>()
        .scaleExtent([0.1, 4])
        .on("zoom", (event) => g.attr("transform", event.transform));

    svg.call(zoom);
    zoomBehaviorRef.current = zoom;

    // Prepare Data
    // Separe nodes by witness to avoid merging distinct entities even if text is identical
    const nodeMap = new Map();

    relevantMatches.forEach(m => {
      // Create distinct IDs for Alpha and Beta witnesses
      const alphaId = `A::${m.sourcePhrase}`;
      const betaId = `B::${m.targetPhrase}`;

      if (!nodeMap.has(alphaId)) {
        nodeMap.set(alphaId, { 
          id: alphaId, 
          label: m.sourcePhrase, 
          group: 'alpha', 
          r: 5 
        });
      }
      if (!nodeMap.has(betaId)) {
        nodeMap.set(betaId, { 
          id: betaId, 
          label: m.targetPhrase, 
          group: 'beta', 
          r: 5 
        });
      }
    });

    const nodes = Array.from(nodeMap.values());
    const links = relevantMatches.map(m => ({
      source: `A::${m.sourcePhrase}`,
      target: `B::${m.targetPhrase}`,
      value: m.similarity,
      matchData: m
    }));

    nodesDataRef.current = nodes;
    linksDataRef.current = links;

    // Force Simulation
    const simulation = d3.forceSimulation(nodes)
      .force("link", d3.forceLink(links).id((d: any) => d.id).distance((d: any) => {
         // Pull exact matches very close together
         if (d.value >= 99) return 40;
         if (d.value >= 80) return 80;
         return 150;
      }))
      .force("charge", d3.forceManyBody().strength(-200))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collide", d3.forceCollide(20))
      .alphaDecay(0.05); // Decay faster to settle quicker

    simulationRef.current = simulation;

    // Draw Links
    const link = g.append("g")
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke", (d: any) => d.value >= 99 ? "#27ae60" : "#95a5a6") // Green for exact
      .attr("stroke-opacity", (d: any) => d.value >= 99 ? 0.6 : 0.3)
      .attr("stroke-width", (d: any) => Math.max(1, (d.value - 40) / 10))
      .attr("stroke-dasharray", (d: any) => d.value >= 99 ? "none" : (d.value < 80 ? "4,2" : "none")) // Dashed for low sim
      .attr("cursor", "pointer")
      .on("click", (event, d: any) => {
        event.stopPropagation();
        onSelectMatch(d.matchData);
      });

    link.append("title").text((d: any) => `Similarity: ${d.value.toFixed(1)}%`);
    linkSelectionRef.current = link;

    // Draw Nodes
    const node = g.append("g")
      .attr("stroke", "#fff")
      .attr("stroke-width", 1.5)
      .selectAll("circle")
      .data(nodes)
      .join("circle")
      .attr("r", (d: any) => d.r + 3)
      .attr("fill", (d: any) => d.group === 'alpha' ? "#34495e" : "#8b7355")
      .attr("cursor", "grab")
      .call(d3.drag<any, any>()
        .on("start", (event, d) => {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          d.fx = d.x;
          d.fy = d.y;
        })
        .on("drag", (event, d) => {
          d.fx = event.x;
          d.fy = event.y;
        })
        .on("end", (event, d) => {
          if (!event.active) simulation.alphaTarget(0);
          d.fx = null;
          d.fy = null;
        }));

    node.append("title").text((d: any) => d.label);
    nodeSelectionRef.current = node;

    // Draw Labels
    const label = g.append("g")
      .selectAll("text")
      .data(nodes)
      .enter()
      .append("text")
      .text((d: any) => d.label.length > 15 ? d.label.substring(0, 15) + '...' : d.label)
      .attr("font-size", 10)
      .attr("dx", 12)
      .attr("dy", 4)
      .attr("fill", "#2c3e50")
      .style("pointer-events", "none");

    labelSelectionRef.current = label;

    // Simulation Tick
    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      node.attr("cx", (d: any) => d.x).attr("cy", (d: any) => d.y);
      label.attr("x", (d: any) => d.x).attr("y", (d: any) => d.y);
    });

    return () => {
      simulation.stop();
    };
  }, [matches]); // IMPORTANT: Do NOT include selectedMatch here

  // 2. Selection Effect: Updates styles and zoom without restarting simulation
  useEffect(() => {
    if (!linkSelectionRef.current || !nodeSelectionRef.current || !labelSelectionRef.current) return;

    // --- Update Styles ---

    // Links
    linkSelectionRef.current
      .transition().duration(300)
      .attr("stroke", (d: any) => {
        if (selectedMatch && d.matchData === selectedMatch) return "#c9302c";
        return d.value >= 99 ? "#27ae60" : "#95a5a6";
      })
      .attr("stroke-opacity", (d: any) => {
        if (!selectedMatch) return d.value >= 99 ? 0.6 : 0.3;
        return d.matchData === selectedMatch ? 1 : 0.1;
      })
      .attr("stroke-width", (d: any) => {
        const base = Math.max(1, (d.value - 40) / 10);
        return (selectedMatch && d.matchData === selectedMatch) ? base + 2 : base;
      });

    // Nodes
    nodeSelectionRef.current
      .transition().duration(300)
      .attr("r", (d: any) => {
        if (!selectedMatch) return d.r + 3;
        // Check using IDs since label might not be unique
        const isTarget = d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`;
        return isTarget ? 10 : 8;
      })
      .attr("fill", (d: any) => {
        const isTarget = selectedMatch && (d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`);
        return isTarget ? "#c9302c" : (d.group === 'alpha' ? "#34495e" : "#8b7355");
      })
      .style("opacity", (d: any) => {
        if (!selectedMatch) return 1;
        const isTarget = selectedMatch && (d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`);
        return isTarget ? 1 : 0.3;
      });

    // Labels
    labelSelectionRef.current
      .transition().duration(300)
      .style("opacity", (d: any) => {
        if (!selectedMatch) return 1;
        const isTarget = selectedMatch && (d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`);
        return isTarget ? 1 : 0;
      });

    // --- Smart Zoom to Selection ---
    if (selectedMatch && svgRef.current && zoomBehaviorRef.current && nodesDataRef.current.length > 0) {
      // Find the nodes corresponding to the selected match
      // Note: Simulation has run, so nodes have x, y properties
      const sourceNode = nodesDataRef.current.find(n => n.id === `A::${selectedMatch.sourcePhrase}`);
      const targetNode = nodesDataRef.current.find(n => n.id === `B::${selectedMatch.targetPhrase}`);

      if (sourceNode && targetNode && typeof sourceNode.x === 'number' && typeof targetNode.x === 'number') {
        const width = containerRef.current?.clientWidth || 800;
        const height = 400;

        const midX = (sourceNode.x + targetNode.x) / 2;
        const midY = (sourceNode.y + targetNode.y) / 2;

        // Calculate distance to determine zoom level
        const dx = Math.abs(sourceNode.x - targetNode.x);
        const dy = Math.abs(sourceNode.y - targetNode.y);
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Scale logic: closer nodes = higher zoom, but capped
        const scale = Math.min(2.5, Math.max(0.8, (height * 0.6) / (distance + 1)));

        d3.select(svgRef.current)
          .transition()
          .duration(800)
          .ease(d3.easeCubicOut)
          .call(
            zoomBehaviorRef.current.transform,
            d3.zoomIdentity
              .translate(width / 2, height / 2)
              .scale(scale)
              .translate(-midX, -midY)
          );
      }
    }

  }, [selectedMatch]);

  return (
    <div className="relative w-full bg-white border border-gray-200 rounded-sm shadow-sm overflow-hidden h-[400px] group">
      <div ref={containerRef} className="w-full h-full" />

      {/* Legend / Help */}
      <div className="absolute top-2 left-2 bg-white/95 p-2 rounded border border-gray-200 text-[10px] text-gray-600 shadow-sm pointer-events-none opacity-50 group-hover:opacity-100 transition-opacity z-10">
        <strong>Network Graph:</strong><br/>
        <span className="text-academic-blue font-bold">●</span> Witness α (Source)<br/>
        <span className="text-academic-gold font-bold">●</span> Witness β (Target)<br/>
        <span className="text-green-600 font-bold">━</span> Exact Match (100%)<br/>
        <span className="text-gray-400 font-bold">┅</span> Fuzzy Match
      </div>

      {isEmpty && (
        <div className="absolute inset-0 flex items-center justify-center text-gray-400 bg-gray-50/50">
          No matches high enough to display network.
        </div>
      )}

      <div className="absolute bottom-2 right-2 bg-white/90 px-2 py-1 text-[10px] text-gray-500 rounded border border-gray-100 shadow-sm z-10">
        {selectedMatch ? "View centered on selection" : "Scroll to Zoom • Drag Nodes"}
      </div>
    </div>
  );
};

export default NetworkGraph;

import React, { useState, useEffect, useRef } from 'react';
import { Token, Alignment, Match } from '../types';

interface ParallelViewerProps {
  tokensA: Token[];
  tokensB: Token[];
  alignments: Alignment[];
  matches: Match[]; // Added to find match context on click
  onSelectMatch: (match: Match) => void; // Trigger global selection
  selectedMatch: Match | null;
}

const ParallelViewer: React.FC<ParallelViewerProps> = ({ 
  tokensA, 
  tokensB, 
  alignments, 
  matches, 
  onSelectMatch, 
  selectedMatch 
}) => {
  const [hoveredIdx, setHoveredIdx] = useState<{ side: 'A' | 'B', index: number } | null>(null);

  const containerARef = useRef<HTMLDivElement>(null);
  const containerBRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logic: Only scroll the internal containers, NOT the window
  useEffect(() => {
    if (selectedMatch) {
      // Helper to scroll a container to a specific token element
      const scrollContainerToToken = (container: HTMLDivElement | null, tokenIndex: number) => {
        if (!container) return;
        const tokenEl = container.querySelector(`[data-token-index="${tokenIndex}"]`) as HTMLElement;
        if (tokenEl) {
          // Calculate position relative to container
          const containerRect = container.getBoundingClientRect();
          const tokenRect = tokenEl.getBoundingClientRect();
          const offset = tokenRect.top - containerRect.top;

          // Scroll container to center the element
          container.scrollTo({
            top: container.scrollTop + offset - (container.clientHeight / 2) + (tokenEl.clientHeight / 2),
            behavior: 'smooth'
          });
        }
      };

      scrollContainerToToken(containerARef.current, selectedMatch.sourcePosition);
      scrollContainerToToken(containerBRef.current, selectedMatch.targetPosition);
    }
  }, [selectedMatch]);

  // Map for quick lookup of pairwise alignments (token-to-token)
  const alignmentMapA = new Map<number, Alignment[]>();
  const alignmentMapB = new Map<number, Alignment[]>();

  alignments.forEach(a => {
    if (!alignmentMapA.has(a.sourceIndex)) alignmentMapA.set(a.sourceIndex, []);
    alignmentMapA.get(a.sourceIndex)?.push(a);

    if (!alignmentMapB.has(a.targetIndex)) alignmentMapB.set(a.targetIndex, []);
    alignmentMapB.get(a.targetIndex)?.push(a);
  });

  // Handle click on a token to select the overarching Match
  const handleTokenClick = (index: number, side: 'A' | 'B') => {
    // Find all matches that cover this token index
    const candidates = matches.filter(m => {
      const start = side === 'A' ? m.sourcePosition : m.targetPosition;
      const len = m.length || 1; // Fallback length if undefined
      return index >= start && index < start + len;
    });

    if (candidates.length > 0) {
      // Pick the best match (highest similarity)
      const bestMatch = candidates.reduce((prev, curr) => prev.similarity > curr.similarity ? prev : curr);
      onSelectMatch(bestMatch);
    }
  };

  const getStyle = (tokenIdx: number, side: 'A' | 'B') => {
    const map = side === 'A' ? alignmentMapA : alignmentMapB;
    const currentAlignments = map.get(tokenIdx);

    // 1. Check if part of Selected Match (Global Selection)
    if (selectedMatch) {
       const len = selectedMatch.length || 3; // default window size assumption if length missing
       const start = side === 'A' ? selectedMatch.sourcePosition : selectedMatch.targetPosition;
       if (tokenIdx >= start && tokenIdx < start + len) {
         return "bg-academic-gold text-white px-0.5 rounded shadow-sm border-b-[3px] border-academic-red scale-105 z-10 font-bold transition-all duration-300 ring-2 ring-academic-red/20";
       }
    }

    // 2. Default Alignment Styling (if no matches, plain text)
    if (!currentAlignments || currentAlignments.length === 0) return 'border-transparent text-gray-700/80 hover:text-gray-900';

    const bestAlignment = currentAlignments.reduce((prev, current) => (prev.similarity > current.similarity) ? prev : current);

    // 3. Hover Effects
    let isConnected = false;
    if (hoveredIdx) {
      if (hoveredIdx.side === side && hoveredIdx.index === tokenIdx) {
        isConnected = true; 
      } else if (hoveredIdx.side !== side) {
        // Check if the hovered token on the OTHER side aligns with THIS token
        const otherSideMatches = (hoveredIdx.side === 'A' ? alignmentMapA : alignmentMapB).get(hoveredIdx.index);
        if (otherSideMatches?.some(m => (side === 'A' ? m.sourceIndex : m.targetIndex) === tokenIdx)) {
          isConnected = true;
        }
      }
    }

    const baseClass = "cursor-pointer transition-all duration-200 border-b-[3px] rounded-t-sm px-0.5 ";
    const connectionClass = isConnected ? "bg-academic-gold/30 scale-110 font-medium " : "";

    // Color coding based on similarity
    let scoreClass = "";
    if (bestAlignment.similarity === 100) scoreClass = "border-green-600/60 bg-green-50/50 hover:bg-green-100";
    else if (bestAlignment.similarity >= 80) scoreClass = "border-blue-500/60 bg-blue-50/50 hover:bg-blue-100";
    else if (bestAlignment.similarity >= 60) scoreClass = "border-gray-400/60 border-dashed bg-gray-50 hover:bg-gray-100";
    else scoreClass = "border-gray-300/60 border-dotted hover:bg-gray-50";

    return baseClass + connectionClass + scoreClass;
  };

  const renderTokens = (tokens: Token[], side: 'A' | 'B', ref: React.RefObject<HTMLDivElement>) => {
    let lastPos = 0;
    return (
      <div className="font-coptic text-lg leading-loose text-justify p-1">
        {tokens.map((token, i) => {
          const spacing = token.start > lastPos ? " " : "";
          lastPos = token.end;

          return (
            <React.Fragment key={i}>
              {spacing}
              <span
                data-token-index={i}
                className={`inline-block relative group select-none ${getStyle(i, side)}`}
                onMouseEnter={() => setHoveredIdx({ side, index: i })}
                onMouseLeave={() => setHoveredIdx(null)}
                onClick={(e) => {
                  e.stopPropagation();
                  handleTokenClick(i, side);
                }}
              >
                {token.text}
              </span>
            </React.Fragment>
          );
        })}
      </div>
    );
  };

  // Sticky footer details
  let activeDetails = null;
  if (selectedMatch) {
     activeDetails = (
       <div className="flex gap-4 items-center w-full bg-academic-gold/10 p-2 rounded border border-academic-gold">
         <div className="font-bold text-academic-blue uppercase text-xs">Selected Pair</div>
         <div className="flex-1 flex flex-col md:flex-row gap-2 md:items-center text-sm">
            <div className="flex-1 font-coptic truncate border-r border-gray-300 pr-2 cursor-help" title={selectedMatch.sourcePhrase}>
              <span className="font-mono text-xs text-academic-blue font-bold mr-2">α[{selectedMatch.sourcePosition}]</span>
              {selectedMatch.sourcePhrase}
            </div>
            <div className="font-bold text-academic-red px-2 bg-white rounded border border-gray-200">
               {selectedMatch.similarity.toFixed(0)}%
            </div>
            <div className="flex-1 font-coptic truncate pl-2 cursor-help" title={selectedMatch.targetPhrase}>
               <span className="font-mono text-xs text-academic-blue font-bold mr-2">β[{selectedMatch.targetPosition}]</span>
               {selectedMatch.targetPhrase}
            </div>
         </div>
       </div>
     );
  } else if (hoveredIdx) {
    const { side, index } = hoveredIdx;
    const token = side === 'A' ? tokensA[index] : tokensB[index];
    const matches = side === 'A' ? alignmentMapA.get(index) : alignmentMapB.get(index);

    if (matches && matches.length > 0) {
      activeDetails = (
         <div className="flex gap-4 items-center animate-fade-in w-full">
            <div className="font-bold text-academic-blue whitespace-nowrap">
               {side === 'A' ? 'Witness α' : 'Witness β'}:
               <span className="ml-2 font-coptic text-lg bg-white px-2 py-1 rounded border border-gray-200 shadow-sm">{token.text}</span>
            </div>
            <div className="text-gray-400">→</div>
            <div className="flex-1 flex flex-wrap gap-2 items-center">
               {matches.sort((a,b) => b.similarity - a.similarity).slice(0, 3).map((m, idx) => (
                  <div key={idx} className="bg-white border border-gray-200 px-2 py-1 rounded text-xs flex items-center shadow-sm">
                     <span className={`font-bold mr-1 ${m.similarity >= 99 ? 'text-green-600' : 'text-academic-gold'}`}>{m.similarity.toFixed(0)}%</span>
                     w/ <span className="font-mono ml-1 font-bold">{side === 'A' ? `β` : `α`}</span>
                  </div>
               ))}
               <span className="text-[10px] text-gray-400 ml-auto uppercase tracking-wide">Click to select match</span>
            </div>
         </div>
      );
    } else {
      activeDetails = <div className="text-gray-500 italic flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-gray-300"></span>No alignment detected for this token.</div>;
    }
  } else {
    activeDetails = <div className="text-gray-400 italic text-center text-sm w-full">Hover tokens to inspect • Click to lock selection</div>;
  }

  return (
    <div className="flex flex-col border border-gray-200 shadow-sm rounded-sm h-full bg-white">
      {/* Scrollable Content */}
      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-0 overflow-hidden h-full">
        <div className="flex flex-col border-r border-gray-200 h-full overflow-hidden">
          <div className="bg-academic-paper p-2 border-b border-gray-200 sticky top-0 z-10 shrink-0">
            <h4 className="font-bold text-academic-blue uppercase text-xs tracking-wider flex items-center justify-between">
              <span>Witness α (Source)</span>
              <span className="text-gray-400 font-mono text-[10px]">{tokensA.length} tokens</span>
            </h4>
          </div>
