export interface Token {
  text: string;
  normalized: string;
  start: number;
  end: number;
  type: 'coptic' | 'greek' | 'latin' | 'number' | 'mixed';
  index: number;
}

export interface Alignment {
  sourceIndex: number;
  targetIndex: number;
  similarity: number;
  sourceText: string;
  targetText: string;
}

export interface Match {
  sourceIndex: number;
  targetIndex: number;
  sourcePhrase: string;
  targetPhrase: string;
  similarity: number;
  sourcePosition: number; // Token index start
  targetPosition: number; // Token index start
  length?: number; // Number of tokens in the match (crucial for SW)
}

// Renamed 'passim' -> 'char-ngram', 'tracer' -> 'word-ngram'
export type AlgorithmType = 'char-ngram' | 'word-ngram' | 'jaccard' | 'levenshtein' | 'coptic-aware' | 'smith-waterman';
export type ScriptMode = 'auto' | 'coptic' | 'mixed' | 'latin';

export interface AnalysisConfig {
  windowSize: number;
  threshold: number;
  algorithm: AlgorithmType;
  scriptMode: ScriptMode;
}

export interface AnalysisStats {
  totalAlignments: number;
  meanSimilarity: number;
  coverage: number;
  uniqueNgrams: number;
}

export interface AnalysisResult {
  tokensA: Token[];
  tokensB: Token[];
  matches: Match[];
  alignments: Alignment[];
  stats: AnalysisStats;
}

import { Token, Match, Alignment, AlgorithmType, ScriptMode } from '../types';

// Unicode Ranges
const RANGES = {
  coptic: { start: 0x2C80, end: 0x2CFF },
  greek: { start: 0x0370, end: 0x03FF, extStart: 0x1F00, extEnd: 0x1FFF },
  copticEpact: { start: 0x102E0, end: 0x102FF },
  // CJK Unified Ideographs, Hiragana, Katakana
  cjk: { start: 0x4E00, end: 0x9FFF },
  hiragana: { start: 0x3040, end: 0x309F },
  katakana: { start: 0x30A0, end: 0x30FF },
  // Semitic & Afroasiatic
  hebrew: { start: 0x0590, end: 0x05FF },
  arabic: { start: 0x0600, end: 0x06FF },
  syriac: { start: 0x0700, end: 0x074F },
  ethiopic: { start: 0x1200, end: 0x137F }, // Ge'ez
  // Devanagari (Sanskrit/Hindi)
  devanagari: { start: 0x0900, end: 0x097F }
};

const checkRange = (char: string, range: { start: number; end: number }) => {
  const code = char.charCodeAt(0);
  return code >= range.start && code <= range.end;
};

const isCoptic = (char: string): boolean => {
  return checkRange(char, RANGES.coptic) || checkRange(char, RANGES.copticEpact);
};

const isGreek = (char: string): boolean => {
  return checkRange(char, RANGES.greek) || 
         (char.charCodeAt(0) >= RANGES.greek.extStart && char.charCodeAt(0) <= RANGES.greek.extEnd);
};

const isCJK = (char: string): boolean => {
  return checkRange(char, RANGES.cjk) || checkRange(char, RANGES.hiragana) || checkRange(char, RANGES.katakana);
};

export const detectScript = (text: string): ScriptMode => {
  let counts = {
    coptic: 0,
    greek: 0,
    cjk: 0,
    latin: 0,
    hebrew: 0,
    arabic: 0,
    syriac: 0,
    ethiopic: 0
  };

  for (const char of text) {
    if (isCoptic(char)) counts.coptic++;
    else if (isGreek(char)) counts.greek++;
    else if (isCJK(char)) counts.cjk++;
    else if (checkRange(char, RANGES.hebrew)) counts.hebrew++;
    else if (checkRange(char, RANGES.arabic)) counts.arabic++;
    else if (checkRange(char, RANGES.syriac)) counts.syriac++;
    else if (checkRange(char, RANGES.ethiopic)) counts.ethiopic++;
    else if (/[a-zA-Z]/.test(char)) counts.latin++;
  }

  const total = Object.values(counts).reduce((a, b) => a + b, 0);
  if (total === 0) return 'latin'; // Default fallback

  if (counts.cjk > total * 0.3) return 'coptic'; // Using generic 'coptic' mode key for CJK tokenization flow momentarily
  if (counts.coptic > total * 0.3) return 'coptic';
  if (counts.greek > total * 0.3) return 'mixed'; // Treated as mixed usually
  if (counts.latin > total * 0.8) return 'latin';

  // For Semitic languages, we can treat them as 'mixed' or 'coptic' (space delimited usually)
  // 'mixed' in our tokenizer handles generic word boundaries which works for Arabic/Hebrew/Syriac/Ge'ez
  return 'mixed';
};

export const tokenize = (text: string, mode: ScriptMode = 'auto'): Token[] => {
  const normalizedText = text.normalize('NFC');

  // Detect if the text is predominantly CJK
  let cjkCount = 0;
  for (const char of normalizedText) {
    if (isCJK(char)) cjkCount++;
  }
  const isPredominantlyCJK = cjkCount > normalizedText.length * 0.3;

  const tokens: Token[] = [];

  if (isPredominantlyCJK) {
    // Character-based tokenization for CJK
    let index = 0;
    for (let i = 0; i < normalizedText.length; i++) {
      const char = normalizedText[i];
      if (!/\s/.test(char) && !/、|。|，|：|；|「|」/.test(char)) {
        tokens.push({
          text: char,
          normalized: char,
          start: i,
          end: i + 1,
          type: 'mixed', 
          index: index++
        });
      }
    }
  } else {
    // Word-based tokenization for everything else
    // \p{L} = Letter, \p{M} = Mark (accents), \p{N} = Number
    // Included Hebrew/Arabic/Syriac/Ethiopic via Unicode properties
    const wordPattern = /[\p{L}\p{M}\p{N}]+/gu;

    let match;
    let index = 0;
    while ((match = wordPattern.exec(normalizedText)) !== null) {
      const txt = match[0];
      const firstChar = txt[0];
      let type: any = 'latin';

      if (isCoptic(firstChar)) type = 'coptic';
      else if (isGreek(firstChar)) type = 'greek';
      else if (checkRange(firstChar, RANGES.hebrew)) type = 'mixed'; // hebrew
      else if (checkRange(firstChar, RANGES.arabic)) type = 'mixed'; // arabic
      else if (checkRange(firstChar, RANGES.syriac)) type = 'mixed'; // syriac
      else if (checkRange(firstChar, RANGES.ethiopic)) type = 'mixed'; // ge'ez
      else if (/\d/.test(firstChar)) type = 'number';

      tokens.push({
        text: txt,
        normalized: txt.toLowerCase(), // Note: toLowerCase works for Greek/Coptic/Latin/Cyrillic. Semitic often doesn't have case.
        start: match.index,
        end: match.index + txt.length,
        type: type,
        index: index++
      });
    }
  }

  return tokens;
};

// Levenshtein Implementation
const levenshteinDistance = (str1: string, str2: string): number => {
  const track = Array(str2.length + 1).fill(null).map(() =>
    Array(str1.length + 1).fill(null));

  for (let i = 0; i <= str1.length; i += 1) track[0][i] = i;
  for (let j = 0; j <= str2.length; j += 1) track[j][0] = j;

  for (let j = 1; j <= str2.length; j += 1) {
    for (let i = 1; i <= str1.length; i += 1) {
      const indicator = str1[i - 1] === str2[j - 1] ? 0 : 1;
      track[j][i] = Math.min(
        track[j][i - 1] + 1,
        track[j - 1][i] + 1,
        track[j - 1][i - 1] + indicator,
      );
    }
  }
  return track[str2.length][str1.length];
};

// Advanced Coptic Normalization & Similarity
const calculateCopticSimilarity = (s1: string, s2: string): number => {
  // Generic normalization for collation
  const normalize = (s: string) => s.toLowerCase()
    .replace(/ⲛ̄/g, 'ⲛ')
    .replace(/ⲙ̄/g, 'ⲙ')
    .replace(/[\u0300-\u036F\u0591-\u05C7\u064B-\u0652]/g, '') // strip diacritics (Coptic, Greek, Hebrew Niqud, Arabic Tashkeel)
    // Greek standardizations
    .replace(/[άἀἁἂἃἄἅἆἇὰάᾀᾁᾂᾃᾄᾅᾆᾇᾰᾱᾲᾳᾴᾶᾷΆἈἉἊἋἌἍἎἏᾈᾉᾊᾋᾌᾍᾎᾏᾸᾹᾺΆᾼ]/g, 'α')
    .replace(/[έἐἑἒἓἔἕὲέῈΈΈἘἙἚἛἜἝ]/g, 'ε')
    .replace(/[ήἠἡἢἣἤἥἦἧὴήᾐᾑᾒᾓᾔᾕᾖᾗῂῃῄῆῇΉἨἩἪἫἬἭἮἯᾘᾙᾚᾛᾜᾝᾞᾟῊΉῌ]/g, 'η')
    .replace(/[ίἰἱἲἳἴἵἶἷὶίῐῑῒΐῖῗΊἸἹἺἻἼἽἾἿῘῙῚΊ]/g, 'ι')
    .replace(/[όὀὁὂὃὄὅὸόΌὈὉὊὋὌὍῸΌ]/g, 'ο')
    .replace(/[ύὐὑὒὓὔὕὖὗὺύῠῡῢΰῦῧΎὙὛὝὟῨῩῪΎ]/g, 'υ')
    .replace(/[ώὠὡὢὣὤὥὦὧὼώᾠᾡᾢᾣᾤᾥᾦᾧῲῳῴῶῷΏὨὩὪὫὬὭὮὯᾨᾩᾪᾫᾬᾭᾮᾯῺΏῼ]/g, 'ω')
    .normalize('NFC');

  const n1 = normalize(s1);
  const n2 = normalize(s2);

  if (n1 === n2) return 100;

  const dist = levenshteinDistance(n1, n2);
  const maxLen = Math.max(n1.length, n2.length);
  return maxLen === 0 ? 100 : (1 - dist / maxLen) * 100;
};

// Jaccard for arrays
const jaccard = (a: any[], b: any[]): number => {
  const setA = new Set(a);
  const setB = new Set(b);
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  const union = new Set([...setA, ...setB]);
  return union.size === 0 ? 0 : intersection.size / union.size;
};

// Smith-Waterman Implementation (Token based)
const runSmithWaterman = (tokensA: Token[], tokensB: Token[], threshold: number): Match[] => {
  const m = tokensA.length;
  const n = tokensB.length;

  // Scoring scheme
  const MATCH_SCORE = 2;
  const MISMATCH_SCORE = -1;
  const GAP_SCORE = -1;

  // Initialize matrix
  const matrix: number[][] = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));
  let maxScore = 0;
  let maxI = 0;
  let maxJ = 0;

  // Fill matrix
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const tokenSim = calculateCopticSimilarity(tokensA[i-1].normalized, tokensB[j-1].normalized);
      const isMatch = tokenSim >= 80; // Fuzzy match threshold for SW steps

      const scoreDiag = matrix[i-1][j-1] + (isMatch ? MATCH_SCORE : MISMATCH_SCORE);
      const scoreUp = matrix[i-1][j] + GAP_SCORE;
      const scoreLeft = matrix[i][j-1] + GAP_SCORE;

      matrix[i][j] = Math.max(0, scoreDiag, scoreUp, scoreLeft);

      if (matrix[i][j] > maxScore) {
        maxScore = matrix[i][j];
        maxI = i;
        maxJ = j;
      }
    }
  }

  // Traceback (Finds ONE best local alignment)
  const pathA: number[] = []; // indices
  const pathB: number[] = [];

  let i = maxI;
  let j = maxJ;

  while (matrix[i][j] > 0) {
    const currentScore = matrix[i][j];
    const tokenSim = calculateCopticSimilarity(tokensA[i-1].normalized, tokensB[j-1].normalized);
    const isMatch = tokenSim >= 80;

    // Check diagonal
    if (i > 0 && j > 0 && 
        (matrix[i-1][j-1] + (isMatch ? MATCH_SCORE : MISMATCH_SCORE) === currentScore || 
         (isMatch && matrix[i-1][j-1] >= matrix[i-1][j] && matrix[i-1][j-1] >= matrix[i][j-1]))) {
      pathA.unshift(i - 1);
      pathB.unshift(j - 1);
      i--;
      j--;
    } 
    // Check Up
    else if (i > 0 && matrix[i-1][j] + GAP_SCORE === currentScore) {
      i--; 
    } 
    // Check Left
    else if (j > 0 && matrix[i][j-1] + GAP_SCORE === currentScore) {
      j--;
    } else {
      break;
    }
  }

  if (pathA.length === 0) return [];

  // Convert path to a single Match object (Region)
  const startA = pathA[0];
  const endA = pathA[pathA.length - 1];
  const startB = pathB[0];
  const endB = pathB[pathB.length - 1];

  const phraseA = tokensA.slice(startA, endA + 1).map(t => t.text).join(' ');
  const phraseB = tokensB.slice(startB, endB + 1).map(t => t.text).join(' ');

  // Calculate aggregate similarity of this region
  const sim = calculateCopticSimilarity(phraseA, phraseB);

  return [{
    sourceIndex: startA,
    targetIndex: startB,
    sourcePhrase: phraseA,
    targetPhrase: phraseB,
    similarity: Math.min(100, sim + 20),
    sourcePosition: startA,
    targetPosition: startB,
    length: Math.max(pathA.length, pathB.length)
  }];
};

// Main Analysis Function
export const runAnalysis = (
  textA: string, 
  textB: string, 
  config: { windowSize: number; threshold: number; algorithm: AlgorithmType; scriptMode: ScriptMode }
) => {
  const tokensA = tokenize(textA, config.scriptMode);
  const tokensB = tokenize(textB, config.scriptMode);

  let matches: Match[] = [];
  const alignments: Alignment[] = [];

  // --- SMITH-WATERMAN ---
  if (config.algorithm === 'smith-waterman') {
    matches = runSmithWaterman(tokensA, tokensB, config.threshold);
  }
  // --- Character N-Grams (was 'passim') ---
  else if (config.algorithm === 'char-ngram') {
    // Heuristic: map windowSize tokens to approx characters (1 token ~ 5 chars)
    const n = config.windowSize;
    for (let i = 0; i <= tokensA.length - n; i++) {
      const sliceA = tokensA.slice(i, i + n);
      const phraseA = sliceA.map(t => t.text).join('');

      for (let j = 0; j <= tokensB.length - n; j++) {
        const sliceB = tokensB.slice(j, j + n);
        const phraseB = sliceB.map(t => t.text).join('');

        const sim = calculateCopticSimilarity(phraseA, phraseB);

        if (sim >= config.threshold) {
          matches.push({
            sourceIndex: i,
            targetIndex: j,
            sourcePhrase: phraseA, 
            targetPhrase: phraseB,
            similarity: sim,
            sourcePosition: i,
            targetPosition: j,
            length: n
          });
        }
      }
    }
  }
  // --- Word N-Grams (was 'tracer') & OTHERS ---
  else {
    const n = config.windowSize;

    for (let i = 0; i <= tokensA.length - n; i++) {
      const sliceA = tokensA.slice(i, i + n);
      const phraseA = sliceA.map(t => t.text).join(' ');
      const normPhraseA = sliceA.map(t => t.normalized).join('');

      for (let j = 0; j <= tokensB.length - n; j++) {
        const sliceB = tokensB.slice(j, j + n);
        const phraseB = sliceB.map(t => t.text).join(' ');
        const normPhraseB = sliceB.map(t => t.normalized).join('');

        let sim = 0;

        if (config.algorithm === 'word-ngram') {
           sim = jaccard(sliceA.map(t => t.normalized), sliceB.map(t => t.normalized)) * 100;
        } else if (config.algorithm === 'jaccard') {
          sim = jaccard(phraseA.split(''), phraseB.split('')) * 100;
        } else if (config.algorithm === 'levenshtein') {
          const dist = levenshteinDistance(normPhraseA, normPhraseB);
          const max = Math.max(normPhraseA.length, normPhraseB.length);
          sim = max === 0 ? 0 : (1 - dist / max) * 100;
        } else if (config.algorithm === 'coptic-aware') {
          sim = calculateCopticSimilarity(phraseA, phraseB);
        }

        if (sim >= config.threshold) {
          matches.push({
            sourceIndex: i,
            targetIndex: j,
            sourcePhrase: phraseA,
            targetPhrase: phraseB,
            similarity: sim,
            sourcePosition: i,
            targetPosition: j,
            length: n
          });
        }
      }
    }
  }

  // 2. Pairwise Token Alignment
  tokensA.forEach((tA, i) => {
    tokensB.forEach((tB, j) => {
       const sim = calculateCopticSimilarity(tA.normalized, tB.normalized);
       if (sim >= 40) {
         alignments.push({
           sourceIndex: i,
           targetIndex: j,
           similarity: sim,
           sourceText: tA.text,
           targetText: tB.text
         });
       }
    });
  });

  // Calculate Stats
  const avgSim = matches.length > 0 
    ? matches.reduce((acc, m) => acc + m.similarity, 0) / matches.length 
    : 0;

  // New Coverage Calculation: Use Sets to count unique tokens involved in matches
  const coveredIndicesA = new Set<number>();
  const coveredIndicesB = new Set<number>();

  matches.forEach(m => {
    const len = m.length || config.windowSize;
    // Mark indices in Source
    for (let k = 0; k < len; k++) {
      if (m.sourcePosition + k < tokensA.length) {
        coveredIndicesA.add(m.sourcePosition + k);
      }
    }
    // Mark indices in Target
    for (let k = 0; k < len; k++) {
      if (m.targetPosition + k < tokensB.length) {
        coveredIndicesB.add(m.targetPosition + k);
      }
    }
  });

  const totalTokens = tokensA.length + tokensB.length;
  const totalCovered = coveredIndicesA.size + coveredIndicesB.size;
  const coverage = totalTokens === 0 ? 0 : (totalCovered / totalTokens) * 100;

  const uniquePhrases = new Set([
    ...matches.map(m => m.sourcePhrase),
    ...matches.map(m => m.targetPhrase)
  ]);

  return {
    tokensA,
    tokensB,
    matches,
    alignments,
    stats: {
      totalAlignments: matches.length,
      meanSimilarity: avgSim,
      coverage: coverage,
      uniqueNgrams: uniquePhrases.size
    }
  };
};

