import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { Match } from '../types';

interface NetworkGraphProps {
  matches: Match[];
  onSelectMatch: (match: Match) => void;
  selectedMatch: Match | null;
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ matches, onSelectMatch, selectedMatch }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement | null>(null);

  // Refs to store D3 selections and data so we don't re-simulate on selection change
  const simulationRef = useRef<d3.Simulation<any, undefined> | null>(null);
  const nodesDataRef = useRef<any[]>([]);
  const linksDataRef = useRef<any[]>([]);

  const linkSelectionRef = useRef<d3.Selection<SVGLineElement, any, SVGGElement, unknown> | null>(null);
  const nodeSelectionRef = useRef<d3.Selection<SVGCircleElement, any, SVGGElement, unknown> | null>(null);
  const labelSelectionRef = useRef<d3.Selection<SVGTextElement, any, SVGGElement, unknown> | null>(null);
  const zoomBehaviorRef = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);

  const [isEmpty, setIsEmpty] = useState(false);

  // 1. Initialization Effect: Runs ONLY when `matches` data changes (e.g. new analysis)
  useEffect(() => {
    if (!containerRef.current) return;

    // Sort and limit to avoid overcrowding
    const relevantMatches = matches
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 100);

    if (relevantMatches.length === 0) {
      setIsEmpty(true);
      return;
    }
    setIsEmpty(false);

    // Clear previous graph
    d3.select(containerRef.current).selectAll("*").remove();

    const width = containerRef.current.clientWidth || 800;
    const height = 400;

    // Setup SVG
    const svg = d3.select(containerRef.current)
      .append("svg")
      .attr("width", "100%")
      .attr("height", height)
      .attr("viewBox", [0, 0, width, height]);

    svgRef.current = svg.node();

    const g = svg.append("g");

    // Setup Zoom
    const zoom = d3.zoom<SVGSVGElement, unknown>()
        .scaleExtent([0.1, 4])
        .on("zoom", (event) => g.attr("transform", event.transform));

    svg.call(zoom);
    zoomBehaviorRef.current = zoom;

    // Prepare Data
    // Separe nodes by witness to avoid merging distinct entities even if text is identical
    const nodeMap = new Map();

    relevantMatches.forEach(m => {
      // Create distinct IDs for Alpha and Beta witnesses
      const alphaId = `A::${m.sourcePhrase}`;
      const betaId = `B::${m.targetPhrase}`;

      if (!nodeMap.has(alphaId)) {
        nodeMap.set(alphaId, { 
          id: alphaId, 
          label: m.sourcePhrase, 
          group: 'alpha', 
          r: 5 
        });
      }
      if (!nodeMap.has(betaId)) {
        nodeMap.set(betaId, { 
          id: betaId, 
          label: m.targetPhrase, 
          group: 'beta', 
          r: 5 
        });
      }
    });

    const nodes = Array.from(nodeMap.values());
    const links = relevantMatches.map(m => ({
      source: `A::${m.sourcePhrase}`,
      target: `B::${m.targetPhrase}`,
      value: m.similarity,
      matchData: m
    }));

    nodesDataRef.current = nodes;
    linksDataRef.current = links;

    // Force Simulation
    const simulation = d3.forceSimulation(nodes)
      .force("link", d3.forceLink(links).id((d: any) => d.id).distance((d: any) => {
         // Pull exact matches very close together
         if (d.value >= 99) return 40;
         if (d.value >= 80) return 80;
         return 150;
      }))
      .force("charge", d3.forceManyBody().strength(-200))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collide", d3.forceCollide(20))
      .alphaDecay(0.05); // Decay faster to settle quicker

    simulationRef.current = simulation;

    // Draw Links
    const link = g.append("g")
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke", (d: any) => d.value >= 99 ? "#27ae60" : "#95a5a6") // Green for exact
      .attr("stroke-opacity", (d: any) => d.value >= 99 ? 0.6 : 0.3)
      .attr("stroke-width", (d: any) => Math.max(1, (d.value - 40) / 10))
      .attr("stroke-dasharray", (d: any) => d.value >= 99 ? "none" : (d.value < 80 ? "4,2" : "none")) // Dashed for low sim
      .attr("cursor", "pointer")
      .on("click", (event, d: any) => {
        event.stopPropagation();
        onSelectMatch(d.matchData);
      });

    link.append("title").text((d: any) => `Similarity: ${d.value.toFixed(1)}%`);
    linkSelectionRef.current = link;

    // Draw Nodes
    const node = g.append("g")
      .attr("stroke", "#fff")
      .attr("stroke-width", 1.5)
      .selectAll("circle")
      .data(nodes)
      .join("circle")
      .attr("r", (d: any) => d.r + 3)
      .attr("fill", (d: any) => d.group === 'alpha' ? "#34495e" : "#8b7355")
      .attr("cursor", "grab")
      .call(d3.drag<any, any>()
        .on("start", (event, d) => {
          if (!event.active) simulation.alphaTarget(0.3).restart();
          d.fx = d.x;
          d.fy = d.y;
        })
        .on("drag", (event, d) => {
          d.fx = event.x;
          d.fy = event.y;
        })
        .on("end", (event, d) => {
          if (!event.active) simulation.alphaTarget(0);
          d.fx = null;
          d.fy = null;
        }));

    node.append("title").text((d: any) => d.label);
    nodeSelectionRef.current = node;

    // Draw Labels
    const label = g.append("g")
      .selectAll("text")
      .data(nodes)
      .enter()
      .append("text")
      .text((d: any) => d.label.length > 15 ? d.label.substring(0, 15) + '...' : d.label)
      .attr("font-size", 10)
      .attr("dx", 12)
      .attr("dy", 4)
      .attr("fill", "#2c3e50")
      .style("pointer-events", "none");

    labelSelectionRef.current = label;

    // Simulation Tick
    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      node.attr("cx", (d: any) => d.x).attr("cy", (d: any) => d.y);
      label.attr("x", (d: any) => d.x).attr("y", (d: any) => d.y);
    });

    return () => {
      simulation.stop();
    };
  }, [matches]); // IMPORTANT: Do NOT include selectedMatch here

  // 2. Selection Effect: Updates styles and zoom without restarting simulation
  useEffect(() => {
    if (!linkSelectionRef.current || !nodeSelectionRef.current || !labelSelectionRef.current) return;

    // --- Update Styles ---

    // Links
    linkSelectionRef.current
      .transition().duration(300)
      .attr("stroke", (d: any) => {
        if (selectedMatch && d.matchData === selectedMatch) return "#c9302c";
        return d.value >= 99 ? "#27ae60" : "#95a5a6";
      })
      .attr("stroke-opacity", (d: any) => {
        if (!selectedMatch) return d.value >= 99 ? 0.6 : 0.3;
        return d.matchData === selectedMatch ? 1 : 0.1;
      })
      .attr("stroke-width", (d: any) => {
        const base = Math.max(1, (d.value - 40) / 10);
        return (selectedMatch && d.matchData === selectedMatch) ? base + 2 : base;
      });

    // Nodes
    nodeSelectionRef.current
      .transition().duration(300)
      .attr("r", (d: any) => {
        if (!selectedMatch) return d.r + 3;
        // Check using IDs since label might not be unique
        const isTarget = d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`;
        return isTarget ? 10 : 8;
      })
      .attr("fill", (d: any) => {
        // Keep distinct group colors even when selected
        return d.group === 'alpha' ? "#34495e" : "#8b7355";
      })
      .attr("stroke", (d: any) => {
        // Use red stroke to indicate selection instead of changing fill color
        if (selectedMatch && (d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`)) {
            return "#c9302c";
        }
        return "#fff";
      })
      .attr("stroke-width", (d: any) => {
        if (selectedMatch && (d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`)) {
            return 3;
        }
        return 1.5;
      })
      .style("opacity", (d: any) => {
        if (!selectedMatch) return 1;
        const isTarget = selectedMatch && (d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`);
        return isTarget ? 1 : 0.3;
      });

    // Labels
    labelSelectionRef.current
      .transition().duration(300)
      .style("opacity", (d: any) => {
        if (!selectedMatch) return 1;
        const isTarget = selectedMatch && (d.id === `A::${selectedMatch.sourcePhrase}` || d.id === `B::${selectedMatch.targetPhrase}`);
        return isTarget ? 1 : 0;
      });

    // --- Smart Zoom to Selection ---
    if (selectedMatch && svgRef.current && zoomBehaviorRef.current && nodesDataRef.current.length > 0) {
      // Find the nodes corresponding to the selected match
      // Note: Simulation has run, so nodes have x, y properties
      const sourceNode = nodesDataRef.current.find(n => n.id === `A::${selectedMatch.sourcePhrase}`);
      const targetNode = nodesDataRef.current.find(n => n.id === `B::${selectedMatch.targetPhrase}`);

      if (sourceNode && targetNode && typeof sourceNode.x === 'number' && typeof targetNode.x === 'number') {
        const width = containerRef.current?.clientWidth || 800;
        const height = 400;

        const midX = (sourceNode.x + targetNode.x) / 2;
        const midY = (sourceNode.y + targetNode.y) / 2;

        // Calculate distance to determine zoom level
        const dx = Math.abs(sourceNode.x - targetNode.x);
        const dy = Math.abs(sourceNode.y - targetNode.y);
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Scale logic: closer nodes = higher zoom, but capped
        const scale = Math.min(2.5, Math.max(0.8, (height * 0.6) / (distance + 1)));

        d3.select(svgRef.current)
          .transition()
          .duration(800)
          .ease(d3.easeCubicOut)
          .call(
            zoomBehaviorRef.current.transform,
            d3.zoomIdentity
              .translate(width / 2, height / 2)
              .scale(scale)
              .translate(-midX, -midY)
          );
      }
    }

  }, [selectedMatch]);

  return (
    <div className="relative w-full bg-white border border-gray-200 rounded-sm shadow-sm overflow-hidden h-[400px] group">
      <div ref={containerRef} className="w-full h-full" />

      {/* Legend / Help */}
      <div className="absolute top-2 left-2 bg-white/95 p-2 rounded border border-gray-200 text-[10px] text-gray-600 shadow-sm pointer-events-none opacity-50 group-hover:opacity-100 transition-opacity z-10">
        <strong>Network Graph:</strong><br/>
        <span className="text-academic-blue font-bold">●</span> Witness α (Source)<br/>
        <span className="text-academic-gold font-bold">●</span> Witness β (Target)<br/>
        <span className="text-green-600 font-bold">━</span> Exact Match (100%)<br/>
        <span className="text-gray-400 font-bold">┅</span> Fuzzy Match
      </div>

      {isEmpty && (
        <div className="absolute inset-0 flex items-center justify-center text-gray-400 bg-gray-50/50">
          No matches high enough to display network.
        </div>
      )}

      <div className="absolute bottom-2 right-2 bg-white/90 px-2 py-1 text-[10px] text-gray-500 rounded border border-gray-100 shadow-sm z-10">
        {selectedMatch ? "View centered on selection" : "Scroll to Zoom • Drag Nodes"}
      </div>
    </div>
  );
};

export default NetworkGraph;

import { Token, Match, Alignment, AlgorithmType, ScriptMode } from '../types';

// Unicode Ranges
const RANGES = {
  coptic: { start: 0x2C80, end: 0x2CFF },
  greek: { start: 0x0370, end: 0x03FF, extStart: 0x1F00, extEnd: 0x1FFF },
  copticEpact: { start: 0x102E0, end: 0x102FF },
  cjk: { start: 0x4E00, end: 0x9FFF },
  hiragana: { start: 0x3040, end: 0x309F },
  katakana: { start: 0x30A0, end: 0x30FF },
  hebrew: { start: 0x0590, end: 0x05FF },
  arabic: { start: 0x0600, end: 0x06FF },
  syriac: { start: 0x0700, end: 0x074F },
  ethiopic: { start: 0x1200, end: 0x137F },
  devanagari: { start: 0x0900, end: 0x097F }
};

const checkRange = (char: string, range: { start: number; end: number }) => {
  const code = char.charCodeAt(0);
  return code >= range.start && code <= range.end;
};

const isCoptic = (char: string): boolean => {
  return checkRange(char, RANGES.coptic) || checkRange(char, RANGES.copticEpact);
};

const isGreek = (char: string): boolean => {
  return checkRange(char, RANGES.greek) || 
         (char.charCodeAt(0) >= RANGES.greek.extStart && char.charCodeAt(0) <= RANGES.greek.extEnd);
};

const isCJK = (char: string): boolean => {
  return checkRange(char, RANGES.cjk) || checkRange(char, RANGES.hiragana) || checkRange(char, RANGES.katakana);
};

export const tokenize = (text: string, mode: ScriptMode = 'auto'): Token[] => {
  const normalizedText = text.normalize('NFC');
  let cjkCount = 0;
  for (const char of normalizedText) {
    if (isCJK(char)) cjkCount++;
  }
  const isPredominantlyCJK = cjkCount > normalizedText.length * 0.3;
  const tokens: Token[] = [];

  if (isPredominantlyCJK) {
    let index = 0;
    for (let i = 0; i < normalizedText.length; i++) {
      const char = normalizedText[i];
      if (!/\s/.test(char) && !/、|。|，|：|；|「|」/.test(char)) {
        tokens.push({
          text: char,
          normalized: char,
          start: i,
          end: i + 1,
          type: 'mixed', 
          index: index++
        });
      }
    }
  } else {
    const wordPattern = /[\p{L}\p{M}\p{N}]+/gu;
    let match;
    let index = 0;
    while ((match = wordPattern.exec(normalizedText)) !== null) {
      const txt = match[0];
      const firstChar = txt[0];
      let type: any = 'latin';
      if (isCoptic(firstChar)) type = 'coptic';
      else if (isGreek(firstChar)) type = 'greek';
      else if (checkRange(firstChar, RANGES.hebrew)) type = 'mixed';
      else if (checkRange(firstChar, RANGES.arabic)) type = 'mixed';
      else if (checkRange(firstChar, RANGES.syriac)) type = 'mixed';
      else if (checkRange(firstChar, RANGES.ethiopic)) type = 'mixed';
      else if (checkRange(firstChar, RANGES.devanagari)) type = 'mixed';
      else if (/\d/.test(firstChar)) type = 'number';

      tokens.push({
        text: txt,
        normalized: txt.toLowerCase(),
        start: match.index,
        end: match.index + txt.length,
        type: type,
        index: index++
      });
    }
  }
  return tokens;
};

const levenshteinDistance = (str1: string, str2: string): number => {
  const track = Array(str2.length + 1).fill(null).map(() => Array(str1.length + 1).fill(null));
  for (let i = 0; i <= str1.length; i += 1) track[0][i] = i;
  for (let j = 0; j <= str2.length; j += 1) track[j][0] = j;
  for (let j = 1; j <= str2.length; j += 1) {
    for (let i = 1; i <= str1.length; i += 1) {
      const indicator = str1[i - 1] === str2[j - 1] ? 0 : 1;
      track[j][i] = Math.min(track[j][i - 1] + 1, track[j - 1][i] + 1, track[j - 1][i - 1] + indicator);
    }
  }
  return track[str2.length][str1.length];
};

const calculateCopticSimilarity = (s1: string, s2: string): number => {
  const normalize = (s: string) => s.toLowerCase()
    .replace(/ⲛ̄/g, 'ⲛ').replace(/ⲙ̄/g, 'ⲙ')
    .replace(/[\u0300-\u036F\u0591-\u05C7\u064B-\u0652\u0730-\u074A]/g, '') 
    .replace(/[άἀἁἂἃἄἅἆἇὰάᾀᾁᾂᾃᾄᾅᾆᾇᾰᾱᾲᾳᾴᾶᾷΆἈἉἊἋἌἍἎἏᾈᾉᾊᾋᾌᾍᾎᾏᾸᾹᾺΆᾼ]/g, 'α')
    .replace(/[έἐἑἒἓἔἕὲέῈΈΈἘἙἚἛἜἝ]/g, 'ε')
    .replace(/[ήἠἡἢἣἤἥἦἧὴήᾐᾑᾒᾓᾔᾕᾖᾗῂῃῄῆῇΉἨἩἪἫἬἭἮἯᾘᾙᾚᾛᾜᾝᾞᾟῊΉῌ]/g, 'η')
    .replace(/[ίἰἱἲἳἴἵἶἷὶίῐῑῒΐῖῗΊἸἹἺἻἼἽἾἿῘῙῚΊ]/g, 'ι')
    .replace(/[όὀὁὂὃὄὅὸόΌὈὉὊὋὌὍῸΌ]/g, 'ο')
    .replace(/[ύὐὑὒὓὔὕὖὗὺύῠῡῢΰῦῧΎὙὛὝὟῨῩῪΎ]/g, 'υ')
    .replace(/[ώὠὡὢὣὤὥὦὧὼώᾠᾡᾢᾣᾤᾥᾦᾧῲῳῴῶῷΏὨὩὪὫὬὭὮὯᾨᾩᾪᾫᾬᾭᾮᾯΏῼ]/g, 'ω')
    .normalize('NFC');

  const n1 = normalize(s1);
  const n2 = normalize(s2);
  if (n1 === n2) return 100;
  const dist = levenshteinDistance(n1, n2);
  const maxLen = Math.max(n1.length, n2.length);
  return maxLen === 0 ? 100 : (1 - dist / maxLen) * 100;
};

const jaccard = (a: any[], b: any[]): number => {
  const setA = new Set(a);
  const setB = new Set(b);
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  const union = new Set([...setA, ...setB]);
  return union.size === 0 ? 0 : (intersection.size / union.size);
};

// MULTI-PEAK SMITH-WATERMAN
const runSmithWaterman = (tokensA: Token[], tokensB: Token[], threshold: number): Match[] => {
  const m = tokensA.length;
  const n = tokensB.length;
  if (m === 0 || n === 0) return [];

  const MATCH_SCORE = 3;
  const MISMATCH_SCORE = -1;
  const GAP_SCORE = -2;

  let matrix: number[][] = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));
  const results: Match[] = [];

  // Compute full matrix
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const sim = calculateCopticSimilarity(tokensA[i - 1].normalized, tokensB[j - 1].normalized);
      const score = sim >= 80 ? MATCH_SCORE : MISMATCH_SCORE;
      matrix[i][j] = Math.max(0, matrix[i - 1][j - 1] + score, matrix[i - 1][j] + GAP_SCORE, matrix[i][j - 1] + GAP_SCORE);
    }
  }

  // Iteratively find peaks to extract multiple local alignments
  while (true) {
    let maxVal = 0;
    let maxI = -1;
    let maxJ = -1;

    for (let i = 1; i <= m; i++) {
      for (let j = 1; j <= n; j++) {
        if (matrix[i][j] > maxVal) {
          maxVal = matrix[i][j];
          maxI = i;
          maxJ = j;
        }
      }
    }

    // If peak is too low, stop
    if (maxVal < 6) break; 

    // Traceback
    let i = maxI, j = maxJ;
    const pathA: number[] = [];
    const pathB: number[] = [];

    while (i > 0 && j > 0 && matrix[i][j] > 0) {
      const current = matrix[i][j];
      const sim = calculateCopticSimilarity(tokensA[i - 1].normalized, tokensB[j - 1].normalized);
      const score = sim >= 80 ? MATCH_SCORE : MISMATCH_SCORE;

      // Mark this cell as used (zero out) to prevent reusing it in next iteration
      matrix[i][j] = 0;

      if (current === matrix[i - 1][j - 1] + score || (sim >= 80 && current > 0)) {
        pathA.unshift(i - 1);
        pathB.unshift(j - 1);
        i--; j--;
      } else if (current === matrix[i - 1][j] + GAP_SCORE) {
        i--;
      } else {
        j--;
      }
    }

    if (pathA.length > 0) {
      const startA = pathA[0];
      const endA = pathA[pathA.length - 1];
      const startB = pathB[0];
      const endB = pathB[pathB.length - 1];
      const phraseA = tokensA.slice(startA, endA + 1).map(t => t.text).join(' ');
      const phraseB = tokensB.slice(startB, endB + 1).map(t => t.text).join(' ');
      const sim = calculateCopticSimilarity(phraseA, phraseB);

      if (sim >= threshold) {
        results.push({
          sourceIndex: startA,
          targetIndex: startB,
          sourcePhrase: phraseA,
          targetPhrase: phraseB,
          similarity: sim,
          sourcePosition: startA,
          targetPosition: startB,
          length: pathA.length
        });
      }
    }
  }

  return results;
};

export const runAnalysis = (
  textA: string, 
  textB: string, 
  config: { windowSize: number; threshold: number; algorithm: AlgorithmType; scriptMode: ScriptMode }
) => {
  const tokensA = tokenize(textA, config.scriptMode);
  const tokensB = tokenize(textB, config.scriptMode);
  let matches: Match[] = [];

  if (config.algorithm === 'smith-waterman') {
    matches = runSmithWaterman(tokensA, tokensB, config.threshold);
  } else if (config.algorithm === 'char-ngram') {
    const n = config.windowSize;
    for (let i = 0; i <= tokensA.length - n; i++) {
      const sliceA = tokensA.slice(i, i + n);
      const phraseA = sliceA.map(t => t.text).join('');
      for (let j = 0; j <= tokensB.length - n; j++) {
        const sliceB = tokensB.slice(j, j + n);
        const phraseB = sliceB.map(t => t.text).join('');
        const sim = calculateCopticSimilarity(phraseA, phraseB);
        if (sim >= config.threshold) {
          matches.push({ sourceIndex: i, targetIndex: j, sourcePhrase: phraseA, targetPhrase: phraseB, similarity: sim, sourcePosition: i, targetPosition: j, length: n });
        }
      }
    }
  } else {
    const n = config.windowSize;
    for (let i = 0; i <= tokensA.length - n; i++) {
      const sliceA = tokensA.slice(i, i + n);
      const phraseA = sliceA.map(t => t.text).join(' ');
      const normA = sliceA.map(t => t.normalized).join('');
      for (let j = 0; j <= tokensB.length - n; j++) {
        const sliceB = tokensB.slice(j, j + n);
        const phraseB = sliceB.map(t => t.text).join(' ');
        const normB = sliceB.map(t => t.normalized).join('');
        let sim = 0;
        if (config.algorithm === 'word-ngram') sim = jaccard(sliceA.map(t => t.normalized), sliceB.map(t => t.normalized)) * 100;
        else if (config.algorithm === 'jaccard') sim = jaccard(phraseA.split(''), phraseB.split('')) * 100;
        else if (config.algorithm === 'levenshtein') {
          const dist = levenshteinDistance(normA, normB);
          const max = Math.max(normA.length, normB.length);
          sim = max === 0 ? 0 : (1 - dist / max) * 100;
        } else if (config.algorithm === 'coptic-aware') sim = calculateCopticSimilarity(phraseA, phraseB);

        if (sim >= config.threshold) {
          matches.push({ sourceIndex: i, targetIndex: j, sourcePhrase: phraseA, targetPhrase: phraseB, similarity: sim, sourcePosition: i, targetPosition: j, length: n });
        }
      }
    }
  }

  const alignments: Alignment[] = [];
  tokensA.forEach((tA, i) => {
    tokensB.forEach((tB, j) => {
       const sim = calculateCopticSimilarity(tA.normalized, tB.normalized);
       if (sim >= 40) alignments.push({ sourceIndex: i, targetIndex: j, similarity: sim, sourceText: tA.text, targetText: tB.text });
    });
  });

  const avgSim = matches.length > 0 ? matches.reduce((acc, m) => acc + m.similarity, 0) / matches.length : 0;
  const coveredA = new Set<number>();
  const coveredB = new Set<number>();
  matches.forEach(m => {
    const len = m.length || config.windowSize;
    for (let k = 0; k < len; k++) {
      if (m.sourcePosition + k < tokensA.length) coveredA.add(m.sourcePosition + k);
      if (m.targetPosition + k < tokensB.length) coveredB.add(m.targetPosition + k);
    }
  });

  return {
    tokensA, tokensB, matches, alignments,
    stats: {
      totalAlignments: matches.length,
      meanSimilarity: avgSim,
      coverage: (tokensA.length + tokensB.length) === 0 ? 0 : ((coveredA.size + coveredB.size) / (tokensA.length + tokensB.length)) * 100,
      uniqueNgrams: new Set([...matches.map(m => m.sourcePhrase), ...matches.map(m => m.targetPhrase)]).size
    }
  };
};

