            </div>
            <div ref={containerBRef} className="overflow-y-auto flex-1 p-4 bg-white custom-scrollbar">
              {renderTokens(tokensB, 'B')}
            </div>
          </div>
        </div>
      </div>
      {/* Footer Info */}
      <div className="bg-gray-50 border-t border-gray-200 p-2 min-h-[40px] flex items-center justify-center">
        {selectedMatch ? (
          <div className="flex items-center gap-3 text-xs w-full">
